const COOKIE_NAME = 'tabready_session';
const SESSION_EXPIRY_SECONDS = 60 * 60 * 24 * 400; // 400 days (~13 months) — browser hard cap for persistent login cookies; keeps volunteers signed in past a full year
const MAGIC_LINK_EXPIRY_SECONDS = 60 * 15; // 15 minutes
const RELINK_EXPIRY_SECONDS = 60 * 60; // 1 hour — admin-generated link for an existing user (texted)
const ONBOARD_LINK_EXPIRY_SECONDS = 60 * 60 * 24 * 7; // 7 days — onboarding gallery QR (single-use, scanned in person)
const LOGIN_CODE_EXPIRY_SECONDS = 60 * 15; // 15 minutes — 6-digit type-in login code (stays in one browser context; no cross-app cookie loss)
