// ══ v2.9.249: SELF-SERVICE SIGN-IN EMAIL CHANGE ═══════════════════════════
// users.email IS the login identity (handleAuthRequest resolves on lower(email)),
// so this is deliberately a two-step, verified change:
//   1. /api/account/email-request  -> code is emailed to the NEW address
//   2. /api/account/email-verify   -> only then is users.email updated
// The old address keeps working until the new one is proven, so a typo cannot
// lock anyone out, and an address already used by another account is refused
// (a duplicate would shadow that person's login row).
// On success the address is PINNED (app_settings email_pin:<user_id>) so the
// weekly live PCO directory sync stops overwriting it. The divergence is not
// hidden — it is reported in the sync summary as a pinned conflict.
async function sendEmailChangeCode(env, to, name, code) {
  const spaced = String(code).split('').join(' ');
  const html = `
    <div style="font-family:-apple-system,Segoe UI,Roboto,sans-serif;max-width:480px;padding:8px;color:#402020">
      <h2 style="margin:0 0 6px;font-size:20px">Confirm your new TabReady address</h2>
      <p style="font-size:14px">Hi ${escapeHtml(name || '')}, enter this code in TabReady to start signing in with this address:</p>
      <p style="margin:26px 0;text-align:center">
        <span style="display:inline-block;font-size:32px;font-weight:700;letter-spacing:8px;background:#f1f5f9;padding:16px 22px;border-radius:10px">${escapeHtml(spaced)}</span>
      </p>
      <p style="color:#666;font-size:14px">This code works for 15 minutes. Until you enter it, nothing changes and your old address still signs you in.</p>
      <p style="color:#999;font-size:12px;margin-top:28px">If you did not ask for this, ignore this email — no change will happen.</p>
    </div>`;
  const res = await fetch('https://api.resend.com/emails', {
    method: 'POST',
    headers: { 'Authorization': `Bearer ${env.RESEND_API_KEY}`, 'Content-Type': 'application/json' },
    body: JSON.stringify({ from: RESEND_FROM_ADDRESS, to: to, subject: `TabReady confirmation code: ${code}`, html })
  });
  if (!res.ok) throw new Error('email_send_failed');
}

