async function apiAlertCreate(request, env, ctx) {
  const user = await getUserFromRequest(request, env);
  if (!user) return json({ error: 'not_authenticated' }, 401);
  if (!canBroadcast(user)) return json({ error: 'forbidden' }, 403);

  // v2.9.70: accept multipart (optional attachment) OR JSON (back-compat)
  let category, note, recipients, photoFile = null;
  const ctype = request.headers.get('content-type') || '';
  if (ctype.includes('multipart/form-data')) {
    const form = await request.formData();
    category = (form.get('category') || form.get('code') || '').toString().trim();
    note = (form.get('note') || form.get('description') || '').toString().trim() || null;
    let rec = form.get('recipients');
    try { rec = JSON.parse(rec || '[]'); } catch (e) { rec = []; }
    recipients = Array.isArray(rec) ? rec : [];
    photoFile = form.get('photo');
  } else {
    const body = await request.json().catch(() => ({}));
    category = (body.category || body.code || '').toString().trim();
    note = (body.note || body.description || '').toString().trim() || null;
    recipients = Array.isArray(body.recipients) ? body.recipients : [];
  }
  if (!category) return json({ error: 'category_required' }, 400);

  const id = crypto.randomUUID();
  const baseUrl = new URL(request.url).origin; // v2.9.70: correct host for email link

  let photoKey = null;
  if (photoFile && typeof photoFile === 'object' && photoFile.size > 0) {
    const upload = await uploadPhotoToR2(env, photoFile, 'alert', id);
    if (upload && upload.key) photoKey = upload.key;
  }

  await env.DB.prepare(
    `INSERT INTO alerts (id, reporter_user_id, category, note, recipients, photo_key) VALUES (?, ?, ?, ?, ?, ?)`
  ).bind(id, user.id, category, note, JSON.stringify(recipients), photoKey).run();
  await audit(env, user.id, 'alert_created', { alert_id: id, category });

  // v2.9.51: Web push fan-out (best-effort, non-blocking)
  sendPushToAll(env, ctx, category, note);

  // Email leaders when a notification is posted
  try {
    const poster = await env.DB.prepare(
      'SELECT display_name, email FROM users WHERE id = ? LIMIT 1'
    ).bind(user.id).first();
    const posterName = (poster && poster.display_name) ? poster.display_name : user.id;
    const alertEmailHtml = `
      <div style="font-family:-apple-system,sans-serif;max-width:560px;margin:0 auto;padding:24px;">
        <div style="background:#fff3cd;border-left:4px solid #ca8342;padding:14px 18px;margin-bottom:24px;">
          <h2 style="color:#7a4f1a;margin:0 0 4px;font-size:18px;">TabReady — New Notification Posted</h2>
          <p style="color:#7a4f1a;margin:0;font-size:13px;">A notification was broadcast to the team.</p>
        </div>
        <table style="width:100%;border-collapse:collapse;font-size:14px;color:#1a1a1a;">
          <tr><td style="padding:6px 0;color:#6b7280;width:120px;">Posted by:</td><td style="padding:6px 0;"><strong>${escapeHtml(posterName)}</strong></td></tr>
          <tr><td style="padding:6px 0;color:#6b7280;">Category:</td><td style="padding:6px 0;"><strong>${escapeHtml(category)}</strong></td></tr>
          ${note ? `<tr><td style="padding:6px 0;color:#6b7280;">Note:</td><td style="padding:6px 0;">${escapeHtml(note)}</td></tr>` : ''}
          ${photoKey ? `<tr><td style="padding:6px 0;color:#6b7280;">Attachment:</td><td style="padding:6px 0;"><a href="${baseUrl}/photo/${encodeURIComponent(photoKey)}">View attachment</a></td></tr>` : ''}
        </table>
        <p style="margin-top:24px;color:#6b7280;font-size:12px;">This is an automated notification from TabReady. View the full notification in the Notifications tab.</p>
        <p style="color:#999;font-size:11px;margin-top:16px;">The Tabernacle Church · 4141 DeSoto Rd, Sarasota, FL</p>
      </div>`;
    await fetch('https://api.resend.com/emails', {
      method: 'POST',
      headers: { 'Authorization': `Bearer ${env.RESEND_API_KEY}`, 'Content-Type': 'application/json' },
      body: JSON.stringify({
        from: RESEND_FROM_ADDRESS,
        to: INCIDENT_REPORT_RECIPIENTS,
        subject: `[TabReady] New Notification — ${category}`,
        html: alertEmailHtml
      })
    });
  } catch (alertEmailErr) {
    console.error('Alert email failed:', alertEmailErr);
  }

  return json({ ok: true, id });
}


