// ── v2.9.54: User search for schedule name autocomplete ──────────────────
async function apiUsersSearch(request, env) {
  const user = await getUserFromRequest(request, env);
  if (!user) return json({ error: 'not_authenticated' }, 401);
  const url = new URL(request.url);
  const q = (url.searchParams.get('q') || '').trim().toLowerCase();
  const role = (url.searchParams.get('role') || '').trim();
  if (!q || q.length < 2) return json({ users: [] });

  try {
    let rows;
    if (role) {
      // Search within a specific team
      const res = await env.DB.prepare(
        `SELECT u.id, u.display_name, GROUP_CONCAT(ur2.role_id) as roles
         FROM users u
         JOIN user_roles ur ON u.id = ur.user_id AND ur.role_id = ?
         LEFT JOIN user_roles ur2 ON u.id = ur2.user_id
         WHERE lower(u.display_name) LIKE ? AND u.hidden = 0
         GROUP BY u.id
         ORDER BY u.display_name LIMIT 10`
      ).bind(role, '%' + q + '%').all();
      rows = res.results || [];
    } else {
      // Search all users
      const res = await env.DB.prepare(
        `SELECT u.id, u.display_name, GROUP_CONCAT(ur.role_id) as roles
         FROM users u
         LEFT JOIN user_roles ur ON u.id = ur.user_id
         WHERE lower(u.display_name) LIKE ? AND u.hidden = 0
         GROUP BY u.id
         ORDER BY u.display_name LIMIT 10`
      ).bind('%' + q + '%').all();
      rows = res.results || [];
    }
    return json({ users: rows.map(r => ({ id: r.id, display_name: r.display_name, roles: r.roles || '' })) });
  } catch (err) {
    return json({ users: [] });
  }
}

