// ─── VAPID signing helper (Web Crypto, no npm) ────────────────────────────
// Produces a signed JWT for VAPID. Works inside Cloudflare Workers runtime.
async function vapidJwt(env, audience) {
  const privateKeyB64 = (env.VAPID_PRIVATE_KEY || '').trim();
  if (!privateKeyB64) throw new Error('VAPID_PRIVATE_KEY not set');
  // Import the raw EC private key (base64url → ArrayBuffer)
  const rawKey = Uint8Array.from(atob(privateKeyB64.replace(/-/g, '+').replace(/_/g, '/')), c => c.charCodeAt(0));
  const cryptoKey = await crypto.subtle.importKey(
    'raw', rawKey, { name: 'ECDSA', namedCurve: 'P-256' }, false, ['sign']
  ).catch(async () => {
    // Some runtimes need pkcs8 format — fall back gracefully
    return await crypto.subtle.importKey(
      'pkcs8', rawKey, { name: 'ECDSA', namedCurve: 'P-256' }, false, ['sign']
    );
  });
  const header = { typ: 'JWT', alg: 'ES256' };
  const payload = { aud: audience, exp: Math.floor(Date.now() / 1000) + 43200, sub: 'mailto:spass@thetabsarasota.org' };
  const b64url = (obj) => btoa(JSON.stringify(obj)).replace(/=/g, '').replace(/\+/g, '-').replace(/\//g, '_');
  const sigInput = b64url(header) + '.' + b64url(payload);
  const sig = await crypto.subtle.sign(
    { name: 'ECDSA', hash: 'SHA-256' },
    cryptoKey,
    new TextEncoder().encode(sigInput)
  );
  const sigB64 = btoa(String.fromCharCode(...new Uint8Array(sig))).replace(/=/g, '').replace(/\+/g, '-').replace(/\//g, '_');
  return sigInput + '.' + sigB64;
}

// ─── Web Push payload encryption (RFC 8291, aes128gcm) ────────────────────
function pushB64ToBytes(s) {
  s = s.replace(/-/g, '+').replace(/_/g, '/');
  while (s.length % 4) s += '=';
  const bin = atob(s);
  const a = new Uint8Array(bin.length);
  for (let i = 0; i < bin.length; i++) a[i] = bin.charCodeAt(i);
  return a;
}
function pushConcat() {
  let len = 0;
  for (let i = 0; i < arguments.length; i++) len += arguments[i].length;
  const out = new Uint8Array(len);
  let o = 0;
  for (let i = 0; i < arguments.length; i++) { out.set(arguments[i], o); o += arguments[i].length; }
  return out;
}
async function encryptPushPayload(p256dhB64, authB64, payloadStr) {
  const uaPublic = pushB64ToBytes(p256dhB64);
  const authSecret = pushB64ToBytes(authB64);
  const salt = crypto.getRandomValues(new Uint8Array(16));
  const serverKeys = await crypto.subtle.generateKey({ name: 'ECDH', namedCurve: 'P-256' }, true, ['deriveBits']);
  const asPublic = new Uint8Array(await crypto.subtle.exportKey('raw', serverKeys.publicKey));
  const uaKey = await crypto.subtle.importKey('raw', uaPublic, { name: 'ECDH', namedCurve: 'P-256' }, false, []);
  const ecdhBits = new Uint8Array(await crypto.subtle.deriveBits({ name: 'ECDH', public: uaKey }, serverKeys.privateKey, 256));
  const enc = new TextEncoder();
  const keyInfo = pushConcat(enc.encode('WebPush: info\0'), uaPublic, asPublic);
  const ecdhKey = await crypto.subtle.importKey('raw', ecdhBits, 'HKDF', false, ['deriveBits']);
  const ikm = new Uint8Array(await crypto.subtle.deriveBits({ name: 'HKDF', hash: 'SHA-256', salt: authSecret, info: keyInfo }, ecdhKey, 256));
  const ikmKey = await crypto.subtle.importKey('raw', ikm, 'HKDF', false, ['deriveBits']);
  const cekBits = await crypto.subtle.deriveBits({ name: 'HKDF', hash: 'SHA-256', salt: salt, info: enc.encode('Content-Encoding: aes128gcm\0') }, ikmKey, 128);
  const nonceBits = new Uint8Array(await crypto.subtle.deriveBits({ name: 'HKDF', hash: 'SHA-256', salt: salt, info: enc.encode('Content-Encoding: nonce\0') }, ikmKey, 96));
  const cek = await crypto.subtle.importKey('raw', cekBits, { name: 'AES-GCM' }, false, ['encrypt']);
  const plaintext = pushConcat(enc.encode(payloadStr), new Uint8Array([2]));
  const cipher = new Uint8Array(await crypto.subtle.encrypt({ name: 'AES-GCM', iv: nonceBits, tagLength: 128 }, cek, plaintext));
  const rs = new Uint8Array([0, 0, 0x10, 0x00]);
  const idlen = new Uint8Array([asPublic.length]);
  return pushConcat(salt, rs, idlen, asPublic, cipher);
}
// Send a payload to one user's push subscriptions. Awaitable; caller wraps in waitUntil.
async function sendPushToUser(env, userId, payloadObj) {
  if (!(env.VAPID_PUBLIC_KEY || '').trim() || !(env.VAPID_PRIVATE_KEY || '').trim()) return;
  try {
    const rows = await env.DB.prepare('SELECT id, endpoint, p256dh, auth FROM push_subscriptions WHERE user_id = ? LIMIT 20').bind(userId).all();
    const subs = rows.results || [];
    if (!subs.length) return;
    const payload = JSON.stringify(payloadObj);
    const toDelete = [];
    await Promise.allSettled(subs.map(async (sub) => {
      try {
        const origin = new URL(sub.endpoint).origin;
        const jwt = await vapidJwt(env, origin);
        const authHeader = 'vapid t=' + jwt + ', k=' + env.VAPID_PUBLIC_KEY;
        const res = await fetch(sub.endpoint, {
          method: 'POST',
          headers: { 'Authorization': authHeader, 'Content-Type': 'application/octet-stream', 'TTL': '86400', 'Content-Encoding': 'aes128gcm' },
          body: await encryptPushPayload(sub.p256dh, sub.auth, payload)
        });
        if (res.status === 410 || res.status === 404) toDelete.push(sub.id);
      } catch (e) {}
    }));
    for (const id of toDelete) await env.DB.prepare('DELETE FROM push_subscriptions WHERE id = ?').bind(id).run().catch(() => {});
  } catch (e) {}
}

async function sendPushToAll(env, ctx, category, note) {
  if (!(env.VAPID_PUBLIC_KEY || '').trim() || !(env.VAPID_PRIVATE_KEY || '').trim()) return;
  ctx.waitUntil((async () => {
    try {
      const rows = await env.DB.prepare('SELECT id, endpoint, p256dh, auth FROM push_subscriptions LIMIT 500').all();
      const subs = rows.results || [];
      if (!subs.length) return;
      const payload = JSON.stringify({
        title: 'TabReady: ' + category,
        body: note || category,
        url: '/'
      });
      const toDelete = [];
      await Promise.allSettled(subs.map(async (sub) => {
        try {
          const origin = new URL(sub.endpoint).origin;
          const jwt = await vapidJwt(env, origin);
          const authHeader = 'vapid t=' + jwt + ', k=' + env.VAPID_PUBLIC_KEY;
          const res = await fetch(sub.endpoint, {
            method: 'POST',
            headers: {
              'Authorization': authHeader,
              'Content-Type': 'application/octet-stream',
              'TTL': '86400',
              'Content-Encoding': 'aes128gcm',
            },
            body: await encryptPushPayload(sub.p256dh, sub.auth, payload)
          });
          if (res.status === 410 || res.status === 404) toDelete.push(sub.id);
        } catch (e) {
          console.error('push send error', e.message);
        }
      }));
      for (const id of toDelete) {
        await env.DB.prepare('DELETE FROM push_subscriptions WHERE id = ?').bind(id).run().catch(() => {});
      }
    } catch (err) {
      console.error('sendPushToAll error:', err.message);
    }
  })());
}

async function apiWeather(request, env) {
  const user = await getUserFromRequest(request, env);
  if (!user) return json({ error: 'not_authenticated' }, 401);
  const url = new URL(request.url);
  let lat = parseFloat(url.searchParams.get('lat'));
  let lon = parseFloat(url.searchParams.get('lon'));
  if (isNaN(lat) || isNaN(lon)) { lat = SARASOTA_LAT; lon = SARASOTA_LON; }

  const cacheKey = `${lat.toFixed(2)},${lon.toFixed(2)}`;
  const cached = WEATHER_CACHE.get(cacheKey);
  if (cached && (Date.now() - cached.fetchedAt) < WEATHER_CACHE_TTL_MS) {
    return json({ ...cached.data, cached: true });
  }
  try {
    const apiUrl = `https://api.open-meteo.com/v1/forecast?latitude=${lat}&longitude=${lon}&current=temperature_2m,weather_code&temperature_unit=fahrenheit&timezone=auto`;
    const res = await fetch(apiUrl);
    if (!res.ok) return json({ error: 'weather_fetch_failed' }, 502);
    const data = await res.json();
    const current = data.current || {};
    const result = {
      temp_f: typeof current.temperature_2m === 'number' ? Math.round(current.temperature_2m) : null,
      code: current.weather_code,
      description: weatherCodeToText(current.weather_code),
      icon: weatherCodeToIcon(current.weather_code),
      lat, lon
    };
    WEATHER_CACHE.set(cacheKey, { data: result, fetchedAt: Date.now() });
    return json(result);
  } catch (err) {
    console.error('Weather fetch failed:', err);
    return json({ error: 'weather_error' }, 502);
  }
}

function weatherCodeToText(code) {
  if (code === 0) return 'Clear';
  if (code === 1) return 'Mostly clear';
  if (code === 2) return 'Partly cloudy';
  if (code === 3) return 'Cloudy';
  if (code === 45 || code === 48) return 'Fog';
  if (code >= 51 && code <= 57) return 'Drizzle';
  if (code >= 61 && code <= 67) return 'Rain';
  if (code >= 71 && code <= 77) return 'Snow';
  if (code >= 80 && code <= 82) return 'Showers';
  if (code === 85 || code === 86) return 'Snow showers';
  if (code === 95) return 'Thunderstorm';
  if (code === 96 || code === 99) return 'T-storm + hail';
  return '—';
}

function weatherCodeToIcon(code) {
  if (code === 0 || code === 1) return '☀️';
  if (code === 2) return '⛅';
  if (code === 3) return '☁️';
  if (code === 45 || code === 48) return '🌫️';
  if (code >= 51 && code <= 67) return '🌧️';
  if (code >= 71 && code <= 77 || code === 85 || code === 86) return '❄️';
  if (code >= 80 && code <= 82) return '🌦️';
  if (code >= 95) return '⛈️';
  return '🌡️';
}

// v2.9.276 — GUNS CUT. Deleted detectWebsiteCategories() and forwardToWebsiteAI().
// Both were dead since the v2.9.67 separation (verified: zero call sites), but
// the forwarder still held a live POST URL to the website assistant.
// Ask Tab is LOCAL ONLY. It reads TabReady D1 content, role-filtered, and nothing else.
// Doctrine / beliefs / giving / ministries / events / staff directory are NOT its job —
// the SCOPE rule in the system prompt routes those to tabsarasota.org.
// DO NOT RE-ADD. The two assistants share no data, no DB, and no calls.

async function apiAsk(request, env) {
  const user = await getUserFromRequest(request, env);
  if (!user) return json({ error: 'not_authenticated' }, 401);
  const body = await request.json().catch(() => ({}));
  const question = (body.question || '').toString().trim();
  const clientHistory = Array.isArray(body.history) ? body.history : [];
  if (!question) return json({ error: 'question_required' }, 400);
  if (!env.ANTHROPIC_API_KEY) return json({ error: 'ai_not_configured' }, 500);

  const origin = new URL(request.url).origin; // v2.9.169: in-app deep links in Ask answers

  // v2.9.67: SEPARATED — TabReady's Ask is fully local. It no longer forwards
  // to tab-website-ai and no longer reads the website content DB. It answers
  // only from TabReady's own role-scoped operational content.
  // 1. Pull TabReady operational content (role-filtered)
  const all = await env.DB.prepare(
    `SELECT id, title, body, tier, role_tags, event_tag, language, source
     FROM content WHERE deleted_at IS NULL ORDER BY is_emergency DESC, updated_at DESC`
  ).all();
  const visible = (all.results || []).filter(row => userCanSeeContent(user, row));

  const ASK_STOPWORDS = new Set(['a','an','the','and','or','but','if','of','to','in','on','at','for','with','about','from','into','inside','is','are','was','were','be','been','am','do','does','did','have','has','had','can','could','would','should','will','i','you','we','they','it','me','my','your','our','this','that','these','those','what','when','where','who','whom','why','how','which','any','some','there','here','please','tell','give','show','find','get','need','want','make','made','take','use','go','url','link','tab','tabready','church','know','like','help']);
  const askTokens = (text) => {
    let t = String(text || '').toLowerCase();
    try { t = t.normalize('NFD').replace(/[\u0300-\u036f]/g, ''); } catch (e) {}
    const out = []; const seen = new Set();
    for (const w of t.split(/[^a-z0-9]+/)) {
      if (w.length < 3 || ASK_STOPWORDS.has(w) || seen.has(w)) continue;
      seen.add(w); out.push(w);
    }
    return out;
  };
  const renderRow = (c) => {
    let tags = [];
    try { tags = JSON.parse(c.role_tags || '[]'); } catch {}
    const meta = [
      `Title: ${c.title}`,
      `Roles: ${tags.join(', ') || 'none'}`,
      c.event_tag ? `Event: ${c.event_tag}` : null,
      c.source ? `Source: ${c.source}` : null,
      `Lang: ${c.language || 'en'}`
    ].filter(Boolean).join(' | ');
    return `---\n${meta}\n\n${c.body}`;
  };
  const askHay = (r) => (String(r.title || '') + ' ' + String(r.body || '')).toLowerCase();
  const askTerms = askTokens(question);
  const askN = visible.length || 1;
  const askWeights = askTerms.map(t => {
    let df = 0;
    for (const r of visible) { if (askHay(r).includes(t)) df++; }
    return { t, w: df === 0 ? 0 : Math.log(askN / df) };
  }).filter(x => x.w > 0);
  const askScore = (row) => {
    const title = String(row.title || '').toLowerCase();
    const body = String(row.body || '').toLowerCase();
    const tagStr = (String(row.role_tags || '') + ' ' + String(row.event_tag || '')).toLowerCase();
    let s = 0;
    for (const pair of askWeights) {
      let hit = 0;
      if (title.includes(pair.t)) hit += 5;
      if (tagStr.includes(pair.t)) hit += 2;
      if (body.includes(pair.t)) hit += 1;
      s += hit * pair.w;
    }
    return s;
  };
  const askRanked = visible.map(c => ({ c, s: askScore(c) })).filter(x => x.s > 0).sort((a, b) => b.s - a.s);
  const askTop = askRanked.length ? askRanked[0].s : 0;
  const askSecond = askRanked.length > 1 ? askRanked[1].s : 0;
  const askConfident = askTop >= 5 && askTop >= 2 * askSecond;
  const askHits = askConfident ? askRanked.filter(x => x.s >= askTop / 3).slice(0, 8).map(x => x.c) : [];
  const askHitIds = new Set(askHits.map(c => c.id));
  const askRest = visible.filter(c => !askHitIds.has(c.id));
  const tabreadyBlock = visible.length === 0
    ? '(No operational content visible to this user.)'
    : (askHits.length === 0
        ? visible.map(renderRow).join('\n\n')
        : `>>> CLOSEST MATCHES for [${askTerms.join(' ')}] — check these first. If the answer is not here, keep reading below.\n\n`
          + askHits.map(renderRow).join('\n\n')
          + `\n\n>>> REST OF THE LIBRARY — the answer may still be here.\n\n`
          + askRest.map(renderRow).join('\n\n'));

  // 2. Build the system prompt (TabReady operational content only)
  const promptLines = [
    'You are Tab, the operational assistant for The Tabernacle Church in Sarasota, Florida.',
    'You help volunteers, staff, and members with TabReady operational matters:',
    '  - Safety codes, emergency procedures, evacuation, schedules, role checklists, classroom and equipment locations, and the contacts contained in the content below.',
    '',
    'SCOPE:',
    '- Answer only from the TABREADY CONTENT below. This is internal operational church information.',
    '- For doctrine, beliefs, salvation, membership, giving, ministries, events, or the full staff directory: you do not have that information here. Point the person to The Tabernacle website (tabsarasota.org) or the church office. Do not guess.',
    '',
    'OUTPUT FORMAT — STRICT:',
    '- Plain prose. NO markdown. NO bold (no **). NO underscores. NO headers (no #). NO bullet stars.',
    '- DO NOT prefix the answer with "Q:" or "A:" or "Answer:" or "Question:". Just answer.',
    '- Lead with the answer. Short, direct, scannable on a phone.',
    '- Phone numbers, addresses, and URLs from the content may be included verbatim. Do not invent any.',
    '',
    'VOICE RULES:',
    '- Pastoral-practical. Warm, clear, restrained. No hype. No performative emotion. No preachiness.',
    '- Be direct, lead with the answer, keep it short.',
    '- Do not invent. If the answer is not in the content below, say so plainly and suggest contacting a team leader, pastor, or the church office.',
    '- NEVER invent a person\'s title, role, or position. If the content does not state someone\'s title explicitly, refer to them by name only or by what the content says they "serve in" / "are part of". Do not summarize a description of someone\'s responsibilities into a title.',
    '- If someone asks "who is the pastor of X" and no exact match exists in the content, say so and suggest contacting the church office. Do not guess.',
    '- For questions about the full pastoral staff or staff list, direct the user to The Tabernacle website at tabsarasota.org, which has the complete and current staff listing.',
    '- If the user asks in Spanish, answer in Spanish. Otherwise, English.',
    '- Software does not dial 911. For real emergencies, direct the user to call 911 themselves.',
    '',
    'IN-APP LINKS (inside TabReady — give the exact link when someone asks how or where to do one of these):',
    '- File an incident report: ' + origin + '/capture/incident',
    '- Capture menu (incident report + report a person of concern): ' + origin + '/capture',
    'When a user asks how to file, where to file, or for the link to an incident report (or the capture menu), give the full link above and tell them to tap it. Put the link on its own line as a plain full URL so it is tappable. Do NOT say you have no URL — these links are inside TabReady.',
    '',
    '═══════════════════════════════════════════',
    'TABREADY CONTENT (operational — role-scoped to this user):',
    '═══════════════════════════════════════════',
    tabreadyBlock
  ];

  const systemPrompt = promptLines.join('\n');

  let answer;
  try {
    const aiRes = await fetch('https://api.anthropic.com/v1/messages', {
      method: 'POST',
      headers: {
        'Content-Type': 'application/json',
        'x-api-key': env.ANTHROPIC_API_KEY,
        'anthropic-version': '2023-06-01'
      },
      body: JSON.stringify({
        model: 'claude-sonnet-5',
        max_tokens: 2000,
        system: systemPrompt,
        messages: [...clientHistory.slice(-6).filter(function(m){return m && (m.role === 'user' || m.role === 'assistant') && m.content;}).map(function(m){return { role: m.role, content: String(m.content) };}), { role: 'user', content: question }]
      })
    });
    if (!aiRes.ok) {
      const errText = await aiRes.text();
      console.error('Anthropic API error:', aiRes.status, errText);
      return json({ error: 'ai_request_failed', status: aiRes.status }, 502);
    }
    const data = await aiRes.json();
    answer = (data.content || []).filter(b => b.type === 'text').map(b => b.text).join('\n').trim() || '(No answer returned.)';
    // v2.9.18: belt-and-suspenders sanitization in case the model
    // ignores the no-Q/A and no-markdown instructions in the system prompt.
    answer = answer
      .replace(/^\s*(Q|Question):\s*[^\n]*\n+/i, '')
      .replace(/^\s*(A|Answer):\s*/i, '')
      .replace(/\*\*/g, '')
      .replace(/__/g, '');
  } catch (err) {
    console.error('Ask Tab fetch failed:', err);
    return json({ error: 'ai_request_failed' }, 502);
  }

  await env.DB.prepare(
    'INSERT INTO ask_log (user_id, question, answer) VALUES (?, ?, ?)'
  ).bind(user.id, question, answer).run();
  await audit(env, user.id, 'ask_question', {
    question_length: question.length,
    tabready_count: visible.length,
    route: 'local'
  });
  return json({ answer });
}

async function apiPcoEvents(request, env) {
  const user = await getUserFromRequest(request, env);
  if (!user) return json({ error: 'not_authenticated' }, 401);
  if (!env.PCO_APP_ID || !env.PCO_SECRET) return json({ events: [], note: 'pco_not_configured' });

  try {
    const creds = btoa(env.PCO_APP_ID + ':' + env.PCO_SECRET);
    const res = await fetch(
      'https://api.planningcenteronline.com/calendar/v2/event_instances?filter=future&per_page=30&include=event',
      { headers: { 'Authorization': 'Basic ' + creds } }
    );
    if (!res.ok) return json({ events: [], note: 'pco_fetch_failed' });
    const data = await res.json();
    const events = (data.data || []).map(ei => {
      const eventId = ei.relationships?.event?.data?.id;
      const event = (data.included || []).find(i => i.type === 'Event' && i.id === eventId);
      const name = event?.attributes?.name || 'Event';
      const start = ei.attributes?.starts_at;
      if (!start) return null;
      return { name, starts_at: start };
    }).filter(Boolean);
    return json({ events });
  } catch (e) {
    return json({ events: [], note: 'pco_error' });
  }
}

// v2.9.116: PCO People quick-lookup for staff/elders. Live search against
// Planning Center People; nothing stored. Reuses PCO_APP_ID/PCO_SECRET (same
// Basic-auth pattern as apiPcoEvents) and degrades gracefully when unset.
async function apiPcoPeople(request, env) {
  const user = await getUserFromRequest(request, env);
  if (!user) return json({ error: 'not_authenticated' }, 401);
  const allowed = user.is_global_admin || (Array.isArray(user.roles) && (user.roles.includes('staff') || user.roles.includes('elders')));
  if (!allowed) return json({ error: 'forbidden' }, 403);

  const url = new URL(request.url);
  const q = (url.searchParams.get('q') || '').trim();
  if (q.length < 2) return json({ people: [] });

  const normEmail = (e) => (e ? String(e).trim().toLowerCase() : '');
  const normPhone = (p) => (p ? String(p).replace(/[^0-9]/g, '') : '');

  // People Router. Merge across sources ONLY on a strong identifier
  // (exact email or exact phone) - never on name alone.
  const merged = [];
  const byEmail = {};
  const byPhone = {};
  const notes = [];
  function add(person) {
    const em = normEmail(person.email);
    const ph = normPhone(person.phone);
    let hit = null;
    if (em && byEmail[em]) hit = byEmail[em];
    else if (ph && byPhone[ph]) hit = byPhone[ph];
    if (hit) {
      if (!hit.email && person.email) hit.email = person.email;
      if (!hit.phone && person.phone) hit.phone = person.phone;
      if (!hit.org && person.org) hit.org = person.org;
      for (const s of person.sources) if (hit.sources.indexOf(s) === -1) hit.sources.push(s);
      const he = normEmail(hit.email), hp = normPhone(hit.phone);
      if (he) byEmail[he] = hit;
      if (hp) byPhone[hp] = hit;
      return;
    }
    const row = {
      name: person.name || 'Unknown',
      email: person.email || null,
      phone: person.phone || null,
      org: person.org || null,
      sources: person.sources.slice()
    };
    merged.push(row);
    if (em) byEmail[em] = row;
    if (ph) byPhone[ph] = row;
  }

  // 1) Planning Center - primary authority. A failure here never blocks the rest.
  if (env.PCO_APP_ID && env.PCO_SECRET) {
    try {
      const creds = btoa(env.PCO_APP_ID + ':' + env.PCO_SECRET);
      const api = 'https://api.planningcenteronline.com/people/v2/people'
        + '?where[search_name_or_email]=' + encodeURIComponent(q)
        + '&include=emails,phone_numbers&per_page=25';
      const res = await fetch(api, { headers: { 'Authorization': 'Basic ' + creds } });
      if (res.ok) {
        const data = await res.json();
        const inc = data.included || [];
        const emailById = {};
        const phoneById = {};
        for (const it of inc) {
          if (it.type === 'Email') emailById[it.id] = it.attributes || {};
          else if (it.type === 'PhoneNumber') phoneById[it.id] = it.attributes || {};
        }
        const pick = (rel, map, field) => {
          const list = (rel && rel.data) || [];
          let primary = null, first = null;
          for (const ref of list) {
            const a = map[ref.id];
            if (!a) continue;
            if (first === null) first = a[field];
            if (a.primary) { primary = a[field]; break; }
          }
          return primary || first || null;
        };
        for (const p of (data.data || [])) {
          const a = p.attributes || {};
          const rels = p.relationships || {};
          const name = a.name || [a.first_name, a.last_name].filter(Boolean).join(' ') || 'Unknown';
          add({
            name,
            email: pick(rels.emails, emailById, 'address'),
            phone: pick(rels.phone_numbers, phoneById, 'number'),
            sources: ['PCO']
          });
        }
      } else {
        notes.push('pco_fetch_failed');
      }
    } catch (e) {
      notes.push('pco_error');
    }
  } else {
    notes.push('pco_not_configured');
  }

  // 2) TabReady people registry - staff / ministry / internal.
  try {
    const like = '%' + q + '%';
    const rs = await env.DB.prepare(
      'SELECT display_name, email_primary, email_alt, phone FROM people_registry '
      + 'WHERE active = 1 AND (display_name LIKE ? OR email_primary LIKE ? OR email_alt LIKE ? OR phone LIKE ?) '
      + 'ORDER BY display_name LIMIT 25'
    ).bind(like, like, like, like).all();
    for (const r of (rs.results || [])) {
      add({
        name: r.display_name,
        email: r.email_primary || r.email_alt || null,
        phone: r.phone || null,
        sources: ['TabReady']
      });
    }
  } catch (e) {
    notes.push('registry_error');
  }

  // 3) Saved / imported contacts - vendors, personal, optional imports.
  try {
    const like = '%' + q + '%';
    const rs = await env.DB.prepare(
      'SELECT display_name, organization, email, phone FROM external_contacts '
      + 'WHERE active = 1 AND (display_name LIKE ? OR organization LIKE ? OR email LIKE ? OR phone LIKE ?) '
      + 'ORDER BY display_name LIMIT 25'
    ).bind(like, like, like, like).all();
    for (const r of (rs.results || [])) {
      add({
        name: r.display_name,
        email: r.email || null,
        phone: r.phone || null,
        org: r.organization || null,
        sources: ['Contacts']
      });
    }
  } catch (e) {
    notes.push('contacts_error');
  }

  return json({ people: merged, notes });
}

// v3.0: Incident-report person lookup. Minimal + name-only. Available to ANY
// authenticated incident filer (NOT gated to staff/elders like /api/pco-people).
// Returns ONLY a stable, source-namespaced person_id and a display name -
// never email, phone, address, family, next-of-kin, or any private field.
// Namespaces: 'pco:<id>' (Planning Center) and 'reg:<id>' (people_registry) so
// approved staff/admin can later resolve the person in gated tools.
async function apiIncidentPeople(request, env) {
  const user = await getUserFromRequest(request, env);
  if (!user) return json({ error: 'not_authenticated' }, 401);

  const url = new URL(request.url);
  const q = (url.searchParams.get('q') || '').trim();
  if (q.length < 2) return json({ people: [] });

  const out = [];
  const seen = {};
  function push(person_id, display_name) {
    const key = String(display_name || '').trim().toLowerCase();
    if (!display_name || seen[key]) return;
    seen[key] = true;
    out.push({ person_id, display_name });
  }

  // 1) Planning Center - whole-congregation authority. Name + id ONLY.
  if (env.PCO_APP_ID && env.PCO_SECRET) {
    try {
      const creds = btoa(env.PCO_APP_ID + ':' + env.PCO_SECRET);
      const api = 'https://api.planningcenteronline.com/people/v2/people'
        + '?where[search_name_or_email]=' + encodeURIComponent(q)
        + '&per_page=15';
      const res = await fetch(api, { headers: { 'Authorization': 'Basic ' + creds } });
      if (res.ok) {
        const data = await res.json();
        for (const pp of (data.data || [])) {
          const a = pp.attributes || {};
          const name = a.name || [a.first_name, a.last_name].filter(Boolean).join(' ');
          if (name && pp.id) push('pco:' + pp.id, name);
        }
      }
    } catch (e) { /* PCO failure never blocks the registry lookup */ }
  }

  // 2) TabReady people registry - staff / ministry. Name + id ONLY.
  try {
    const like = '%' + q + '%';
    const rs = await env.DB.prepare(
      'SELECT person_id, display_name FROM people_registry '
      + 'WHERE active = 1 AND display_name LIKE ? ORDER BY display_name LIMIT 15'
    ).bind(like).all();
    for (const r of (rs.results || [])) push('reg:' + r.person_id, r.display_name);
  } catch (e) { /* registry optional */ }

  return json({ people: out.slice(0, 20) });
}

// ══════════════════════════════════════════════════════════════════════════
// v2.9.258 EXTERNAL INCIDENT REPORT SHARING (Builder packet sections 9-16).
// Neutral by design: "person involved" and "recipient". This is NOT a
// child-only or parent-only system - the recipient may be the adult involved,
// a spouse, a parent or guardian, a caregiver, or a manually entered contact.
// Nothing is ever preselected. No acknowledgment is required of the recipient.
// The recipient does not need a TabReady login: they open a tokenized page
// that renders ONLY their report, with system/audit data excluded.
// ══════════════════════════════════════════════════════════════════════════

// v2.9.260: incident contact is DATA, not code. Staff transitions (office
// administrator changes, address changes) are an app_settings edit, never a
// deploy. Fallback is the verified-active address, never a phantom one.
async function incidentContact(env) {
  const d = { name: 'Ronel Uys / Church Office', email: 'ruys@thetabsarasota.org' };
  try {
    const r = await env.DB.prepare("SELECT key, value FROM app_settings WHERE key IN ('incident_contact_name','incident_contact_email')").all();
    for (const x of (r.results || [])) {
      if (x.key === 'incident_contact_name' && x.value) d.name = String(x.value);
      if (x.key === 'incident_contact_email' && x.value) d.email = String(x.value);
    }
  } catch (e) { /* fall back to defaults */ }
  return d;
}

function incidentShareManageGate(user) {
  if (!user) return false;
  if (user.is_global_admin) return true;
  return Array.isArray(user.roles) && (user.roles.includes('safety') || user.roles.includes('staff'));
}

// v2.9.261: Filing an incident report is open to every logged-in user, so sending the
// recipient copies that are PART of filing is open too. Authorization is per-report,
// not per-role - see canActOnReportShare. This gate only asserts "signed in".
function incidentShareGate(user) {
  return !!user;
}

// v2.9.261: A volunteer may act only on a report they personally filed.
// safety / staff / global admin may act on any report. This is what keeps an
// open send path from becoming a skeleton key to every report in the system.
async function canActOnReportShare(env, user, rid) {
  if (!user) return false;
  if (incidentShareManageGate(user)) return true;
  try {
    const r = await env.DB.prepare('SELECT reporter_user_id FROM incident_reports WHERE id = ? AND deleted_at IS NULL LIMIT 1').bind(rid).first();
    return !!(r && String(r.reporter_user_id) === String(user.id));
  } catch (e) { return false; }
}

function newShareToken() {
  const abc = 'ABCDEFGHJKLMNPQRSTUVWXYZabcdefghijkmnopqrstuvwxyz23456789';
  const a = new Uint8Array(40);
  crypto.getRandomValues(a);
  let s = '';
  for (let i = 0; i < a.length; i++) s += abc.charAt(a[i] % abc.length);
  return s;
}

async function shareTokenHash(tok) {
  const buf = await crypto.subtle.digest('SHA-256', new TextEncoder().encode(String(tok)));
  return Array.from(new Uint8Array(buf)).map(function (b) { return b.toString(16).padStart(2, '0'); }).join('');
}

function shareAgeFrom(birthdate) {
  if (!birthdate) return null;
  const b = new Date(birthdate + 'T00:00:00Z');
  if (isNaN(b.getTime())) return null;
  const now = new Date();
  let age = now.getUTCFullYear() - b.getUTCFullYear();
  const m = now.getUTCMonth() - b.getUTCMonth();
  if (m < 0 || (m === 0 && now.getUTCDate() < b.getUTCDate())) age--;
  if (age < 0 || age > 120) return null;
  return age;
}

// Suggest possible recipients. SUGGEST ONLY - every candidate returns checked:false.
// PCO fields (household membership, primary_contact, child, grade) organize and
// label the list. They never make the sending decision. Known-bad PCO data is
// surfaced as a visible warning rather than silently trusted.
async function apiIncidentRecipients(request, env) {
  const user = await getUserFromRequest(request, env);
  if (!user) return json({ error: 'not_authenticated' }, 401);
  if (!incidentShareGate(user)) return json({ error: 'forbidden' }, 403);
  const url = new URL(request.url);
  const rid = (url.searchParams.get('report_id') || '').trim();
  if (!rid) return json({ error: 'report_id_required' }, 400);
  const rep = await env.DB.prepare(
    'SELECT id, tagged_person_id, tagged_person_display_name, guest_person_name FROM incident_reports WHERE id = ? AND deleted_at IS NULL LIMIT 1'
  ).bind(rid).first();
  if (!rep) return json({ error: 'not_found' }, 404);
  // v2.9.261: per-report authorization. A volunteer sees recipients only for their own report.
  if (!(await canActOnReportShare(env, user, rid))) return json({ error: 'forbidden' }, 403);

  const out = {
    report_id: rid,
    person_display: rep.tagged_person_display_name || rep.guest_person_name || null,
    person_source: rep.tagged_person_id ? 'linked' : 'guest',
    households: [],
    other: [],
    warnings: [],
    note: null
  };
  const pid = (rep.tagged_person_id || '').toString();

  // TabReady's own registry contact for the person involved.
  if (pid.indexOf('reg:') === 0) {
    try {
      const r = await env.DB.prepare('SELECT display_name, email_primary, email_alt FROM people_registry WHERE person_id = ? LIMIT 1').bind(pid.slice(4)).first();
      const em = r && (r.email_primary || r.email_alt);
      if (em) out.other.push({ name: r.display_name || out.person_display || 'Person involved', email: em, label: 'Person involved - TabReady contact', source: 'registry', checked: false });
    } catch (e) { /* optional */ }
  }

  if (pid.indexOf('pco:') === 0 && env.PCO_APP_ID && env.PCO_SECRET) {
    const ppid = pid.slice(4);
    const H = { 'Authorization': 'Basic ' + btoa(env.PCO_APP_ID + ':' + env.PCO_SECRET) };
    const PB = 'https://api.planningcenteronline.com/people/v2/';
    const getj = async function (u) {
      try { const r = await fetch(u, { headers: H }); if (!r.ok) return null; return await r.json(); } catch (e) { return null; }
    };
    const hh = await getj(PB + 'people/' + encodeURIComponent(ppid) + '/households');
    const hlist = (hh && hh.data) || [];
    if (!hlist.length) out.note = 'No PCO household was found for this person. Enter the recipient manually.';
    for (const h of hlist) {
      const hid = h.id;
      const ha = h.attributes || {};
      const box = {
        household_id: hid,
        household_name: ha.name || 'Household',
        primary_contact_name: ha.primary_contact_name || null,
        members: []
      };
      const hp = await getj(PB + 'households/' + encodeURIComponent(hid) + '/people?include=emails&per_page=30');
      const emailsById = {};
      for (const inc of ((hp && hp.included) || [])) {
        if (inc.type === 'Email') {
          const owner = ((inc.relationships || {}).person || {}).data;
          const a = inc.attributes || {};
          if (owner && owner.id && (!emailsById[owner.id] || a.primary)) emailsById[owner.id] = a.address;
        }
      }
      for (const p of ((hp && hp.data) || [])) {
        const a = p.attributes || {};
        const nm = a.name || [a.first_name, a.last_name].filter(Boolean).join(' ');
        const age = shareAgeFrom(a.birthdate);
        const isPrimary = !!(ha.primary_contact_id && String(ha.primary_contact_id) === String(p.id));
        const labels = [];
        if (isPrimary) labels.push('Primary contact in PCO');
        if (a.child === true) labels.push('Listed as a child in PCO');
        if (a.grade !== null && a.grade !== undefined && a.grade !== '') labels.push('Grade ' + a.grade);
        if (age !== null) labels.push(age + ' years old');
        if (String(p.id) === String(ppid)) labels.push('Person involved');
        const m = {
          pco_id: p.id,
          name: nm || 'Unnamed',
          email: emailsById[p.id] || null,
          is_primary_contact: isPrimary,
          is_child_flag: a.child === true,
          age: age,
          labels: labels,
          is_person_involved: String(p.id) === String(ppid),
          source: 'pco',
          checked: false
        };
        // Sanity signals only - these never approve or exclude anyone.
        if (isPrimary && age !== null && age < 18) out.warnings.push(nm + ' is PCO\u2019s primary contact but is listed as ' + age + ' years old. Check before sending.');
        if (isPrimary && a.child === true) out.warnings.push(nm + ' is PCO\u2019s primary contact but is also flagged as a child in PCO. Check before sending.');
        if (!m.email) m.labels.push('No email in PCO');
        box.members.push(m);
      }
      // Order is a hint, not a decision: likely adults first, everyone unchecked.
      box.members.sort(function (x, y) {
        const rank = function (z) { return (z.is_child_flag ? 2 : 0) + (z.is_primary_contact ? -1 : 0); };
        return rank(x) - rank(y);
      });
      out.households.push(box);
    }
    if (hlist.length > 1) out.warnings.push('This person belongs to ' + hlist.length + ' households. TabReady does not guess which one is correct - choose the right recipient.');
  } else if (pid.indexOf('pco:') !== 0 && !out.other.length) {
    out.note = 'No linked person record for this report. Enter the recipient manually.';
  }
  return json(out);
}

// The external-facing report. ONE renderer is used for BOTH the staff preview
// and the recipient's page, so the preview cannot drift from what is actually
// sent. Excluded on purpose (packet section 12): database/PCO identifiers,
// tokens, audit rows, delivery metadata, staff permissions, and the private
// contact details of staff, responders, or anyone else named in the report.
function externalReportHtml(rep, opts) {
  opts = opts || {};
  const E = escapeHtml;
  const cName = (opts.contact && opts.contact.name) ? opts.contact.name : '';
  const cEmail = (opts.contact && opts.contact.email) ? opts.contact.email : 'ruys@thetabsarasota.org';
  const rowsOut = [];
  const row = function (label, val) {
    if (!val) return;
    rowsOut.push('<tr><td style="padding:11px 0;color:#6d3d31;font-size:14px;width:150px;vertical-align:top">' + E(label) + '</td><td style="padding:11px 0;font-size:16px;color:#402020">' + E(val) + '</td></tr>');
  };
  const who = rep.tagged_person_display_name || rep.guest_person_name || 'Not recorded';
  let when = rep.occurred_at || rep.created_at || '';
  try { if (when) when = new Date(when.indexOf('T') > -1 ? when : when.replace(' ', 'T') + 'Z').toLocaleString('en-US', { timeZone: 'America/New_York', dateStyle: 'full', timeStyle: 'short' }); } catch (e) {}
  row('Person involved', who);
  row('Date and time', when);
  row('Location', rep.location || 'Not recorded');

  let actions = '';
  try { const a = JSON.parse(rep.action_taken || '[]'); if (Array.isArray(a) && a.length) actions = a.join(', '); } catch (e) { actions = rep.action_taken || ''; }

  // Follow-up is stored as an internal Yes/No. The internal field is preserved;
  // only the wording shown to the recipient is translated (packet section 15).
  const fu = String(rep.follow_up_needed || '').trim().toLowerCase();
  let fuText = 'Please contact the church office with any questions about this incident.';
  if (fu === 'yes') fuText = 'A church staff member will contact you regarding this incident.';
  else if (fu === 'no') fuText = 'No additional church follow-up is currently scheduled. Please contact us with any questions.';

  const body = (opts.external_note !== null && opts.external_note !== undefined && String(opts.external_note).trim())
    ? String(opts.external_note)
    : (rep.summary || '');

  return '<div style="font-family:-apple-system,system-ui,sans-serif;max-width:620px;margin:0 auto;padding:22px;color:#402020;background:#faf8f5">'
    + '<div style="background:#fff;border:1px solid #e7ddd3;border-radius:14px;padding:20px">'
    + '<div style="font-size:13px;font-weight:800;letter-spacing:.06em;color:#6d3d31">THE TABERNACLE CHURCH</div>'
    + '<h1 style="font-size:24px;margin:6px 0 4px">Incident Report</h1>'
    + '<p style="font-size:15px;color:#6d3d31;margin:0 0 16px">This report is being shared with you by the church office.</p>'
    + '<table style="width:100%;border-collapse:collapse;border-top:1px solid #efe7dd">' + rowsOut.join('') + '</table>'
    + '<h2 style="font-size:18px;margin:22px 0 6px">What happened</h2>'
    + '<div style="font-size:16px;line-height:1.6;white-space:pre-wrap">' + E(body) + '</div>'
    + (opts.photo_url ? '<h2 style="font-size:18px;margin:22px 0 6px">Photo</h2><div style="margin-top:6px"><img src="' + E(opts.photo_url) + '" alt="Photo attached to this incident report" style="max-width:100%;border-radius:10px;border:1px solid #efe7dd"></div>' : '')
    + (actions ? '<h2 style="font-size:18px;margin:22px 0 6px">Immediate action taken</h2><div style="font-size:16px;line-height:1.6">' + E(actions) + '</div>' : '')
    + (rep.action_taken_notes ? '<div style="font-size:16px;line-height:1.6;white-space:pre-wrap;margin-top:6px">' + E(rep.action_taken_notes) + '</div>' : '')
    + '<h2 style="font-size:18px;margin:22px 0 6px">Follow-up</h2>'
    + '<div style="font-size:16px;line-height:1.6">' + E(fuText) + '</div>'
    + '<div style="margin-top:24px;padding-top:16px;border-top:1px solid #efe7dd;font-size:15px;line-height:1.7;color:#6d3d31">'
    + '<b style="color:#402020">Contact the church</b><br>The Tabernacle Church<br>4141 DeSoto Road, Sarasota, FL 34235<br>'
    + (cName ? E(cName) + '<br>' : '')
    + '<a href="mailto:' + E(cEmail) + '" style="color:#6d3d31">' + E(cEmail) + '</a>'
    + '</div>'
    + '<p style="font-size:13px;color:#8a7a6a;margin-top:18px">You are not required to reply to or approve this report. It is provided so you know what was recorded.</p>'
    + '</div></div>';
}

async function loadReportForShare(env, rid) {
  return await env.DB.prepare(
    'SELECT id, location, summary, created_at, occurred_at, tagged_person_display_name, guest_person_name, action_taken, action_taken_notes, follow_up_needed, photo_key FROM incident_reports WHERE id = ? AND deleted_at IS NULL LIMIT 1'
  ).bind(rid).first();
}

// Staff preview: byte-for-byte the same renderer the recipient gets.
async function apiIncidentSharePreview(request, env) {
  const user = await getUserFromRequest(request, env);
  if (!user) return json({ error: 'not_authenticated' }, 401);
  if (!incidentShareGate(user)) return json({ error: 'forbidden' }, 403);
  const body = await request.json().catch(function () { return {}; });
  const rid = (body.report_id || '').toString().trim();
  if (!rid) return json({ error: 'report_id_required' }, 400);
  // v2.9.261: per-report authorization.
  if (!(await canActOnReportShare(env, user, rid))) return json({ error: 'forbidden' }, 403);
  const rep = await loadReportForShare(env, rid);
  if (!rep) return json({ error: 'not_found' }, 404);
  const note = (body.external_note === null || body.external_note === undefined) ? null : String(body.external_note);
  const contact = await incidentContact(env);
  // Staff preview: same renderer, same content. Only the image URL differs (no share
  // token exists yet), so staff see the photo through their own authenticated route.
  return json({ ok: true, html: externalReportHtml(rep, { external_note: note, contact: contact, photo_url: rep.photo_key ? ('/photo/' + rep.photo_key) : null }), contact: contact });
}

async function apiIncidentShareSend(request, env) {
  const user = await getUserFromRequest(request, env);
  if (!user) return json({ error: 'not_authenticated' }, 401);
  if (!incidentShareGate(user)) return json({ error: 'forbidden' }, 403);
  const body = await request.json().catch(function () { return {}; });
  const rid = (body.report_id || '').toString().trim();
  if (!rid) return json({ error: 'report_id_required' }, 400);
  // v2.9.261: per-report authorization. Without this, an open send path would let any
  // volunteer email themselves any report in the system. This is the load-bearing line.
  if (!(await canActOnReportShare(env, user, rid))) return json({ error: 'forbidden' }, 403);
  const rep = await loadReportForShare(env, rid);
  if (!rep) return json({ error: 'not_found' }, 404);
  const note = (body.external_note === null || body.external_note === undefined) ? null : String(body.external_note);

  // Deduplicate identical recipients before sending (packet section 10).
  const seen = {};
  const list = [];
  for (const r of (Array.isArray(body.recipients) ? body.recipients : [])) {
    const em = ((r && r.email) || '').toString().trim().toLowerCase();
    const nm = ((r && r.name) || '').toString().trim();
    if (!em || em.indexOf('@') < 1) continue;
    if (seen[em]) continue;
    seen[em] = 1;
    list.push({ email: em, name: nm || em, source: ((r && r.source) || 'manual').toString() });
  }
  if (!list.length) return json({ ok: false, error: 'no_recipient_selected' }, 400);

  const origin = new URL(request.url).origin;
  const contact = await incidentContact(env);
  const html = externalReportHtml(rep, { external_note: note, contact: contact, photo_url: rep.photo_key ? ('/photo/' + rep.photo_key) : null });
  const results = [];
  for (const r of list) {
    const id = crypto.randomUUID();
    const tok = newShareToken();
    const th = await shareTokenHash(tok);
    const exp = new Date(Date.now() + 45 * 24 * 3600 * 1000).toISOString().slice(0, 19).replace('T', ' ');
    await env.DB.prepare(
      'INSERT INTO incident_shares (id, report_id, recipient_name, recipient_email, recipient_source, token_hash, external_note, created_by, expires_at) VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?)'
    ).bind(id, rid, r.name, r.email, r.source, th, note, user.id, exp).run();
    let sent = false, err = null;
    try {
      await sendIncidentShareEmail(env, r, rep, origin + '/r/' + tok, contact);
      sent = true;
    } catch (e) { err = (e && e.message) ? String(e.message).slice(0, 200) : 'send_failed'; }
    await env.DB.prepare('UPDATE incident_shares SET sent_at = ?, send_error = ? WHERE id = ?')
      .bind(sent ? new Date().toISOString().slice(0, 19).replace('T', ' ') : null, err, id).run();
    await auditV2(env, user.id, 'incident_share_sent', 'incident_report', rid, {
      share_id: id, recipient_email: r.email, recipient_source: r.source, sent: sent, error: err, note_edited: note !== null
    });
    results.push({ email: r.email, name: r.name, sent: sent, error: err });
  }
  const okCount = results.filter(function (x) { return x.sent; }).length;
  return json({ ok: okCount > 0, sent: okCount, total: results.length, results: results, preview_html: html });
}

async function sendIncidentShareEmail(env, recipient, rep, link, contact) {
  const who = rep.tagged_person_display_name || rep.guest_person_name || 'someone connected to you';
  const cEmail = (contact && contact.email) ? contact.email : 'ruys@thetabsarasota.org';
  const html = '<div style="font-family:-apple-system,system-ui,sans-serif;max-width:520px;margin:0 auto;padding:24px;color:#402020">'
    + '<div style="font-size:13px;font-weight:800;letter-spacing:.06em;color:#6d3d31">THE TABERNACLE CHURCH</div>'
    + '<h2 style="font-size:21px;margin:8px 0 10px">An incident report involving ' + escapeHtml(who) + '</h2>'
    + '<p style="font-size:16px;line-height:1.6">Our team recorded an incident report and is sharing it with you. Open the private link below to read the full report.</p>'
    + '<p style="margin:26px 0"><a href="' + escapeHtml(link) + '" style="background:#402020;color:#fff;text-decoration:none;padding:14px 24px;border-radius:10px;font-weight:700;font-size:16px;display:inline-block">Read the report</a></p>'
    + '<p style="font-size:14px;color:#6d3d31;line-height:1.6">This link is private to you and expires in 45 days. You do not need an account, and you are not required to reply or approve anything.</p>'
    + '<p style="font-size:14px;color:#6d3d31;line-height:1.6">Questions? Contact the church office at <a href="mailto:' + escapeHtml(cEmail) + '" style="color:#6d3d31">' + escapeHtml(cEmail) + '</a>.</p>'
    + '</div>';
  const res = await fetch('https://api.resend.com/emails', {
    method: 'POST',
    headers: { 'Authorization': 'Bearer ' + env.RESEND_API_KEY, 'Content-Type': 'application/json' },
    body: JSON.stringify({
      from: RESEND_FROM_ADDRESS,
      to: [recipient.email],
      subject: 'Incident report from The Tabernacle Church',
      html: html
    })
  });
  if (!res.ok) throw new Error('share_email_failed: ' + (await res.text()).substring(0, 160));
}

// Public tokenized report page. No TabReady account. No login. The token is
// matched by SHA-256 hash and is scoped to exactly one share row, therefore to
// exactly one report and one recipient. Opens are logged; nothing is required
// of the reader (packet section 14).
// v2.9.261: Token-scoped photo for an external recipient. Verified on EVERY request:
// token -> share row -> not revoked -> not expired -> photo resolved FROM that share's
// report_id. The caller never supplies a key, so a valid token can only ever reach the
// photo of its own report. Revoking or expiring a share kills photo access immediately.
async function handleExternalReportPhoto(request, env, token) {
  const deny = function (status) {
    return new Response('Not available', { status: status, headers: { 'Cache-Control': 'no-store', 'X-Robots-Tag': 'noindex, nofollow, noarchive' } });
  };
  const tok = (token || '').trim();
  if (tok.length < 20) return deny(404);
  const th = await shareTokenHash(tok);
  const sh = await env.DB.prepare('SELECT id, report_id, expires_at, revoked_at FROM incident_shares WHERE token_hash = ? LIMIT 1').bind(th).first();
  if (!sh) return deny(404);
  if (sh.revoked_at) return deny(410);
  if (sh.expires_at && new Date(sh.expires_at.replace(' ', 'T') + 'Z').getTime() < Date.now()) return deny(410);
  const rep = await env.DB.prepare('SELECT photo_key FROM incident_reports WHERE id = ? AND deleted_at IS NULL LIMIT 1').bind(sh.report_id).first();
  if (!rep || !rep.photo_key) return deny(404);
  if (!env.PHOTOS) return deny(503);
  const obj = await env.PHOTOS.get(rep.photo_key);
  if (!obj) return deny(404);
  const h = new Headers();
  h.set('Content-Type', (obj.httpMetadata && obj.httpMetadata.contentType) || 'image/jpeg');
  h.set('Cache-Control', 'no-store, private');
  h.set('X-Robots-Tag', 'noindex, nofollow, noarchive');
  h.set('Referrer-Policy', 'no-referrer');
  h.set('Content-Disposition', 'inline');
  return new Response(obj.body, { headers: h });
}

async function handleExternalReportPage(request, env, token) {
  const wrap = function (msg) {
    return new Response('<!doctype html><html><head><meta charset="utf-8"><meta name="viewport" content="width=device-width,initial-scale=1"><title>Incident Report</title></head><body style="font-family:-apple-system,system-ui,sans-serif;background:#faf8f5;margin:0"><div style="max-width:560px;margin:0 auto;padding:40px 22px;color:#402020"><h1 style="font-size:23px">' + msg + '</h1><p style="font-size:16px;line-height:1.6">If you need help, contact the church office.</p></div></body></html>',
      { status: 404, headers: { 'Content-Type': 'text/html; charset=utf-8', 'Cache-Control': 'no-store', 'X-Robots-Tag': 'noindex, nofollow, noarchive' } });
  };
  const tok = (token || '').trim();
  if (tok.length < 20) return wrap('This link is not valid.');
  const th = await shareTokenHash(tok);
  const sh = await env.DB.prepare('SELECT id, report_id, recipient_name, external_note, expires_at, revoked_at, first_opened_at, open_count FROM incident_shares WHERE token_hash = ? LIMIT 1').bind(th).first();
  if (!sh) return wrap('This link is not valid.');
  if (sh.revoked_at) return wrap('This link has been turned off by the church office.');
  if (sh.expires_at && new Date(sh.expires_at.replace(' ', 'T') + 'Z').getTime() < Date.now()) return wrap('This link has expired.');
  const rep = await loadReportForShare(env, sh.report_id);
  if (!rep) return wrap('This report is no longer available.');
  const nowTs = new Date().toISOString().slice(0, 19).replace('T', ' ');
  try {
    await env.DB.prepare('UPDATE incident_shares SET first_opened_at = COALESCE(first_opened_at, ?), last_opened_at = ?, open_count = COALESCE(open_count, 0) + 1 WHERE id = ?')
      .bind(nowTs, nowTs, sh.id).run();
  } catch (e) { /* never block the reader on logging */ }
  const html = '<!doctype html><html lang="en"><head><meta charset="utf-8"><meta name="viewport" content="width=device-width,initial-scale=1">'
    + '<meta name="robots" content="noindex, nofollow, noarchive"><meta name="referrer" content="no-referrer">'
    + '<meta name="theme-color" content="#402020"><title>Incident Report</title></head><body style="margin:0;background:#faf8f5">'
    + externalReportHtml(rep, { external_note: sh.external_note, contact: await incidentContact(env), photo_url: rep.photo_key ? ('/r/' + encodeURIComponent(tok) + '/photo') : null })
    + '</body></html>';
  return new Response(html, { headers: { 'Content-Type': 'text/html; charset=utf-8', 'Cache-Control': 'no-store, private', 'X-Robots-Tag': 'noindex, nofollow, noarchive', 'Referrer-Policy': 'no-referrer' } });
}

// Staff-facing delivery activity for one report. Sent / opened are tracked
// separately and neither implies the recipient agrees with the report.
async function apiIncidentShareList(request, env) {
  const user = await getUserFromRequest(request, env);
  if (!user) return json({ error: 'not_authenticated' }, 401);
  // v2.9.261: browsing delivery activity is a management action - safety/staff/admin only.
  if (!incidentShareManageGate(user)) return json({ error: 'forbidden' }, 403);
  const url = new URL(request.url);
  const rid = (url.searchParams.get('report_id') || '').trim();
  if (!rid) return json({ error: 'report_id_required' }, 400);
  const r = await env.DB.prepare(
    'SELECT id, recipient_name, recipient_email, recipient_source, created_at, sent_at, send_error, first_opened_at, last_opened_at, open_count, revoked_at, expires_at FROM incident_shares WHERE report_id = ? ORDER BY created_at DESC'
  ).bind(rid).all();
  return json({ items: r.results || [] });
}

async function apiIncidentShareRevoke(request, env) {
  const user = await getUserFromRequest(request, env);
  if (!user) return json({ error: 'not_authenticated' }, 401);
  // v2.9.261: revoking someone else's link is a management action - safety/staff/admin only.
  if (!incidentShareManageGate(user)) return json({ error: 'forbidden' }, 403);
  const body = await request.json().catch(function () { return {}; });
  const sid = (body.share_id || '').toString().trim();
  if (!sid) return json({ error: 'share_id_required' }, 400);
  await env.DB.prepare('UPDATE incident_shares SET revoked_at = datetime(\'now\') WHERE id = ? AND revoked_at IS NULL').bind(sid).run();
  await auditV2(env, user.id, 'incident_share_revoked', 'incident_share', sid, {});
  return json({ ok: true });
}

// v3.4: Resolve a stable person id to contact info for the LEADERSHIP EMAIL ONLY.
// Never called on the filer path. Best-effort: any failure returns null (contact omitted).
// self:<userId> -> filer's own email; reg:<id> -> people_registry; pco:<id> -> Planning Center.
async function resolvePersonContact(env, id, user) {
  try {
    if (!id) return null;
    if (id.indexOf('self:') === 0) return { email: (user && user.email) || null, phone: null };
    if (id.indexOf('reg:') === 0) {
      const pid = id.slice(4);
      const r = await env.DB.prepare('SELECT email_primary, email_alt, phone FROM people_registry WHERE person_id = ? LIMIT 1').bind(pid).first();
      if (r) return { email: r.email_primary || r.email_alt || null, phone: r.phone || null };
      return null;
    }
    if (id.indexOf('pco:') === 0 && env.PCO_APP_ID && env.PCO_SECRET) {
      const pid = id.slice(4);
      const creds = btoa(env.PCO_APP_ID + ':' + env.PCO_SECRET);
      const api = 'https://api.planningcenteronline.com/people/v2/people/' + encodeURIComponent(pid) + '?include=emails,phone_numbers';
      const res = await fetch(api, { headers: { 'Authorization': 'Basic ' + creds } });
      if (!res.ok) return null;
      const data = await res.json();
      let email = null, phone = null;
      for (const it of (data.included || [])) {
        const a = it.attributes || {};
        if (it.type === 'Email' && (email === null || a.primary)) email = a.address || email;
        else if (it.type === 'PhoneNumber' && (phone === null || a.primary)) phone = a.number || phone;
      }
      return { email: email, phone: phone };
    }
  } catch (e) { /* best-effort; contact simply omitted */ }
  return null;
}

// v2.9.137: Save a person into TabReady's own contacts (external_contacts).
// Staff/elder gated. Dedupes on exact email or exact phone so re-saving the
// same person updates instead of duplicating. Writes ONLY to TabReady's own
// store - never to PCO, Outlook, Gmail, or Azure.
async function apiAddContact(request, env) {
  const user = await getUserFromRequest(request, env);
  if (!user) return json({ error: 'not_authenticated' }, 401);
  const allowed = user.is_global_admin || (Array.isArray(user.roles) && (user.roles.includes('staff') || user.roles.includes('elders')));
  if (!allowed) return json({ error: 'forbidden' }, 403);

  const body = await request.json().catch(() => ({}));
  const name = (body.display_name || '').toString().trim();
  if (!name) return json({ ok: false, error: 'Name is required.' }, 400);
  const phone = ((body.phone || '').toString().trim()) || null;
  const email = ((body.email || '').toString().trim()) || null;
  const org = ((body.organization || '').toString().trim()) || null;
  const notes = ((body.notes || '').toString().trim()) || null;
  const category = ((body.category || 'saved').toString().trim()) || 'saved';

  const normEmail = (e) => (e ? String(e).trim().toLowerCase() : '');
  const normPhone = (p) => (p ? String(p).replace(/[^0-9]/g, '') : '');

  try {
    let existing = null;
    if (email) {
      existing = await env.DB.prepare(
        'SELECT * FROM external_contacts WHERE active = 1 AND lower(email) = ? LIMIT 1'
      ).bind(normEmail(email)).first();
    }
    if (!existing && phone) {
      const wantP = normPhone(phone);
      const rs = await env.DB.prepare(
        'SELECT * FROM external_contacts WHERE active = 1 AND phone IS NOT NULL'
      ).all();
      for (const r of (rs.results || [])) {
        if (normPhone(r.phone) && normPhone(r.phone) === wantP) { existing = r; break; }
      }
    }

    if (existing) {
      await env.DB.prepare(
        'UPDATE external_contacts SET display_name = ?, '
        + 'phone = COALESCE(?, phone), email = COALESCE(?, email), '
        + 'organization = COALESCE(?, organization), notes = COALESCE(?, notes), '
        + "updated_at = datetime('now') WHERE id = ?"
      ).bind(name, phone, email, org, notes, existing.id).run();
      return json({ ok: true, id: existing.id, action: 'updated' });
    }

    const id = crypto.randomUUID();
    await env.DB.prepare(
      'INSERT INTO external_contacts (id, display_name, organization, role_title, phone, email, is_lead, category, notes, active) '
      + 'VALUES (?, ?, ?, ?, ?, ?, 0, ?, ?, 1)'
    ).bind(id, name, org, null, phone, email, category, notes).run();
    return json({ ok: true, id: id, action: 'inserted' });
  } catch (e) {
    return json({ ok: false, error: 'save_failed' }, 500);
  }
}

// ═════════════════════════════════════════════════════════════
// REPORTS API
// ═════════════════════════════════════════════════════════════

// v2.9.79 — admin onboarding: create a person (phone or email), assign their
//   access (teams), and mint a one-tap login link to text them. Login is by
//   token, so they never need to receive email; the email field is just the
//   account's unique key (synthesized from phone if none given).
async function apiAdminCreateUser(request, env) {
  const admin = await getUserFromRequest(request, env);
  if (!admin) return json({ error: 'not_authenticated' }, 401);
  if (!admin.is_global_admin) return json({ error: 'forbidden' }, 403);

  const body = await request.json().catch(() => ({}));
  const name = (body.name || '').trim();
  let email = (body.email || '').trim().toLowerCase();
  const phone = (body.phone || '').trim();
  const roles = Array.isArray(body.roles) ? body.roles.filter(Boolean) : [];
  const makeAdmin = !!body.is_global_admin;

  if (!name) return json({ error: 'name_required' }, 400);
  if (!email && !phone) return json({ error: 'email_or_phone_required' }, 400);
  if (email && !email.includes('@')) return json({ error: 'invalid_email' }, 400);

  // Login is by token, not inbox — synthesize a unique email if only a phone is given.
  if (!email) {
    const digits = phone.replace(/[^0-9]/g, '') || crypto.randomUUID().slice(0, 8);
    email = digits + '@phone.tabready.local';
  }

  const existing = await env.DB.prepare('SELECT id FROM users WHERE lower(email) = ? LIMIT 1').bind(email).first();
  if (existing) return json({ error: 'already_exists', user_id: existing.id }, 409);

  const userId = 'usr_' + crypto.randomUUID().replace(/-/g, '').slice(0, 16);
  await env.DB.prepare(
    'INSERT INTO users (id, email, display_name, is_global_admin, phone, notify_email) VALUES (?, ?, ?, ?, ?, 1)'
  ).bind(userId, email, name, makeAdmin ? 1 : 0, phone || null).run();

  for (const r of roles) {
    await env.DB.prepare(
      'INSERT OR IGNORE INTO user_roles (user_id, role_id, assigned_by) VALUES (?, ?, ?)'
    ).bind(userId, r, admin.id).run();
  }

  const token = crypto.randomUUID() + '-' + crypto.randomUUID();
  const expiresAt = Math.floor(Date.now() / 1000) + MAGIC_LINK_EXPIRY_SECONDS;
  await env.DB.prepare(
    'INSERT INTO magic_links (token, user_id, expires_at) VALUES (?, ?, ?)'
  ).bind(token, userId, expiresAt).run();

  const loginUrl = `${new URL(request.url).origin}/auth/verify?token=${token}`;
  await auditV2(env, admin.id, 'user_created', 'user', userId,
    { name, email, phone, roles, is_global_admin: makeAdmin });

  return json({ ok: true, user_id: userId, name, login_url: loginUrl, qr_svg: qrSvg(loginUrl) });
}

// v2.9.95 — admin re-link: mint a fresh one-tap login link for an EXISTING user
//   (e.g. someone whose provider drops magic-link emails). Looks them up by email,
//   invalidates any unused links, mints one new 1-hour token. Global-admin gated.
async function apiAdminRelinkUser(request, env) {
  const admin = await getUserFromRequest(request, env);
  if (!admin) return json({ error: 'not_authenticated' }, 401);
  if (!admin.is_global_admin) return json({ error: 'forbidden' }, 403);

  const body = await request.json().catch(() => ({}));
  const email = (body.email || '').trim().toLowerCase();
  if (!email) return json({ error: 'email_required' }, 400);

  const user = await env.DB.prepare(
    'SELECT id, email, display_name FROM users WHERE lower(email) = ? LIMIT 1'
  ).bind(email).first();
  if (!user) return json({ error: 'not_found' }, 404);

  await env.DB.prepare(
    'UPDATE magic_links SET used_at = unixepoch() WHERE user_id = ? AND used_at IS NULL'
  ).bind(user.id).run();

  const token = crypto.randomUUID() + '-' + crypto.randomUUID();
  const expiresAt = Math.floor(Date.now() / 1000) + RELINK_EXPIRY_SECONDS;
  await env.DB.prepare(
    'INSERT INTO magic_links (token, user_id, expires_at) VALUES (?, ?, ?)'
  ).bind(token, user.id, expiresAt).run();

  const loginUrl = `${new URL(request.url).origin}/auth/verify?token=${token}`;
  await auditV2(env, admin.id, 'login_link_generated', 'user', user.id,
    { email: user.email, expires_in_minutes: RELINK_EXPIRY_SECONDS / 60 });

  return json({ ok: true, user_id: user.id, name: user.display_name, login_url: loginUrl, qr_svg: qrSvg(loginUrl) });
}

// v2.9.98 — onboarding gallery: mint a fresh SINGLE-USE login QR for an EXISTING
//   user, valid 7 days, scanned in person off the admin's phone. Same single-use
//   mechanism as relink (invalidate unused links, mint one new token); only the
//   TTL differs (7 days vs 1 hour). Global-admin gated.
async function apiAdminOnboardLink(request, env) {
  const admin = await getUserFromRequest(request, env);
  if (!admin) return json({ error: 'not_authenticated' }, 401);
  if (!admin.is_global_admin) return json({ error: 'forbidden' }, 403);

  const body = await request.json().catch(() => ({}));
  const userId = (body.user_id || '').trim();
  if (!userId) return json({ error: 'user_id_required' }, 400);

  const user = await env.DB.prepare(
    'SELECT id, email, display_name FROM users WHERE id = ? LIMIT 1'
  ).bind(userId).first();
  if (!user) return json({ error: 'not_found' }, 404);

  await env.DB.prepare(
    'UPDATE magic_links SET used_at = unixepoch() WHERE user_id = ? AND used_at IS NULL'
  ).bind(user.id).run();

  const token = crypto.randomUUID() + '-' + crypto.randomUUID();
  const expiresAt = Math.floor(Date.now() / 1000) + ONBOARD_LINK_EXPIRY_SECONDS;
  await env.DB.prepare(
    'INSERT INTO magic_links (token, user_id, expires_at) VALUES (?, ?, ?)'
  ).bind(token, user.id, expiresAt).run();

  const loginUrl = `${new URL(request.url).origin}/auth/verify?token=${token}`;
  await auditV2(env, admin.id, 'onboard_link_generated', 'user', user.id,
    { email: user.email, expires_in_days: ONBOARD_LINK_EXPIRY_SECONDS / 86400 });

  return json({ ok: true, user_id: user.id, name: user.display_name, login_url: loginUrl, qr_svg: qrSvg(loginUrl) });
}

// v2.9.169 — CROSS-ACCOUNT PROVISIONING (Phase 1, staged). Secret-locked, idempotent
//   upsert-by-email. Called by the Relay onboarding orchestrator with a shared secret
//   (header x-provision-secret must equal env.PROVISION_SECRET). DORMANT until that secret
//   is set: with no secret, every call returns 503 and writes NOTHING. The secret value is
//   never logged or returned. Creates OR updates a user by normalized email, ADDS the mapped
//   roles (never removes), never grants admin, and mints a single-use onboarding login link
//   for the QR flow. This is the reference implementation for all target apps.
async function apiProvision(request, env) {
  const configured = (env.PROVISION_SECRET || '').trim();
  if (!configured) return json({ error: 'provisioning_disabled' }, 503);
  const presented = (request.headers.get('x-provision-secret') || '').trim();
  if (!presented || presented !== configured) return json({ error: 'forbidden' }, 403);

  const body = await request.json().catch(() => ({}));
  const name = (body.name || '').trim();
  const email = (body.email || '').trim().toLowerCase();
  const phone = (body.phone || '').trim();
  const roles = Array.isArray(body.roles) ? body.roles.filter(Boolean) : [];
  if (!email || !email.includes('@')) return json({ error: 'valid_email_required' }, 400);

  const existing = await env.DB.prepare(
    'SELECT id, display_name, phone FROM users WHERE lower(email) = ? LIMIT 1'
  ).bind(email).first();

  let userId, action;
  const rolesAdded = [];
  if (existing) {
    userId = existing.id;
    action = 'updated';
    if (name && name !== existing.display_name) {
      await env.DB.prepare('UPDATE users SET display_name = ? WHERE id = ?').bind(name, userId).run();
    }
    if (phone && phone !== (existing.phone || '')) {
      await env.DB.prepare('UPDATE users SET phone = ? WHERE id = ?').bind(phone, userId).run();
    }
  } else {
    userId = 'usr_' + crypto.randomUUID().replace(/-/g, '').slice(0, 16);
    action = 'created';
    await env.DB.prepare(
      'INSERT INTO users (id, email, display_name, is_global_admin, phone, notify_email) VALUES (?, ?, ?, 0, ?, 1)'
    ).bind(userId, email, name || email, phone || null).run();
  }

  for (const r of roles) {
    const res = await env.DB.prepare(
      'INSERT OR IGNORE INTO user_roles (user_id, role_id, assigned_by) VALUES (?, ?, ?)'
    ).bind(userId, r, 'provision').run();
    if (res && res.meta && res.meta.changes) rolesAdded.push(r);
  }

  // Fresh single-use onboarding login link for the QR flow (invalidate any unused first).
  await env.DB.prepare(
    'UPDATE magic_links SET used_at = unixepoch() WHERE user_id = ? AND used_at IS NULL'
  ).bind(userId).run();
  const token = crypto.randomUUID() + '-' + crypto.randomUUID();
  const expiresAt = Math.floor(Date.now() / 1000) + ONBOARD_LINK_EXPIRY_SECONDS;
  await env.DB.prepare(
    'INSERT INTO magic_links (token, user_id, expires_at) VALUES (?, ?, ?)'
  ).bind(token, userId, expiresAt).run();
  const loginUrl = `${new URL(request.url).origin}/auth/verify?token=${token}`;

  try {
    await auditV2(env, 'provision', 'user_provisioned', 'user', userId, { email, action, roles_added: rolesAdded });
  } catch (e) {}

  return json({ ok: true, action, app_person_id: userId, roles_added: rolesAdded, login_url: loginUrl, qr_svg: qrSvg(loginUrl) });
}

// v2.9.98 — onboarding gallery page. Lists every user with a live search box.
//   Tapping a person calls /api/admin/users/onboard-link and shows the QR inline.
//   Global-admin gated. Built with string concat + DOM APIs (no regex literals,
//   no backticks, no ${} inside the client script) to stay deploy-safe.
// v2.9.127 — Edit display_name, email, phone for an existing user.
//   Global-admin gated. Catches duplicate email. Audits to audit_log_v2.
//   Does NOT change roles, is_global_admin, hidden, or any other field.
async function apiAdminUpdateUser(request, env, userId) {
  const admin = await getUserFromRequest(request, env);
  if (!admin) return json({ error: 'not_authenticated' }, 401);
  if (!admin.is_global_admin) return json({ error: 'forbidden' }, 403);

  const body = await request.json().catch(() => ({}));
  const newName = (body.display_name || '').toString().trim();
  const newEmail = (body.email || '').toString().trim().toLowerCase();
  const newPhone = (body.phone || '').toString().trim() || null;

  if (!newName) return json({ error: 'display_name_required' }, 400);
  if (!newEmail || !newEmail.includes('@')) return json({ error: 'invalid_email' }, 400);

  // Confirm target user exists
  const existing = await env.DB.prepare(
    'SELECT id, display_name, email, phone FROM users WHERE id = ? LIMIT 1'
  ).bind(userId).first();
  if (!existing) return json({ error: 'not_found' }, 404);

  try {
    await env.DB.prepare(
      'UPDATE users SET display_name = ?, email = ?, phone = ? WHERE id = ?'
    ).bind(newName, newEmail, newPhone, userId).run();
  } catch (err) {
    // SQLite UNIQUE constraint on email
    if (err && err.message && err.message.includes('UNIQUE')) {
      return json({ error: 'email_already_exists', message: 'That email is already in use by another account.' }, 409);
    }
    console.error('apiAdminUpdateUser DB error:', err);
    return json({ error: 'update_failed', message: err.message }, 500);
  }

  await auditV2(env, admin.id, 'user_updated', 'user', userId, {
    changed: { display_name: newName, email: newEmail, phone: newPhone },
    previous: { display_name: existing.display_name, email: existing.email, phone: existing.phone }
  });

  return json({ ok: true, user_id: userId, display_name: newName, email: newEmail, phone: newPhone });
}


async function onboardGalleryPage(request, env) {
  const admin = await getUserFromRequest(request, env);
  if (!admin) return Response.redirect(new URL('/', request.url).toString(), 302);
  if (!admin.is_global_admin) {
    return new Response(
      '<!doctype html><meta name="viewport" content="width=device-width,initial-scale=1">' +
      '<body style="font-family:system-ui;padding:24px">Forbidden \u2014 global admin only. <a href="/">Home</a></body>',
      { status: 403, headers: { 'Content-Type': 'text/html' } });
  }

  // v2.9.127: fetch users + phone + last_login_at; also pull active magic link status
  const rows = ((await env.DB.prepare(
    'SELECT id, display_name, email, phone, is_global_admin, hidden, last_login_at FROM users ORDER BY display_name COLLATE NOCASE'
  ).all()).results) || [];

  // For each user, check if they have an active (unused, not expired) magic link
  // Returns a map of user_id -> expiry ISO string (or null)
  const activeLinks = {};
  try {
    const linkRows = ((await env.DB.prepare(
      'SELECT user_id, MAX(expires_at) as exp FROM magic_links WHERE used_at IS NULL AND expires_at > unixepoch() GROUP BY user_id'
    ).all()).results) || [];
    for (const lr of linkRows) {
      activeLinks[lr.user_id] = lr.exp;
    }
  } catch (e) { /* non-fatal */ }

  function fmtExpiry(unixTs) {
    if (!unixTs) return null;
    try {
      const d = new Date(unixTs * 1000);
      return d.toLocaleDateString('en-US', { month: 'short', day: 'numeric', year: 'numeric' });
    } catch (e) { return null; }
  }

  let cards = '';
  for (const u of rows) {
    const adminPill = u.is_global_admin
      ? '<span class="pill admin">ADMIN</span>' : '';
    const hiddenPill = u.hidden
      ? '<span class="pill hidden">HIDDEN</span>' : '';
    const exp = activeLinks[u.id];
    const qrStatus = exp
      ? '<span class="qlnk active">Active login link \u00b7 expires ' + escapeHtml(fmtExpiry(exp) || 'soon') + '</span>'
      : '<span class="qlnk none">No active login link</span>';
    const lastLogin = u.last_login_at
      ? 'Last login: ' + escapeHtml(u.last_login_at.slice(0, 10))
      : 'Never logged in';
    const search = escapeHtml(((u.display_name || '') + ' ' + (u.email || '')).toLowerCase());
    // Store editable fields as data attrs for JS to pre-fill (html-escaped, no token values)
    cards +=
      '<div class="card" data-name="' + search + '" data-uid="' + escapeHtml(u.id) + '"' +
        ' data-nm="' + escapeHtml(u.display_name || '') + '"' +
        ' data-em="' + escapeHtml(u.email || '') + '"' +
        ' data-ph="' + escapeHtml(u.phone || '') + '">' +
        '<div class="row"><div class="who">' +
          '<div class="nm">' + escapeHtml(u.display_name) + '</div>' +
          '<div class="em">' + escapeHtml(u.email) + '</div>' +
          '<div class="pills">' + adminPill + hiddenPill + '</div>' +
          '<div class="meta">' + qrStatus + '</div>' +
          '<div class="meta">' + lastLogin + '</div>' +
        '</div>' +
        '<div class="btns">' +
          '<button class="btn" onclick="showQr(this,\'' + escapeHtml(u.id) + '\')">QR</button>' +
          '<button class="btn edit-btn" onclick="openEdit(this)">Edit</button>' +
        '</div>' +
      '</div>' +
      '<div class="qrwrap" style="display:none"></div>' +
      '<div class="editwrap" style="display:none">' +
        '<div class="editform">' +
          '<label class="lbl">Name<input class="finput" data-field="nm" type="text" autocomplete="off"></label>' +
          '<label class="lbl">Email<input class="finput" data-field="em" type="email" autocomplete="off" inputmode="email"></label>' +
          '<label class="lbl">Phone<input class="finput" data-field="ph" type="tel" autocomplete="off" inputmode="tel"></label>' +
          '<div class="roinfo">Roles, admin status, and hidden are read-only in this panel.</div>' +
          '<div class="errmsg" style="display:none"></div>' +
          '<div class="editbtns">' +
            '<button class="btn save-btn" onclick="saveEdit(this)">Save</button>' +
            '<button class="btn cancel-btn" onclick="cancelEdit(this)">Cancel</button>' +
          '</div>' +
        '</div>' +
      '</div>' +
    '</div>';
  }

  const html =
    '<!doctype html><html><head><meta charset="utf-8">' +
    '<meta name="viewport" content="width=device-width,initial-scale=1">' +
    '<title>People / QR \u2014 Admin</title><style>' +
    'body{font-family:system-ui,-apple-system,sans-serif;margin:0;background:#f4f3ee;color:#2b2b2b}' +
    'header{background:#7a9a6a;color:#fff;padding:16px;position:sticky;top:0;z-index:5}' +
    'header h1{margin:0 0 4px;font-size:18px}header p{margin:0;font-size:13px;opacity:.92;line-height:1.4}' +
    '#q{width:100%;box-sizing:border-box;padding:12px;font-size:16px;border:0;border-radius:8px;margin-top:10px}' +
    '.wrap{padding:12px;max-width:560px;margin:0 auto}' +
    '.card{background:#fff;border-radius:12px;padding:14px;margin:10px 0;box-shadow:0 1px 3px rgba(0,0,0,.08)}' +
    '.row{display:flex;align-items:flex-start;gap:10px;justify-content:space-between}' +
    '.who{flex:1;min-width:0}' +
    '.nm{font-weight:600;font-size:15px;word-break:break-word}' +
    '.em{font-size:12px;color:#555;word-break:break-all}' +
    '.pills{margin-top:3px}' +
    '.pill{display:inline-block;margin-right:4px;font-size:10px;font-weight:700;padding:2px 7px;border-radius:999px;background:#eee;color:#555}' +
    '.pill.admin{background:#c0392b;color:#fff}.pill.hidden{background:#888;color:#fff}' +
    '.meta{font-size:11px;color:#888;margin-top:3px}' +
    '.qlnk.active{color:#2d8659;font-weight:600}.qlnk.none{color:#aaa}' +
    '.btns{display:flex;flex-direction:column;gap:6px;flex-shrink:0}' +
    '.btn{background:#2d8659;color:#fff;border:0;border-radius:8px;padding:9px 13px;font-size:13px;font-weight:600;white-space:nowrap;cursor:pointer}' +
    '.btn:disabled{opacity:.5}.edit-btn{background:#ca8342}.cancel-btn{background:#888}.save-btn{background:#2d8659}' +
    '.qrwrap{text-align:center;margin-top:10px}.qrwrap svg{width:220px;height:220px;max-width:80%}' +
    '.editwrap{margin-top:10px;border-top:1px solid #eee;padding-top:10px}' +
    '.editform{display:flex;flex-direction:column;gap:10px}' +
    '.lbl{display:flex;flex-direction:column;font-size:12px;font-weight:600;color:#666;gap:3px}' +
    '.finput{padding:10px;font-size:15px;border:1.5px solid #ddd;border-radius:8px;width:100%;box-sizing:border-box}' +
    '.finput:focus{outline:none;border-color:#2d8659}' +
    '.roinfo{font-size:11px;color:#aaa;padding:4px 0}' +
    '.errmsg{background:#fdecea;color:#c0392b;border-radius:6px;padding:8px 10px;font-size:13px}' +
    '.editbtns{display:flex;gap:8px}' +
    '</style></head><body>' +
    '<header><h1>People / QR \u2014 Admin</h1>' +
    '<p>Edit name, email, or phone. Tap QR to generate a login code. Each QR is single-use, valid 7 days.</p>' +
    '<input id="q" placeholder="Search name or email" oninput="filt()" autocomplete="off"></header>' +
    '<div class="wrap" id="list">' + cards + '</div>' +
    '<script>' +
    'function filt(){var t=document.getElementById("q").value.toLowerCase();' +
    'var cs=document.querySelectorAll(".card");for(var i=0;i<cs.length;i++){' +
    'var n=cs[i].getAttribute("data-name")||\"\";cs[i].style.display=(n.indexOf(t)>-1)?\"\":\"none\";}}' +
    // QR - unchanged logic, token never shown
    'async function showQr(btn,id){btn.disabled=true;var card=btn.closest(".card");' +
    'var w=card.querySelector(".qrwrap");w.style.display="block";w.textContent="Generating\u2026";' +
    'try{var r=await fetch("/api/admin/users/onboard-link",{method:"POST",' +
    'headers:{"Content-Type":"application/json"},credentials:"same-origin",' +
    'body:JSON.stringify({user_id:id})});var d=await r.json();' +
    'if(d&&d.ok){w.innerHTML=d.qr_svg;var note=document.createElement("div");' +
    'note.textContent="Single-use \u00b7 valid 7 days \u00b7 "+d.name;' +
    'note.style.marginTop="6px";note.style.fontSize="12px";note.style.color="#666";' +
    'w.appendChild(note);btn.textContent="Regen QR";}' +
    'else{w.textContent="Error: "+((d&&d.error)||"failed");}}' +
    'catch(e){w.textContent="Network error";}btn.disabled=false;}' +
    // Edit panel open
    'function openEdit(btn){var card=btn.closest(".card");' +
    'var ew=card.querySelector(".editwrap");' +
    'if(ew.style.display!=="none"){ew.style.display="none";btn.textContent="Edit";return;}' +
    'ew.style.display="block";btn.textContent="Close";' +
    'var inputs=ew.querySelectorAll(".finput");' +
    'inputs[0].value=card.getAttribute("data-nm")||"";' +
    'inputs[1].value=card.getAttribute("data-em")||"";' +
    'inputs[2].value=card.getAttribute("data-ph")||"";' +
    'var err=ew.querySelector(".errmsg");err.style.display="none";err.textContent="";}' +
    // Cancel
    'function cancelEdit(btn){var card=btn.closest(".card");' +
    'card.querySelector(".editwrap").style.display="none";' +
    'card.querySelector(".edit-btn").textContent="Edit";}' +
    // Save
    'async function saveEdit(btn){' +
    'var card=btn.closest(".card");' +
    'var uid=card.getAttribute("data-uid");' +
    'var ew=card.querySelector(".editwrap");' +
    'var inputs=ew.querySelectorAll(".finput");' +
    'var nm=inputs[0].value.trim();' +
    'var em=inputs[1].value.trim();' +
    'var ph=inputs[2].value.trim();' +
    'var err=ew.querySelector(".errmsg");' +
    'err.style.display="none";err.textContent="";' +
    'if(!nm){err.textContent="Name is required.";err.style.display="block";return;}' +
    'if(!em||em.indexOf("@")<1){err.textContent="A valid email is required.";err.style.display="block";return;}' +
    'btn.disabled=true;btn.textContent="Saving\u2026";' +
    'try{var r=await fetch("/api/admin/users/"+uid+"/update",{method:"POST",' +
    'headers:{"Content-Type":"application/json"},credentials:"same-origin",' +
    'body:JSON.stringify({display_name:nm,email:em,phone:ph})});' +
    'var d=await r.json();' +
    'if(d&&d.ok){' +
    'card.setAttribute("data-nm",nm);' +
    'card.setAttribute("data-em",em);' +
    'card.setAttribute("data-ph",ph);' +
    'card.querySelector(".nm").textContent=nm;' +
    'card.querySelector(".em").textContent=em;' +
    'card.setAttribute("data-name",(nm+" "+em).toLowerCase());' +
    'ew.style.display="none";card.querySelector(".edit-btn").textContent="Edit";' +
    '}else{var msg=(d&&(d.message||d.error))||"Save failed";' +
    'err.textContent=msg;err.style.display="block";}}' +
    'catch(e){err.textContent="Network error. Try again.";err.style.display="block";}' +
    'btn.disabled=false;btn.textContent="Save";}' +
    '</script></body></html>';

  return new Response(html, { headers: { 'Content-Type': 'text/html' } });
}


async function apiReportsList(request, env) {
  const user = await getUserFromRequest(request, env);
  if (!user) return json({ error: 'not_authenticated' }, 401);
  const isSafety = Array.isArray(user.roles) && user.roles.includes('safety');
  const isStaff = Array.isArray(user.roles) && user.roles.includes('staff');
  if (!user.is_global_admin && !isSafety && !isStaff) return json({ error: 'forbidden' }, 403);
  try {
    const all = await env.DB.prepare(
      `SELECT id, kind, location, summary, reporter_user_id,
              email_sent, email_error, photo_key, created_at, occurred_at,
              resolved_at, resolved_by, resolution_note
       FROM incident_reports
       WHERE deleted_at IS NULL
       ORDER BY (resolved_at IS NOT NULL) ASC, created_at DESC LIMIT 100`
    ).all();
    return json({ items: all.results || [] });
  } catch (err) {
    return json({ items: [], note: 'table_not_yet_created' });
  }
}

async function apiAuditLog(request, env) {
  const user = await getUserFromRequest(request, env);
  if (!user) return json({ error: 'not_authenticated' }, 401);
  if (!user.is_global_admin) return json({ error: 'forbidden' }, 403);
  try {
    const all = await env.DB.prepare(
      `SELECT id, actor_user_id, action, target_kind, target_id, metadata, created_at
       FROM audit_log_v2 ORDER BY created_at DESC LIMIT 200`
    ).all();
    return json({ items: all.results || [] });
  } catch (err) {
    return json({ items: [], note: 'table_not_yet_created' });
  }
}

// ═════════════════════════════════════════════════════════════
// v2.5 — TEAM NOTES API
// ═════════════════════════════════════════════════════════════

async function apiNotesList(request, env) {
  const user = await getUserFromRequest(request, env);
  if (!user) return json({ error: 'not_authenticated' }, 401);

  try {
    // Anyone authenticated can see notes targeted to "all" or to their roles.
    // Global admins see everything.
    const all = await env.DB.prepare(
      `SELECT id, author_user_id, body, target_role, photo_key, status, created_at, closed_at, closed_by
       FROM team_notes WHERE deleted_at IS NULL ORDER BY (status = 'closed') ASC, created_at DESC LIMIT 100`
    ).all();
    const rows = all.results || [];

    // Filter by visibility
    const visible = rows.filter(r => {
      if (user.is_global_admin) return true;
      if (!r.target_role || r.target_role === 'all') return true;
      return Array.isArray(user.roles) && user.roles.includes(r.target_role);
    });

    // Pull author names for display
    const authorIds = [...new Set(visible.map(r => r.author_user_id))];
    let authorMap = {};
    if (authorIds.length > 0) {
      const placeholders = authorIds.map(() => '?').join(',');
      const authRes = await env.DB.prepare(
        `SELECT id, display_name, email FROM users WHERE id IN (${placeholders})`
      ).bind(...authorIds).all();
      (authRes.results || []).forEach(u => {
        authorMap[u.id] = u.display_name || u.email || u.id;
      });
    }

    // v2.9.170: reply counts for visible notes (one grouped query)
    let replyCounts = {};
    const noteIds = visible.map(r => r.id);
    if (noteIds.length > 0) {
      const ph = noteIds.map(() => '?').join(',');
      const rc = await env.DB.prepare(
        `SELECT note_id, COUNT(*) AS c FROM note_replies WHERE deleted_at IS NULL AND note_id IN (${ph}) GROUP BY note_id`
      ).bind(...noteIds).all();
      (rc.results || []).forEach(x => { replyCounts[x.note_id] = x.c; });
    }

    const enriched = visible.map(r => {
      const isStaff = Array.isArray(user.roles) && user.roles.includes('staff');
      const isLaneMember = r.target_role && Array.isArray(user.roles) && user.roles.includes(r.target_role);
      const canClose = !!user.is_global_admin || r.author_user_id === user.id || isStaff || !!isLaneMember;
      return {
        ...r,
        status: r.status || 'open',
        author_name: authorMap[r.author_user_id] || 'Unknown',
        reply_count: replyCounts[r.id] || 0,
        can_close: canClose
      };
    });
    return json({ items: enriched });
  } catch (err) {
    console.error('Notes list failed:', err);
    return json({ items: [], note: 'table_not_yet_created' });
  }
}

// v2.9.73 — resolve who an email-routed note should reach, from live D1.
//   Lane (target_role) -> role's team lead, else role members, else global admins.
//   No hardcoded addresses; always reflects current roster.
const LANE_LABELS = {
  cafe: 'Café Leader', safety: 'Safety Leader', director: 'Facilities Director',
  staff: 'Office / Staff', greeters: 'Greeters / Hospitality', ss_adult: 'Sunday School',
  elders: 'Elders', not_sure: 'Review (unsure)', all: 'All teams'
};
async function resolveNoteRecipients(env, targetRole, isTopTier) {
  // v2.9.100 — mistake-proof routing. No note can blast a group. Everything lands
  //   with Shane for triage. ONLY top-tier (global admin) senders may reach the
  //   elders on purpose; for everyone else, an "elders" note quietly routes to Shane.
  const TRIAGE = ['spass@thetabsarasota.org']; // Shane — single safe point of contact

  if (targetRole === 'elders') {
    if (!isTopTier) return { emails: [...TRIAGE], via: 'triage_elders_blocked' };
    const e = await env.DB.prepare(
      `SELECT u.email FROM user_roles ur JOIN users u ON u.id = ur.user_id
       WHERE ur.role_id = 'elders' AND u.email IS NOT NULL`
    ).all();
    const emails = [...new Set((e.results || []).map(r => r.email).filter(Boolean))];
    return { emails: emails.length ? emails : [...TRIAGE], via: 'elders_toptier' };
  }

  // Broad / unsure -> Shane triage (never a group blast).
  if (!targetRole || targetRole === 'all' || targetRole === 'not_sure') {
    return { emails: [...TRIAGE], via: 'triage' };
  }

  // Specific lane -> its single team lead; if none, Shane triage (never the roster/all admins).
  const lead = await env.DB.prepare(
    `SELECT u.email FROM roles r JOIN users u ON u.id = r.team_lead_user_id
     WHERE r.id = ? AND u.email IS NOT NULL`
  ).bind(targetRole).all();
  const emails = [...new Set((lead.results || []).map(r => r.email).filter(Boolean))];
  if (emails.length === 0) return { emails: [...TRIAGE], via: 'triage_no_lead' };
  return { emails, via: 'team_lead' };
}

async function sendTeamNoteEmail(env, opts) {
  const recipients = opts.recipients || [];
  if (recipients.length === 0) return;
  const html = `
    <div style="font-family: -apple-system, sans-serif; max-width: 480px; margin: 0 auto; padding: 24px;">
      <div style="font-size: 13px; color: #6d3d31; text-transform: uppercase; letter-spacing: 0.5px; font-weight: 700; margin-bottom: 8px;">TabReady — New Note</div>
      <table style="width:100%;border-collapse:collapse;font-size:14px;color:#1a1a1a;">
        <tr><td style="padding:6px 0;color:#6b7280;width:120px;">From:</td><td style="padding:6px 0;"><strong>${escapeHtml(opts.authorName || 'A volunteer')}</strong></td></tr>
        <tr><td style="padding:6px 0;color:#6b7280;">For:</td><td style="padding:6px 0;">${escapeHtml(opts.laneLabel || 'Team')}</td></tr>
      </table>
      <div style="margin-top: 20px; padding: 16px; background: #f7f6f2; border: 1px solid #e5e3dd; border-radius: 8px;">
        <div style="font-size: 12px; color: #6d3d31; text-transform: uppercase; letter-spacing: 0.5px; margin-bottom: 8px; font-weight: 600;">Note</div>
        <div style="font-size: 14px; line-height: 1.6; color: #1a1a1a; white-space: pre-wrap;">${escapeHtml(opts.body || '')}</div>
      </div>
      <p style="color: #999; font-size: 11px; margin-top: 16px;">The Tabernacle Church · Sent from TabReady.</p>
    </div>`;
  const res = await fetch('https://api.resend.com/emails', {
    method: 'POST',
    headers: { 'Authorization': `Bearer ${env.RESEND_API_KEY}`, 'Content-Type': 'application/json' },
    body: JSON.stringify({
      from: RESEND_FROM_ADDRESS, to: recipients,
      subject: `[TabReady] New note for ${opts.laneLabel || 'your team'}`, html
    })
  });
  if (!res.ok) {
    const err = await res.text();
    throw new Error('note_email_failed: ' + err.substring(0, 200));
  }
}

async function apiNoteCreate(request, env) {
  const user = await getUserFromRequest(request, env);
  if (!user) return json({ error: 'not_authenticated' }, 401);

  // v2.6: Accept either JSON or multipart/form-data (for photo upload)
  const contentType = request.headers.get('Content-Type') || '';
  let noteBody, targetRole, photoFile;

  if (contentType.includes('multipart/form-data')) {
    const form = await request.formData();
    noteBody = (form.get('body') || '').toString().trim();
    targetRole = (form.get('target_role') || '').toString().trim() || 'all';
    photoFile = form.get('photo');
  } else {
    const body = await request.json().catch(() => ({}));
    noteBody = (body.body || '').toString().trim();
    targetRole = (body.target_role || '').toString().trim() || 'all';
    photoFile = null;
  }

  if (!noteBody) return json({ error: 'body_required' }, 400);

  const id = crypto.randomUUID();

  // v2.6: photo upload (optional)
  let photoKey = null;
  let photoError = null;
  if (photoFile && typeof photoFile === 'object' && photoFile.size > 0) {
    const upload = await uploadPhotoToR2(env, photoFile, 'team_note', id);
    if (upload.ok) {
      photoKey = upload.key;
    } else {
      photoError = upload.error;
    }
  }

  try {
    await env.DB.prepare(
      `INSERT INTO team_notes (id, author_user_id, body, target_role, photo_key)
       VALUES (?, ?, ?, ?, ?)`
    ).bind(id, user.id, noteBody, targetRole, photoKey).run();
    try { await sendSubmitterReceipt(env, user, `Your note was sent`, `Sent to: ${LANE_LABELS[targetRole] || targetRole}`, `<div style="font-size:14px;color:#1a1a1a;white-space:pre-wrap;">${escapeHtml(noteBody)}</div>`); } catch (e) {}
    await auditV2(env, user.id, 'team_note_posted', 'team_note', id, {
      target_role: targetRole, body_length: noteBody.length,
      has_photo: !!photoKey, photo_error: photoError
    });
    // v2.9.73 — email the note to the right lane (best-effort; never blocks posting).
    try {
      const routed = await resolveNoteRecipients(env, targetRole, !!user.is_global_admin);
      await sendTeamNoteEmail(env, {
        recipients: routed.emails,
        body: noteBody,
        authorName: user.display_name || user.email,
        laneLabel: LANE_LABELS[targetRole] || targetRole
      });
      await auditV2(env, user.id, 'team_note_routed', 'team_note', id,
        { target_role: targetRole, recipients: routed.emails.length, via: routed.via });
    } catch (mailErr) {
      console.error('Note email routing failed:', mailErr);
    }
    return json({ ok: true, id, photo_error: photoError });
  } catch (err) {
    console.error('Note create failed:', err);
    return json({ error: 'create_failed', message: err.message }, 500);
  }
}

// ═════════════════════════════════════════════════════════════
// v2.9.170 — NOTE THREADING + CLOSE. Send a Note is now the single trackable
//   request tool (replaces the standalone Work Orders worker). Adds a reply
//   thread, an open/closed status, and best-effort email notify on reply/close.
//   Closing a note IS the all-clear (notifies the person who filed it).
// ═════════════════════════════════════════════════════════════
async function noteVisibleTo(user, note) {
  if (!note) return false;
  if (user.is_global_admin) return true;
  if (!note.target_role || note.target_role === 'all') return true;
  return Array.isArray(user.roles) && user.roles.includes(note.target_role);
}
function noteCanClose(user, note) {
  if (!user || !note) return false;
  if (user.is_global_admin) return true;
  if (note.author_user_id === user.id) return true;
  if (Array.isArray(user.roles) && user.roles.includes('staff')) return true;
  if (note.target_role && Array.isArray(user.roles) && user.roles.includes(note.target_role)) return true;
  return false;
}
async function notifyNoteEmail(env, toEmail, subject, lines) {
  if (!toEmail) return;
  const body = (lines || []).map(function (l) {
    return '<p style="font-size:14px;line-height:1.6;color:#1a1a1a;margin:0 0 10px">' + escapeHtml(l) + '</p>';
  }).join('');
  const html = '<div style="font-family:-apple-system,sans-serif;max-width:480px;margin:0 auto;padding:24px;">' +
    '<div style="font-size:13px;color:#6d3d31;text-transform:uppercase;letter-spacing:0.5px;font-weight:700;margin-bottom:12px;">TabReady — Note Update</div>' +
    body +
    '<p style="color:#999;font-size:11px;margin-top:16px;">The Tabernacle Church · TabReady</p></div>';
  try { await resendEmail(env, toEmail, subject, html); } catch (e) { console.error('note notify failed:', e); }
}

async function apiNoteRepliesList(request, env, noteId) {
  const user = await getUserFromRequest(request, env);
  if (!user) return json({ error: 'not_authenticated' }, 401);
  const note = await env.DB.prepare('SELECT id, author_user_id, target_role FROM team_notes WHERE id = ? AND deleted_at IS NULL LIMIT 1').bind(noteId).first();
  if (!note) return json({ error: 'not_found' }, 404);
  if (!(await noteVisibleTo(user, note))) return json({ error: 'forbidden' }, 403);
  const rs = await env.DB.prepare('SELECT id, author_name, body, created_at FROM note_replies WHERE note_id = ? AND deleted_at IS NULL ORDER BY created_at ASC').bind(noteId).all();
  return json({ items: rs.results || [] });
}

async function apiNoteReplyCreate(request, env, noteId) {
  const user = await getUserFromRequest(request, env);
  if (!user) return json({ error: 'not_authenticated' }, 401);
  const note = await env.DB.prepare('SELECT id, author_user_id, target_role FROM team_notes WHERE id = ? AND deleted_at IS NULL LIMIT 1').bind(noteId).first();
  if (!note) return json({ error: 'not_found' }, 404);
  if (!(await noteVisibleTo(user, note))) return json({ error: 'forbidden' }, 403);
  const b = await request.json().catch(() => ({}));
  const text = (b.body || '').toString().trim();
  if (!text) return json({ error: 'body_required' }, 400);
  const id = crypto.randomUUID();
  const authorName = user.display_name || user.email || 'Someone';
  await env.DB.prepare('INSERT INTO note_replies (id, note_id, author_user_id, author_name, body) VALUES (?, ?, ?, ?, ?)').bind(id, noteId, user.id, authorName, text).run();
  try { await auditV2(env, user.id, 'note_reply_added', 'team_note', noteId, { reply_id: id }); } catch (e) {}
  try {
    if (note.author_user_id && note.author_user_id !== user.id) {
      const a = await env.DB.prepare('SELECT email FROM users WHERE id = ? LIMIT 1').bind(note.author_user_id).first();
      if (a && a.email) await notifyNoteEmail(env, a.email, '[TabReady] New reply on your note',
        [authorName + ' replied to your note:', text, 'Open TabReady, then Connect, then Send a Note to view the thread.']);
    }
  } catch (e) {}
  return json({ ok: true, id });
}

async function apiNoteClose(request, env, noteId) {
  const user = await getUserFromRequest(request, env);
  if (!user) return json({ error: 'not_authenticated' }, 401);
  const note = await env.DB.prepare('SELECT id, author_user_id, target_role, status FROM team_notes WHERE id = ? AND deleted_at IS NULL LIMIT 1').bind(noteId).first();
  if (!note) return json({ error: 'not_found' }, 404);
  if (!noteCanClose(user, note)) return json({ error: 'forbidden' }, 403);
  const b = await request.json().catch(() => ({}));
  const closeText = (b.note || '').toString().trim();
  const closerName = user.display_name || user.email || 'A leader';
  await env.DB.prepare("UPDATE team_notes SET status='closed', closed_at=datetime('now'), closed_by=? WHERE id = ?").bind(closerName, noteId).run();
  if (closeText) {
    const rid = crypto.randomUUID();
    await env.DB.prepare('INSERT INTO note_replies (id, note_id, author_user_id, author_name, body) VALUES (?, ?, ?, ?, ?)').bind(rid, noteId, user.id, closerName, 'Resolved: ' + closeText).run();
  }
  try { await auditV2(env, user.id, 'note_closed', 'team_note', noteId, {}); } catch (e) {}
  try {
    if (note.author_user_id && note.author_user_id !== user.id) {
      const a = await env.DB.prepare('SELECT email FROM users WHERE id = ? LIMIT 1').bind(note.author_user_id).first();
      if (a && a.email) await notifyNoteEmail(env, a.email, '[TabReady] Your note was resolved',
        [closerName + ' marked your note resolved (all-clear).', closeText ? ('Note: ' + closeText) : '', 'No further action needed.'].filter(Boolean));
    }
  } catch (e) {}
  return json({ ok: true });
}

async function apiNoteReopen(request, env, noteId) {
  const user = await getUserFromRequest(request, env);
  if (!user) return json({ error: 'not_authenticated' }, 401);
  const note = await env.DB.prepare('SELECT id, author_user_id, target_role FROM team_notes WHERE id = ? AND deleted_at IS NULL LIMIT 1').bind(noteId).first();
  if (!note) return json({ error: 'not_found' }, 404);
  if (!noteCanClose(user, note)) return json({ error: 'forbidden' }, 403);
  await env.DB.prepare("UPDATE team_notes SET status='open', closed_at=NULL, closed_by=NULL WHERE id = ?").bind(noteId).run();
  try { await auditV2(env, user.id, 'note_reopened', 'team_note', noteId, {}); } catch (e) {}
  return json({ ok: true });
}

// v2.9.26: Change-request capture. Any user can file a request to edit TabReady
// content/directory/etc. Writes to change_requests in D1 and emails the admin.
async function apiChangeRequestCreate(request, env) {
  const user = await getUserFromRequest(request, env);
  if (!user) return json({ error: 'not_authenticated' }, 401);

  const body = await request.json().catch(() => ({}));
  const reqBody = (body.body || '').toString().trim();
  const reqType = (body.request_type || 'edit').toString().trim();
  if (!reqBody) return json({ error: 'body_required' }, 400);

  const id = crypto.randomUUID();
  try {
    await env.DB.prepare(
      `INSERT INTO change_requests (id, reporter_user_id, reporter_name, reporter_email, request_type, body)
       VALUES (?, ?, ?, ?, ?, ?)`
    ).bind(id, user.id, user.display_name || '', user.email || '', reqType, reqBody).run();
    try { await sendSubmitterReceipt(env, user, `Your change request was submitted`, `Request ID: ${id}`, `<table style="width:100%;border-collapse:collapse;font-size:14px;color:#1a1a1a;"><tr><td style="padding:6px 0;color:#6b7280;width:120px;">Type:</td><td style="padding:6px 0;"><strong>${escapeHtml(reqType)}</strong></td></tr></table><div style="margin-top:12px;font-size:14px;color:#1a1a1a;white-space:pre-wrap;">${escapeHtml(reqBody)}</div>`); } catch (e) {}
    await auditV2(env, user.id, 'change_request_filed', 'change_request', id, {
      request_type: reqType, body_length: reqBody.length
    });
    // Email the admin. Non-fatal if it fails — the request is already saved.
    try { await sendChangeRequestEmail(env, { reporter_name: user.display_name, reporter_email: user.email, request_type: reqType, body: reqBody, id }); }
    catch (e) { console.error('Change-request email failed:', e); }
    return json({ ok: true, id });
  } catch (err) {
    console.error('Change request create failed:', err);
    return json({ error: 'create_failed', message: err.message }, 500);
  }
}

