// v2.9.78 — pull a stored photo out of R2 and base64-encode it as a real email
//   attachment, so recipients see it without logging in. Returns {attachments, note}.
async function photoAttachment(env, photoKey) {
  if (!photoKey) return { attachments: [], note: '' };
  try {
    const obj = await env.PHOTOS.get(photoKey);
    if (!obj) return { attachments: [], note: '' };
    const bytes = new Uint8Array(await obj.arrayBuffer());
    let binary = '';
    for (let i = 0; i < bytes.length; i += 0x8000) {
      binary += String.fromCharCode.apply(null, bytes.subarray(i, i + 0x8000));
    }
    const ext = (photoKey.split('.').pop() || 'jpg').toLowerCase();
    return {
      attachments: [{ filename: 'photo.' + ext, content: btoa(binary) }],
      note: '<tr><td style="padding:6px 0;color:#6b7280;">Photo:</td><td style="padding:6px 0;">Attached to this email.</td></tr>'
    };
  } catch (e) {
    console.error('photoAttachment failed:', e);
    return { attachments: [], note: '<tr><td style="padding:6px 0;color:#6b7280;">Photo:</td><td style="padding:6px 0;">On file — view it in the Reports tab.</td></tr>' };
  }
}

