// ─────────────────────────────────────────────────────────────────────────
// v2.9.118 — TIME OFF REQUESTS
// Staff submit a request (type + date range + purpose). It logs to D1 and
// emails the business office. Elders / global admins can Approve or Deny,
// which emails the requester. Mirrors the existing notes/incident patterns.
// ─────────────────────────────────────────────────────────────────────────

// Who is allowed to approve/deny: elders and global admins (not regular staff).
function canApproveTimeOff(user) {
  return !!(user && (user.is_global_admin ||
    (Array.isArray(user.roles) && user.roles.includes('elders'))));
}

// A simple YYYY-MM-DD shape check without a regex literal.
function isValidYmd(s) {
  if (typeof s !== 'string' || s.length !== 10) return false;
  if (s[4] !== '-' || s[7] !== '-') return false;
  const y = s.slice(0, 4), m = s.slice(5, 7), d = s.slice(8, 10);
  const allDigits = (str) => str.split('').every(ch => ch >= '0' && ch <= '9');
  if (!allDigits(y) || !allDigits(m) || !allDigits(d)) return false;
  const mi = parseInt(m, 10), di = parseInt(d, 10);
  return mi >= 1 && mi <= 12 && di >= 1 && di <= 31;
}

// Day codes match the inherited paper form legend.
const TIME_OFF_CODES = { V: 'Vacation', S: 'Sick', P: 'Personal', H: 'Holiday' };
function timeOffCodeLabel(code) { return TIME_OFF_CODES[code] || 'Vacation'; }

// Render the per-day list (from days_json) as HTML rows for an email.
function renderTimeOffDaysHtml(daysJson) {
  let days = [];
  try { days = JSON.parse(daysJson || '[]'); } catch (e) { days = []; }
  if (!Array.isArray(days) || days.length === 0) return '';
  const items = days.map(d =>
    '<li style="margin:2px 0;">' + escapeHtml(d.date) +
    ' — ' + escapeHtml(timeOffCodeLabel(d.type)) + '</li>'
  ).join('');
  return '<ul style="margin:6px 0 0;padding-left:18px;font-size:14px;color:#1a1a1a;">' + items + '</ul>';
}

async function apiTimeOffCreate(request, env, ctx) {
  const user = await getUserFromRequest(request, env);
  if (!user) return json({ error: 'not_authenticated' }, 401);

  // Gate to staff (same rule as the Receipts tile): global admin OR 'staff' role.
  const isStaff = user.is_global_admin ||
    (Array.isArray(user.roles) && user.roles.includes('staff'));
  if (!isStaff) return json({ error: 'forbidden' }, 403);

  const body = await request.json().catch(() => ({}));
  const purpose = (body.purpose || '').toString().trim();

  // Accept a list of days: [{ date: 'YYYY-MM-DD', type: 'V'|'S'|'P'|'H' }].
  // Backward-compatible: if only start/end are sent, expand them as Vacation.
  let rawDays = Array.isArray(body.days) ? body.days : [];
  if (rawDays.length === 0 && body.start_date && body.end_date) {
    rawDays = [{ date: body.start_date, type: 'V' }, { date: body.end_date, type: 'V' }];
  }

  // Clean, validate, de-dup, and sort the days.
  const seen = {};
  const days = [];
  for (const d of rawDays) {
    const date = (d && d.date ? d.date : '').toString().trim();
    let code = (d && d.type ? d.type : 'V').toString().trim().toUpperCase();
    if (!TIME_OFF_CODES[code]) code = 'V';
    if (!isValidYmd(date)) continue;
    if (seen[date]) continue;
    seen[date] = true;
    days.push({ date, type: code });
  }
  days.sort((a, b) => a.date < b.date ? -1 : (a.date > b.date ? 1 : 0));

  if (days.length === 0) return json({ error: 'no_days' }, 400);
  if (days.length > 60) return json({ error: 'too_many_days' }, 400);

  // Derive summary columns for display/sorting.
  const startDate = days[0].date;
  const endDate = days[days.length - 1].date;
  const totalDays = days.length;
  const counts = {};
  for (const d of days) counts[d.type] = (counts[d.type] || 0) + 1;
  const codesUsed = Object.keys(counts);
  const requestType = codesUsed.length === 1
    ? timeOffCodeLabel(codesUsed[0])
    : 'Mixed';

  const id = crypto.randomUUID();
  const requesterName = user.display_name || user.email || 'Staff member';
  const requesterEmail = user.email || '';

  try {
    await env.DB.prepare(
      `INSERT INTO time_off_requests
        (id, user_id, requester_name, requester_email, request_type,
         start_date, end_date, total_days, days_json, purpose, status)
       VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?, ?, 'Submitted')`
    ).bind(id, user.id, requesterName, requesterEmail, requestType,
           startDate, endDate, totalDays, JSON.stringify(days), purpose).run();

    try { await sendSubmitterReceipt(env, user, `Your time-off request was submitted`, `Status: Submitted`, `<table style="width:100%;border-collapse:collapse;font-size:14px;color:#1a1a1a;"><tr><td style="padding:6px 0;color:#6b7280;width:120px;">Type:</td><td style="padding:6px 0;"><strong>${escapeHtml(requestType)}</strong></td></tr><tr><td style="padding:6px 0;color:#6b7280;">Dates:</td><td style="padding:6px 0;">${escapeHtml(startDate)} to ${escapeHtml(endDate)} (${totalDays})</td></tr>${purpose ? `<tr><td style="padding:6px 0;color:#6b7280;">Purpose:</td><td style="padding:6px 0;">${escapeHtml(purpose)}</td></tr>` : ``}</table>`); } catch (e) {}
    await auditV2(env, user.id, 'time_off_submitted', 'time_off', id, {
      request_type: requestType, total_days: totalDays,
      start_date: startDate, end_date: endDate
    });

    const record = {
      id, requester_name: requesterName, requester_email: requesterEmail,
      request_type: requestType, start_date: startDate, end_date: endDate,
      total_days: totalDays, days_json: JSON.stringify(days),
      purpose, status: 'Submitted'
    };
    const origin = new URL(request.url).origin;
    const send = sendTimeOffEmail(env, record, origin).catch(e =>
      console.error('time off office email failed:', e));
    if (ctx && ctx.waitUntil) ctx.waitUntil(send); else await send;

    return json({ ok: true, id });
  } catch (err) {
    console.error('apiTimeOffCreate failed:', err);
    return json({ error: 'save_failed' }, 500);
  }
}

async function apiTimeOffMine(request, env) {
  const user = await getUserFromRequest(request, env);
  if (!user) return json({ error: 'not_authenticated' }, 401);
  try {
    const rows = await env.DB.prepare(
      `SELECT id, request_type, start_date, end_date, total_days, days_json,
              purpose, status, decided_by_name, decision_note, decided_at, created_at
         FROM time_off_requests
        WHERE user_id = ?
        ORDER BY created_at DESC`
    ).bind(user.id).all();
    return json({ items: rows.results || [] });
  } catch (err) {
    console.error('apiTimeOffMine failed:', err);
    return json({ items: [] });
  }
}

async function apiTimeOffAll(request, env) {
  const user = await getUserFromRequest(request, env);
  if (!user) return json({ error: 'not_authenticated' }, 401);
  if (!canApproveTimeOff(user)) return json({ error: 'forbidden' }, 403);
  try {
    // Pending first, then most recent.
    const rows = await env.DB.prepare(
      `SELECT id, requester_name, requester_email, request_type, start_date,
              end_date, total_days, days_json, purpose, status, decided_by_name,
              decision_note, decided_at, created_at
         FROM time_off_requests
        ORDER BY (status = 'Submitted') DESC, created_at DESC`
    ).all();
    return json({ items: rows.results || [] });
  } catch (err) {
    console.error('apiTimeOffAll failed:', err);
    return json({ items: [] });
  }
}

async function apiTimeOffDecision(request, env, ctx) {
  const user = await getUserFromRequest(request, env);
  if (!user) return json({ error: 'not_authenticated' }, 401);
  if (!canApproveTimeOff(user)) return json({ error: 'forbidden' }, 403);

  const body = await request.json().catch(() => ({}));
  const id = (body.id || '').toString().trim();
  const decision = (body.decision || '').toString().trim(); // 'Approved' | 'Denied'
  const note = (body.note || '').toString().trim();
  if (!id) return json({ error: 'id_required' }, 400);
  if (decision !== 'Approved' && decision !== 'Denied') {
    return json({ error: 'invalid_decision' }, 400);
  }

  try {
    const existing = await env.DB.prepare(
      'SELECT * FROM time_off_requests WHERE id = ? LIMIT 1'
    ).bind(id).first();
    if (!existing) return json({ error: 'not_found' }, 404);

    const deciderName = user.display_name || user.email || 'Elder';
    await env.DB.prepare(
      `UPDATE time_off_requests
          SET status = ?, decided_by_user_id = ?, decided_by_name = ?,
              decision_note = ?, decided_at = datetime('now')
        WHERE id = ?`
    ).bind(decision, user.id, deciderName, note || null, id).run();

    await auditV2(env, user.id, 'time_off_decided', 'time_off', id, {
      decision, requester: existing.requester_name
    });

    if (existing.requester_email) {
      const record = Object.assign({}, existing, {
        status: decision, decided_by_name: deciderName, decision_note: note
      });
      const send = sendTimeOffDecisionEmail(env, record).catch(e =>
        console.error('time off decision email failed:', e));
      if (ctx && ctx.waitUntil) ctx.waitUntil(send); else await send;
    }

    return json({ ok: true });
  } catch (err) {
    console.error('apiTimeOffDecision failed:', err);
    return json({ error: 'update_failed' }, 500);
  }
}

async function apiTimeOffRecipients(request, env) {
  const user = await getUserFromRequest(request, env);
  if (!user) return json({ error: 'not_authenticated' }, 401);
  if (!user.is_global_admin) return json({ error: 'forbidden' }, 403);
  try {
    const rows = await env.DB.prepare(
      'SELECT email, name, created_at FROM time_off_recipients ORDER BY created_at ASC'
    ).all();
    return json({ primary: TIME_OFF_PRIMARY_RECIPIENTS, items: rows.results || [] });
  } catch (err) {
    console.error('apiTimeOffRecipients failed:', err);
    return json({ primary: TIME_OFF_PRIMARY_RECIPIENTS, items: [] });
  }
}

async function apiTimeOffRecipientAdd(request, env) {
  const user = await getUserFromRequest(request, env);
  if (!user) return json({ error: 'not_authenticated' }, 401);
  if (!user.is_global_admin) return json({ error: 'forbidden' }, 403);
  const body = await request.json().catch(() => ({}));
  const email = (body.email || '').toString().trim().toLowerCase();
  const name = (body.name || '').toString().trim();
  // Light email check without a regex literal.
  const at = email.indexOf('@');
  const dot = email.lastIndexOf('.');
  if (email.length < 5 || at < 1 || dot < at + 2 || dot === email.length - 1) {
    return json({ error: 'invalid_email' }, 400);
  }
  try {
    await env.DB.prepare(
      `INSERT INTO time_off_recipients (email, name) VALUES (?, ?)
       ON CONFLICT(email) DO UPDATE SET name = excluded.name`
    ).bind(email, name || null).run();
    await auditV2(env, user.id, 'time_off_recipient_added', 'time_off', email, { name });
    return json({ ok: true });
  } catch (err) {
    console.error('apiTimeOffRecipientAdd failed:', err);
    return json({ error: 'save_failed' }, 500);
  }
}

async function apiTimeOffRecipientDelete(request, env) {
  const user = await getUserFromRequest(request, env);
  if (!user) return json({ error: 'not_authenticated' }, 401);
  if (!user.is_global_admin) return json({ error: 'forbidden' }, 403);
  const body = await request.json().catch(() => ({}));
  const email = (body.email || '').toString().trim().toLowerCase();
  if (!email) return json({ error: 'email_required' }, 400);
  try {
    await env.DB.prepare('DELETE FROM time_off_recipients WHERE email = ?').bind(email).run();
    await auditV2(env, user.id, 'time_off_recipient_removed', 'time_off', email, {});
    return json({ ok: true });
  } catch (err) {
    console.error('apiTimeOffRecipientDelete failed:', err);
    return json({ error: 'delete_failed' }, 500);
  }
}

// ── v2.9.122: one-click email approval ──────────────────────────────────
// Approvers (Ron, elders, and anyone on the notify list) each get a personal
// email with Approve/Deny buttons. The button carries a signed, expiring token
// (HMAC over the request id + action + their email) so a tap acts without a
// login. First response wins; the requester is emailed the decision. The app
// records who acted, so Ron's record-keeping lives in the Time Off tab.

async function signTimeOffActionToken(env, payload) {
  const p = btoa(JSON.stringify(payload));
  const sig = await hmac(env.SESSION_SECRET, p);
  return p + '.' + sig;
}

async function verifyTimeOffActionToken(env, token) {
  if (!token || token.indexOf('.') < 0) return null;
  const parts = token.split('.');
  const p = parts[0], sig = parts[1];
  const expected = await hmac(env.SESSION_SECRET, p);
  if (sig !== expected) return null;
  try {
    const payload = JSON.parse(atob(p));
    if (!payload.exp || payload.exp < Math.floor(Date.now() / 1000)) return null;
    return payload;
  } catch (e) { return null; }
}

async function sendSubmitterReceipt(env, user, heading, subLabel, detailHtml) {
  try {
    if (!user || !user.email) return;
    const _h = `<div style="font-family:-apple-system,sans-serif;max-width:560px;margin:0 auto;padding:24px;"><div style="background:#eef4e6;border-left:4px solid #aac27f;padding:14px 18px;margin-bottom:16px;"><h2 style="color:#402020;margin:0 0 4px;font-size:18px;">${escapeHtml(heading)}</h2>${subLabel ? `<p style="color:#6d3d31;margin:0;font-size:13px;">${escapeHtml(subLabel)}</p>` : ``}</div>${detailHtml || ``}<p style="color:#999;font-size:11px;margin-top:16px;">The Tabernacle Church &middot; This is a confirmation of what you submitted in TabReady. Keep it for your records.</p></div>`;
    await resendEmail(env, user.email, `[TabReady] ${heading}`, _h);
  } catch (e) {}
}

async function resendEmail(env, to, subject, html, opts) {
  try {
    const payload = { from: RESEND_FROM_ADDRESS, to, subject, html };
    if (opts && opts.cc) payload.cc = opts.cc;
    if (opts && opts.reply_to) payload.reply_to = opts.reply_to;
    const res = await fetch('https://api.resend.com/emails', {
      method: 'POST',
      headers: { 'Authorization': `Bearer ${env.RESEND_API_KEY}`, 'Content-Type': 'application/json' },
      body: JSON.stringify(payload)
    });
    if (!res.ok) { console.error('resend failed:', await res.text()); return false; }
    return true;
  } catch (e) { console.error('resend error:', e); return false; }
}

function timeOffDetailsTableHtml(req) {
  return `
      <table style="width:100%;border-collapse:collapse;font-size:14px;color:#1a1a1a;">
        <tr><td style="padding:6px 0;color:#6b7280;width:130px;">Staff member:</td><td style="padding:6px 0;"><strong>${escapeHtml(req.requester_name)}</strong></td></tr>
        <tr><td style="padding:6px 0;color:#6b7280;">Type:</td><td style="padding:6px 0;">${escapeHtml(req.request_type)}</td></tr>
        <tr><td style="padding:6px 0;color:#6b7280;">Total days:</td><td style="padding:6px 0;"><strong>${escapeHtml(String(req.total_days || ''))}</strong></td></tr>
        <tr><td style="padding:6px 0;color:#6b7280;vertical-align:top;">Days requested:</td><td style="padding:6px 0;">${renderTimeOffDaysHtml(req.days_json)}</td></tr>
        <tr><td style="padding:6px 0;color:#6b7280;">Contact:</td><td style="padding:6px 0;">${escapeHtml(req.requester_email || '(none on file)')}</td></tr>
      </table>
      <div style="margin-top:20px;padding:16px;background:#f7f6f2;border:1px solid #e5e3dd;border-radius:8px;">
        <div style="font-size:12px;color:#6d3d31;text-transform:uppercase;letter-spacing:0.5px;margin-bottom:8px;font-weight:600;">Purpose / Notes</div>
        <div style="font-size:14px;line-height:1.6;color:#1a1a1a;white-space:pre-wrap;">${escapeHtml(req.purpose || '(none provided)')}</div>
      </div>`;
}

function timeOffActPage(title, message, color) {
  const html = `<!DOCTYPE html><html><head><meta charset="utf-8"><meta name="viewport" content="width=device-width, initial-scale=1"><title>TabReady</title></head>
  <body style="font-family:-apple-system,sans-serif;background:#f7f6f2;margin:0;padding:24px;">
    <div style="max-width:420px;margin:40px auto;background:#fff;border-radius:12px;padding:28px;border:1px solid #e5e3dd;text-align:center;">
      <div style="font-size:40px;margin-bottom:8px;">🌴</div>
      <h1 style="color:${color};font-size:20px;margin:0 0 10px;">${escapeHtml(title)}</h1>
      <p style="color:#1a1a1a;font-size:15px;line-height:1.5;margin:0;">${message}</p>
      <p style="color:#999;font-size:12px;margin-top:24px;">The Tabernacle Church · TabReady</p>
    </div>
  </body></html>`;
  return new Response(html, { headers: { 'Content-Type': 'text/html' } });
}

async function handleTimeOffAct(request, env, ctx) {
  const url = new URL(request.url);
  const method = request.method;

  // The token may arrive on the query string (GET — the link in the email) or
  // in the form body (POST — the human pressing the Confirm button).
  let token = url.searchParams.get('t') || '';
  if (method === 'POST') {
    try {
      const form = await request.formData();
      const ft = form.get('t');
      if (ft) token = ft.toString();
    } catch (e) {}
  }

  const payload = await verifyTimeOffActionToken(env, token);
  if (!payload || !payload.tid || (payload.act !== 'approve' && payload.act !== 'deny')) {
    return timeOffActPage('Link expired or invalid',
      'This approval link is no longer valid. Open the Time Off tab in TabReady to review the request.', '#c0392b');
  }
  const existing = await env.DB.prepare(
    'SELECT * FROM time_off_requests WHERE id = ? LIMIT 1'
  ).bind(payload.tid).first();
  if (!existing) {
    return timeOffActPage('Request not found', 'This request no longer exists.', '#c0392b');
  }
  if (existing.status !== 'Submitted') {
    return timeOffActPage('Already ' + escapeHtml(existing.status.toLowerCase()),
      'This request was already ' + escapeHtml(existing.status.toLowerCase()) +
      (existing.decided_by_name ? (' by ' + escapeHtml(existing.decided_by_name)) : '') + '.', '#6d3d31');
  }

  const decision = payload.act === 'approve' ? 'Approved' : 'Denied';

  // GET = show a confirmation page ONLY. No database change happens here.
  // Many corporate mail systems auto-open every link in an email to scan it
  // for safety; that auto-open used to silently approve or deny a request.
  // Now a scanner just loads this page and stops — only a real button press
  // (POST) records a decision.
  if (method !== 'POST') {
    return timeOffConfirmPage(existing, decision, token);
  }

  let deciderName = payload.who;
  try {
    const u = await env.DB.prepare('SELECT display_name FROM users WHERE email = ? LIMIT 1').bind(payload.who).first();
    if (u && u.display_name) deciderName = u.display_name;
    else if (payload.who === 'jon@tabsrq.org') deciderName = 'Jon Marino';
  } catch (e) {}

  const upd = await env.DB.prepare(
    `UPDATE time_off_requests
        SET status = ?, decided_by_name = ?, decided_at = datetime('now')
      WHERE id = ? AND status = 'Submitted'`
  ).bind(decision, deciderName, payload.tid).run();

  if (!upd.meta || upd.meta.changes === 0) {
    const cur = await env.DB.prepare('SELECT status, decided_by_name FROM time_off_requests WHERE id = ?').bind(payload.tid).first();
    return timeOffActPage('Already decided',
      'This request was already ' + escapeHtml((cur && cur.status ? cur.status.toLowerCase() : 'decided')) +
      (cur && cur.decided_by_name ? (' by ' + escapeHtml(cur.decided_by_name)) : '') + '.', '#6d3d31');
  }

  await auditV2(env, null, 'time_off_decided_email', 'time_off', payload.tid, { decision, who: payload.who });

  if (existing.requester_email) {
    const record = Object.assign({}, existing, { status: decision, decided_by_name: deciderName });
    const send = sendTimeOffDecisionEmail(env, record).catch(e => console.error('decision email failed:', e));
    if (ctx && ctx.waitUntil) ctx.waitUntil(send); else await send;
  }

  return timeOffActPage(decision,
    'Thank you. This request has been marked ' + decision + ' and ' +
    escapeHtml(existing.requester_name) + ' has been notified.',
    decision === 'Approved' ? '#2d8659' : '#c0392b');
}

function timeOffConfirmPage(req, decision, token) {
  const isApprove = decision === 'Approved';
  const color = isApprove ? '#2d8659' : '#c0392b';
  const verb = isApprove ? 'Approve' : 'Deny';
  const details = timeOffDetailsTableHtml(req);
  const html = '<!DOCTYPE html><html><head><meta charset="utf-8">' +
    '<meta name="viewport" content="width=device-width, initial-scale=1">' +
    '<meta name="robots" content="noindex,nofollow">' +
    '<title>' + escapeHtml(verb) + ' Time Off</title></head>' +
    '<body style="font-family:-apple-system,sans-serif;background:#f7f6f2;margin:0;padding:24px;">' +
    '<div style="max-width:520px;margin:32px auto;background:#fff;border-radius:14px;padding:28px;text-align:center;box-shadow:0 2px 14px rgba(0,0,0,0.06);">' +
    '<div style="font-size:40px;margin-bottom:8px;">🌴</div>' +
    '<h1 style="color:' + color + ';font-size:20px;margin:0 0 6px;">Confirm: ' + escapeHtml(verb) + ' this request?</h1>' +
    '<p style="color:#6d3d31;font-size:14px;margin:0 0 18px;">' + escapeHtml(req.requester_name) +
    ' requested time off. Nothing is recorded until you press the button below.</p>' +
    '<div style="text-align:left;margin:0 0 22px;">' + details + '</div>' +
    '<form method="POST" action="/api/time-off/act">' +
    '<input type="hidden" name="t" value="' + escapeHtml(token) + '">' +
    '<button type="submit" style="background:' + color + ';color:#fff;padding:14px 30px;border:none;border-radius:8px;font-weight:600;font-size:16px;cursor:pointer;">Confirm ' + escapeHtml(verb) + '</button>' +
    '</form>' +
    '<p style="color:#999;font-size:11px;margin-top:18px;">The Tabernacle Church · TabReady</p>' +
    '</div></body></html>';
  return new Response(html, { headers: { 'Content-Type': 'text/html' } });
}

async function sendTimeOffEmail(env, req, origin) {
  const details = timeOffDetailsTableHtml(req);

  // Simple outbound notification. Ron and Pastor Dwain are the (informal)
  // approvers; Ronel is a courtesy copy, kept informed only. Replies go
  // straight back to the staff member who submitted — no buttons, no tracking
  // of approve/deny. The in-app "My Requests" list is the record of days used.
  const toList = ['jon@tabsrq.org', 'pd@tabsrq.org'];      // Jon Marino (Pastor of Admin & Ops), Dwain Kitchens
  const ccList = ['ruys@thetabsarasota.org'];             // Ronel Uys (courtesy / informed)
  const subject = `[TabReady] Time Off Request \u2014 ${req.requester_name} (${req.start_date} to ${req.end_date})`;
  const html = `
    <div style="font-family:-apple-system,sans-serif;max-width:560px;margin:0 auto;padding:24px;">
      <div style="background:#eef4e6;border-left:4px solid #aac27f;padding:14px 18px;margin-bottom:24px;">
        <h2 style="color:#402020;margin:0 0 4px;font-size:18px;">TabReady \u2014 Time Off Request</h2>
        <p style="color:#6d3d31;margin:0;font-size:13px;">${escapeHtml(req.requester_name)} has submitted a time-off request. Just reply to this email to respond to them directly.</p>
      </div>
      ${details}
      <p style="margin-top:16px;color:#6b7280;font-size:12px;">Reply to this message and it goes straight to ${escapeHtml(req.requester_name)}.</p>
      <p style="color:#999;font-size:11px;margin-top:8px;">The Tabernacle Church \u00b7 4141 DeSoto Rd, Sarasota, FL</p>
    </div>`;
  const opts = { cc: ccList };
  if (req.requester_email) {
    opts.reply_to = req.requester_email;
    opts.cc = [...ccList, req.requester_email]; // submitter gets a copy
  }
  await resendEmail(env, toList, subject, html, opts);
}

async function sendTimeOffDecisionEmail(env, req) {
  const approved = req.status === 'Approved';
  const accent = approved ? '#aac27f' : '#c0392b';
  const bg = approved ? '#eef4e6' : '#fdecea';
  const heading = approved ? 'Time Off Approved' : 'Time Off Not Approved';
  const html = `
    <div style="font-family: -apple-system, sans-serif; max-width: 560px; margin: 0 auto; padding: 24px;">
      <div style="background:${bg};border-left:4px solid ${accent};padding:14px 18px;margin-bottom:24px;">
        <h2 style="color:#402020;margin:0 0 4px;font-size:18px;">TabReady — ${escapeHtml(heading)}</h2>
        <p style="color:#6d3d31;margin:0;font-size:13px;">Your time-off request has been reviewed.</p>
      </div>
      <table style="width:100%;border-collapse:collapse;font-size:14px;color:#1a1a1a;">
        <tr><td style="padding:6px 0;color:#6b7280;width:130px;">Type:</td><td style="padding:6px 0;">${escapeHtml(req.request_type)}</td></tr>
        <tr><td style="padding:6px 0;color:#6b7280;">Total days:</td><td style="padding:6px 0;">${escapeHtml(String(req.total_days || ''))}</td></tr>
        <tr><td style="padding:6px 0;color:#6b7280;vertical-align:top;">Days:</td><td style="padding:6px 0;">${renderTimeOffDaysHtml(req.days_json)}</td></tr>
        <tr><td style="padding:6px 0;color:#6b7280;">Decision:</td><td style="padding:6px 0;"><strong>${escapeHtml(req.status)}</strong></td></tr>
        <tr><td style="padding:6px 0;color:#6b7280;">Reviewed by:</td><td style="padding:6px 0;">${escapeHtml(req.decided_by_name || '')}</td></tr>
      </table>
      ${req.decision_note ? `<div style="margin-top:20px;padding:16px;background:#f7f6f2;border:1px solid #e5e3dd;border-radius:8px;"><div style="font-size:12px;color:#6d3d31;text-transform:uppercase;letter-spacing:0.5px;margin-bottom:8px;font-weight:600;">Note</div><div style="font-size:14px;line-height:1.6;color:#1a1a1a;white-space:pre-wrap;">${escapeHtml(req.decision_note)}</div></div>` : ''}
      <p style="margin-top:24px;color:#6b7280;font-size:12px;">This is an automated notification from TabReady. Questions? Reply to the office directly.</p>
      <p style="color:#999;font-size:11px;margin-top:16px;">The Tabernacle Church · 4141 DeSoto Rd, Sarasota, FL</p>
    </div>`;
  const res = await fetch('https://api.resend.com/emails', {
    method: 'POST',
    headers: { 'Authorization': `Bearer ${env.RESEND_API_KEY}`, 'Content-Type': 'application/json' },
    body: JSON.stringify({
      from: RESEND_FROM_ADDRESS, to: req.requester_email,
      subject: `[TabReady] ${heading} — ${req.start_date} to ${req.end_date}`,
      html
    })
  });
  if (!res.ok) {
    const err = await res.text();
    console.error('Resend time-off decision email failed:', err);
    throw new Error('email_send_failed: ' + err.substring(0, 200));
  }
}

async function audit(env, actorId, action, details) {
  try {
    const id = crypto.randomUUID();
    const target = details && (details.alert_id || details.content_id || details.target || null);
    await env.DB.prepare(
      'INSERT INTO audit_log (id, actor_user_id, action, target, metadata) VALUES (?, ?, ?, ?, ?)'
    ).bind(id, actorId, action, target, JSON.stringify(details || {})).run();
  } catch (err) {
    console.error('Audit log failed:', err);
  }
}

async function auditV2(env, actorId, action, targetKind, targetId, metadata) {
  try {
    const id = crypto.randomUUID();
    await env.DB.prepare(
      `INSERT INTO audit_log_v2 (id, actor_user_id, action, target_kind, target_id, metadata)
       VALUES (?, ?, ?, ?, ?, ?)`
    ).bind(id, actorId, action, targetKind || null, targetId || null, JSON.stringify(metadata || {})).run();
  } catch (err) {
    console.error('Audit log v2 failed:', err);
  }
}


// v2.9.97 — Tax-exempt certificate (Phase 2). Served from the shared R2 bucket
//   (tab-shared-docs, key tax-exempt-cert.pdf) via the DOCS binding — the same
//   cert the Supplies app uses. Any logged-in TabReady user may view it.
async function serveTaxExempt(request, env) {
  const user = await getUserFromRequest(request, env);
  if (!user) return errorPage('Please sign in to view the tax-exempt certificate.');
  if (!env.DOCS) {
    return new Response('Tax-exempt document storage is not connected yet. Add the DOCS R2 binding (bucket tab-shared-docs) to this worker.', { status: 500 });
  }
  const obj = await env.DOCS.get('tax-exempt-cert.pdf');
  if (!obj) {
    return new Response('The tax-exempt certificate has not been uploaded yet.', { status: 404 });
  }
  return new Response(obj.body, {
    headers: {
      'Content-Type': 'application/pdf',
      'Content-Disposition': 'inline; filename="TAB-Tax-Exempt-Cert.pdf"',
      'Cache-Control': 'private, max-age=3600'
    }
  });
}

