  // on the nursery sheet is Joe Wassef (no account); churchwide fallback would
  // have silently linked Joe Mascitto (cafe). Team-scoped single names still match.
  if(qn.split(' ').length===1) return {id:null,name:q,status:'unmatched'};
  var r2=find(users); if(r2.one) return {id:r2.one.id,name:r2.one.display_name,status:'matched'};
  if(r2.many) return {id:null,name:q,status:'ambiguous'};
