  var dMon = s.match(/^(\d{1,2})[-\s]([A-Za-z]{3,})$/); if (dMon) { var m = SRV_MON[dMon[2].slice(0,3).toLowerCase()]; if (m && year) return year + '-' + srvPad(m) + '-' + srvPad(+dMon[1]); }
  var monD = s.match(/^([A-Za-z]{3,})[-\s](\d{1,2})$/); if (monD) { var m2 = SRV_MON[monD[1].slice(0,3).toLowerCase()]; if (m2 && year) return year + '-' + srvPad(m2) + '-' + srvPad(+monD[2]); }
