  function isMonthRow(a){ return SRV_MON[String(a||'').trim().slice(0,3).toLowerCase()] !== undefined && String(a||'').trim().length>2; }
  function isDateSerial(v){ return typeof v === 'number' && v > 40000 && v < 60000; }
