async function apiScheduleImport(request, env, ctx) {
  // HTTP wrapper for the in-app upload: authenticate the signed-in user,
  // then run the shared import core. (Logic itself lives in runScheduleImport.)
  const user = await getUserFromRequest(request, env);
  if (!user) return json({ error: 'not_authenticated' }, 401);
  const body = await request.json().catch(() => ({}));
  const r = await runScheduleImport(env, ctx, user, body);
  return json(r, r.ok ? 200 : 400);
}

// v2.9.115 — Email intake path. A trusted intake worker (safety-schedule-intake)
// POSTs here with a shared secret, the sender's email, and the raw .xlsx. We
// resolve the sender to a TabReady account, enforce the SAME team permission as
// the in-app upload (canEditSchedule), and run the IDENTICAL import core
// (overwrite/idempotency). Nothing here can write a schedule the sender could
// not already write from inside the app. Fail-closed: no secret set => 401.
async function apiScheduleImportEmail(request, env, ctx) {
  const secret = request.headers.get('X-Intake-Secret') || '';
  // Expected secret lives in app_settings (set via D1, no worker binding needed),
  // with env.SCHEDULE_INTAKE_SECRET as a fallback. Fail-closed if neither is set.
  let expected = '';
  try {
    const sres = await env.DB.prepare("SELECT value FROM app_settings WHERE key = 'schedule_intake_secret'").all();
    const srow = (sres.results || [])[0];
    expected = (srow && srow.value) ? srow.value : '';
  } catch (e) {}
  if (!expected) expected = (env.SCHEDULE_INTAKE_SECRET || '');
  if (!expected || secret !== expected) {
    return json({ ok: false, error: 'unauthorized' }, 401);
  }
  const body = await request.json().catch(() => ({}));
  const sender = (body.sender || '').toString().trim().toLowerCase();
  const role = (body.role || '').toString().trim();
  if (!sender) return json({ ok: false, error: 'sender_required' }, 400);
  if (!role) return json({ ok: false, error: 'role_required' }, 400);
  const ures = await env.DB.prepare(
    'SELECT id, display_name, email, is_global_admin FROM users WHERE lower(email) = ? AND hidden = 0'
  ).bind(sender).all();
  const urow = (ures.results || [])[0];
  if (!urow) return json({ ok: false, error: 'sender_not_recognized', sender }, 403);
  const rres = await env.DB.prepare('SELECT role_id FROM user_roles WHERE user_id = ?').bind(urow.id).all();
  const roles = (rres.results || []).map(r => r.role_id);
  const user = { id: urow.id, display_name: urow.display_name, email: urow.email, is_global_admin: urow.is_global_admin, roles };
  if (!canEditSchedule(user, role)) return json({ ok: false, error: 'sender_not_authorized_for_team', sender, role }, 403);
  const r = await runScheduleImport(env, ctx, user, { fileB64: body.fileB64, csv: body.csv, role });
  return json(r, r.ok ? 200 : 400);
}

// Shared import core — used by BOTH the in-app upload and the email intake.
// Returns a plain result object (callers wrap with json()). This is the verified
// overwrite/idempotency logic; do not fork it.
async function runScheduleImport(env, ctx, user, body) {
  // Accepts a raw .xlsx file (fileB64) or CSV text. Server reads the file,
  // flattens weekly grids, and parses rows: date, name, role, time, position.
  let csv = (body.csv || '').toString();
  const defaultRole = (body.role || '').toString().trim();

  // v2.9.112: prefer the uploaded raw file. .xlsx → server reader; otherwise text.
  let workCsv = '';
  let gridImport = false;
  if (body.fileB64) {
    try {
      const bytes = xlsxB64ToBytes(body.fileB64);
      if (bytes.length > 4 && bytes[0] === 0x50 && bytes[1] === 0x4B) { // PK zip = xlsx
        const flat = await xlsxToFlatCsv(bytes, defaultRole);
        if (flat) { workCsv = flat; gridImport = true; }
      } else {
        csv = new TextDecoder('utf-8').decode(bytes); // a .csv file uploaded
      }
    } catch (e) {}
  }
  if (!workCsv) {
    if (!csv) return { ok: false, error: 'file_or_csv_required' };
    const flatCsv = srvGridCsvToFlat(csv, defaultRole);
    workCsv = flatCsv || csv;
    if (flatCsv) gridImport = true;
  }
  const lines = workCsv.split(/\r?\n/).map(l => l.trim()).filter(Boolean);

  // v2.9.112: idempotent re-import — replace any prior imported rows for this
  // team within the date range being imported, so re-importing never piles up.
  if (gridImport && defaultRole) {
    const ds = lines
      .map(l => (l.split(',')[0] || '').trim().replace(/\//g, '-'))
      .filter(d => /^\d{4}-\d{2}-\d{2}/.test(d)).sort();
    if (ds.length) {
      try {
        await env.DB.prepare(
          `UPDATE schedule_assignments SET deleted_at = datetime('now'), deleted_by = ?
           WHERE source = 'import' AND role = ? AND event_date >= ? AND event_date <= ? AND deleted_at IS NULL`
        ).bind(user.id, defaultRole, ds[0], ds[ds.length - 1]).run();
      } catch (e) {}
    }
  }
  const imported = []; const skipped = []; const unmatched = []; const ambiguous = []; const matched = []; const byUser = {}; const conflicts = [];
  // v2.9.110: Load accounts WITH their roles so matching can scope to the team.
  const uRes = await env.DB.prepare(
    `SELECT u.id, u.display_name, GROUP_CONCAT(ur.role_id) AS roles
     FROM users u LEFT JOIN user_roles ur ON ur.user_id = u.id WHERE u.hidden = 0 GROUP BY u.id`
  ).all();
  const usersForMatch = (uRes.results || []).map(u => ({
    id: u.id, display_name: u.display_name || '',
    roleset: (u.roles || '').split(',').filter(Boolean)
  }));

  // v2.9.110: Load active unavailability windows so import can flag (not drop)
  // anyone scheduled while marked unavailable. Date strings are YYYY-MM-DD, so
  // lexicographic comparison is correct.
  const blkRes = await env.DB.prepare(
    `SELECT user_id, display_name, start_date, end_date, note FROM schedule_blackouts WHERE deleted_at IS NULL`
  ).all();
  const blackoutList = (blkRes.results || []).map(b => ({
    uid: b.user_id,
    name: b.display_name || '',
    s: b.start_date, e: b.end_date, note: b.note || ''
  }));
  function blackoutHit(resolvedId, slotName, date) {
    for (const b of blackoutList) {
      if (date >= b.s && date <= b.e &&
          ((resolvedId && resolvedId !== 'unlinked' && b.uid && b.uid === resolvedId) || _looseNameEq(b.name, slotName))) {
        return b;
      }
    }
    return null;
  }

  for (let i = 0; i < lines.length; i++) {
    const cols = lines[i].split(',').map(c => c.trim().replace(/^["']|["']$/g, ''));
    // Skip header row
    if (i === 0 && isNaN(Date.parse(cols[0])) && !/^\d{4}/.test(cols[0])) continue;
    const [dateRaw, nameRaw, roleRaw, timeRaw, posRaw] = cols;
    const event_date = (dateRaw || '').replace(/\//g, '-').trim();
    const display_name = (nameRaw || '').trim();
    const role = (roleRaw || defaultRole || '').trim();
    const time_block = (timeRaw || '').trim() || null;
    const position = (posRaw || '').trim() || null;
    if (!event_date || !display_name || !role) { skipped.push(lines[i]); continue; }
    if (!canEditSchedule(user, role)) { skipped.push(lines[i]); continue; }
    const id = crypto.randomUUID();
    // v2.9.110: tolerant, team-scoped, single-candidate-only matching.
    const res = resolvePerson(display_name, role, usersForMatch);
    let resolvedId = 'unlinked';
    let storedName = display_name;          // default: keep the leader's coding
    if (res.status === 'matched') {
      resolvedId = res.id;
      storedName = res.name;                // canonical account name (e.g., "Dave Coker")
      if (_normName(res.name) !== _normName(display_name)) matched.push(display_name + ' → ' + res.name);
    } else if (res.status === 'ambiguous') {
      ambiguous.push(display_name);
    } else {
      unmatched.push(display_name);
    }
    const bHit = blackoutHit(resolvedId, storedName, event_date);
    if (bHit) conflicts.push({ display_name: storedName, event_date, note: bHit.note });
    try {
      await env.DB.prepare(
        `INSERT INTO schedule_assignments (id, event_date, role, user_id, display_name, time_block, position, source, assigned_by)
         VALUES (?, ?, ?, ?, ?, ?, ?, 'import', ?)`
      ).bind(id, event_date, role, resolvedId, storedName, time_block, position, user.id).run();
      imported.push({ id, event_date, display_name: storedName, role });
      if (resolvedId !== 'unlinked') {
        if (!byUser[resolvedId]) byUser[resolvedId] = [];
        byUser[resolvedId].push({ event_date, role, time_block, position });
      }
    } catch (e) { skipped.push(lines[i]); }
  }
  const unmatchedUniq = Array.from(new Set(unmatched));
  const ambiguousUniq = Array.from(new Set(ambiguous));
  await audit(env, user.id, 'schedule_import', { imported: imported.length, skipped: skipped.length, unmatched: unmatchedUniq.length, ambiguous: ambiguousUniq.length, matched: matched.length });
  // Opt-in email: only users who turned schedule emails on get one summary. Best-effort, after response.
  const recipientIds = Object.keys(byUser).slice(0, 100);
  if (ctx && recipientIds.length) {
    ctx.waitUntil((async () => {
      try {
        const ph = recipientIds.map(() => '?').join(',');
        const ur = await env.DB.prepare('SELECT id, display_name, email, notify_email FROM users WHERE id IN (' + ph + ')').bind(...recipientIds).all();
        for (const u of (ur.results || [])) {
          if (u.notify_email && u.email) await sendScheduleEmail(env, u.email, u.display_name, byUser[u.id]);
        }
        for (const uid of recipientIds) {
          const items = byUser[uid] || [];
          const first = items[0];
          if (first) {
            const more = items.length > 1 ? " (+" + (items.length - 1) + " more)" : "";
            await sendPushToUser(env, uid, { title: "You're scheduled to serve", body: humanSchedDate(first.event_date) + " — " + humanRole(first.role) + more, url: "/" });
          }
        }
      } catch (e) {}
    })());
  }
  const firstDate = imported.map(x => x.event_date).filter(Boolean).sort()[0] || null;
  return { ok: true, imported: imported.length, skipped: skipped.length, matched: matched.length, unmatched: unmatchedUniq, ambiguous: ambiguousUniq, conflicts: conflicts.slice(0, 50), first_date: firstDate };
}

async function apiScheduleList(request, env) {
  const user = await getUserFromRequest(request, env);
  if (!user) return json({ error: 'not_authenticated' }, 401);

  try {
    const url = new URL(request.url);
    // month param expected as YYYY-MM; default to current month (server time)
    let month = (url.searchParams.get('month') || '').trim();
    if (!isValidMonth(month)) {
      const now = new Date();
      month = now.getUTCFullYear() + '-' + String(now.getUTCMonth() + 1).padStart(2, '0');
    }
    const monthStart = month + '-01';
    // last day boundary: first of next month
    const [yy, mm] = month.split('-').map(Number);
    const nextMonth = (mm === 12)
      ? (yy + 1) + '-01-01'
      : yy + '-' + String(mm + 1).padStart(2, '0') + '-01';

    // Assignments within the requested month
    const aRes = await env.DB.prepare(
      `SELECT s.id, s.event_date, s.role, s.user_id, s.display_name, s.time_block, s.position, s.source, u.phone AS phone, COALESCE(u.contact_email, u.email) AS email
       FROM schedule_assignments s LEFT JOIN users u ON u.id = s.user_id
       WHERE s.deleted_at IS NULL AND s.event_date >= ? AND s.event_date < ?
       ORDER BY s.event_date ASC, s.role ASC, s.display_name ASC`
    ).bind(monthStart, nextMonth).all();
    const assignments = aRes.results || [];

    // v2.9.111: return ALL active blackouts (not just this month) so the
    // "Currently unavailable" list is always complete and reassuring.
    const bRes = await env.DB.prepare(
      `SELECT id, user_id, display_name, start_date, end_date, note
       FROM schedule_blackouts
       WHERE deleted_at IS NULL
       ORDER BY start_date ASC`
    ).all();
    const blackouts = bRes.results || [];

    // Nearest future date (>= today) that has at least one assignment
    const todayStr = new Date().toISOString().slice(0, 10);
    const nRes = await env.DB.prepare(
      `SELECT MIN(event_date) AS d
       FROM schedule_assignments
       WHERE deleted_at IS NULL AND event_date >= ?`
    ).bind(todayStr).all();
    const nextDay = (nRes.results && nRes.results[0] && nRes.results[0].d) || null;

    // v2.9.257 (Scout R3): contact fields are authorized SERVER-SIDE, per row.
    // This endpoint no longer hands every scheduled person's phone + email to
    // every authenticated account. Names, teams, times, positions are unchanged.
    // Contact rides along only where an operational relationship exists:
    //   - global admins: everything
    //   - your own row: always
    //   - a team you belong to: yes (same exposure the team directory already gives)
    //   - designated team leads serving on a date your own editable team serves: yes
    //   - anything else: phone + email are dropped before the response is built
    const leadIds = {};
    try {
      const lres = await env.DB.prepare('SELECT team_lead_user_id FROM roles WHERE team_lead_user_id IS NOT NULL').all();
      (lres.results || []).forEach(function (r) { if (r.team_lead_user_id) leadIds[String(r.team_lead_user_id)] = 1; });
    } catch (e) { /* fail closed: no cross-team lead contact */ }
    const myRoles = Array.isArray(user.roles) ? user.roles : [];
    const editable = {};
    assignments.forEach(function (a) { if (a.role && editable[a.role] === undefined) editable[a.role] = canEditSchedule(user, a.role); });
    const myDates = {};
    assignments.forEach(function (a) { if (a.role && editable[a.role]) myDates[a.event_date] = 1; });
    const scoped = assignments.map(function (a) {
      let ok = false;
      if (user.is_global_admin) ok = true;
      else if (a.user_id && String(a.user_id) === String(user.id)) ok = true;
      else if (a.role && myRoles.indexOf(a.role) !== -1) ok = true;
      else if (myDates[a.event_date] && a.user_id && leadIds[String(a.user_id)]) ok = true;
      if (ok) return a;
      const b = Object.assign({}, a);
      b.phone = null; b.email = null;
      return b;
    });

    return json({ month, assignments: scoped, blackouts, next_day: nextDay });
  } catch (err) {
    console.error('Schedule list failed:', err);
    return json({ month: null, assignments: [], blackouts: [], next_day: null, note: 'table_not_yet_created' });
  }
}

// YYYY-MM validator — pure char checks, no regex anywhere.
function isValidMonth(s) {
  if (typeof s !== 'string' || s.length !== 7) return false;
  if (s.charAt(4) !== '-') return false;
  for (let i = 0; i < 7; i++) {
    if (i === 4) continue;
    const c = s.charCodeAt(i);
    if (c < 48 || c > 57) return false; // 0-9
  }
  const mn = Number(s.slice(5, 7));
  return mn >= 1 && mn <= 12;
}

async function apiFacilitiesMaps(request, env) {
  const user = await getUserFromRequest(request, env);
  if (!user) return json({ error: 'not_authenticated' }, 401);
  if (!env.PHOTOS) return json({ broad: [], safety: [], note: 'r2_not_configured' });

  const canBroad = canSeeFacilitiesMap(user);
  const canSafety = canSeeFacilitiesMapSafety(user);
  if (!canBroad && !canSafety) return json({ error: 'forbidden' }, 403);

  const broad = [];
  const safety = [];

  try {
    if (canBroad) {
      const listed = await env.PHOTOS.list({ prefix: 'facilities-map/' });
      (listed.objects || []).forEach(function(o) {
        if (o.key && o.key !== 'facilities-map/') {
          var meta = prettyMapName(o.key);
          broad.push({ key: o.key, name: meta.name, building: meta.building, type: meta.type, url: '/photo/' + o.key });
        }
      });
    }
    if (canSafety) {
      const listedS = await env.PHOTOS.list({ prefix: 'facilities-map-safety/' });
      (listedS.objects || []).forEach(function(o) {
        if (o.key && o.key !== 'facilities-map-safety/') {
          var metaS = prettyMapName(o.key);
          safety.push({ key: o.key, name: metaS.name, building: metaS.building, type: metaS.type, url: '/photo/' + o.key });
        }
      });
    }
  } catch (err) {
    console.error('Facilities maps list failed:', err);
    return json({ error: 'list_failed' }, 500);
  }

  // v2.9.82: attach each map's note. A map can carry free text OR be linked to
  // an existing content note (single source of truth). Linked content is shown
  // only if the viewer is allowed to see that note (its role_tags), so nothing
  // leaks; free text rides with the map's own visibility. Non-fatal on error.
  try {
    const dres = await env.DB.prepare('SELECT map_key, description, content_id, location_key FROM map_descriptions').all();
    const dmap = {};
    const wantedIds = [];
    (dres.results || []).forEach(function(r) {
      dmap[r.map_key] = { description: r.description || '', content_id: r.content_id || '', location_key: r.location_key || '' };
      if (r.content_id) wantedIds.push(r.content_id);
    });
    var locmap = {};
    try {
      var lres = await env.DB.prepare('SELECT location_key, name, display_order FROM location_defs').all();
      (lres.results || []).forEach(function(L){ locmap[L.location_key] = { name: L.name, order: L.display_order }; });
    } catch (e) {}
    const linked = {};
    if (wantedIds.length) {
      const uniq = Array.from(new Set(wantedIds));
      const ph = uniq.map(function(){ return '?'; }).join(',');
      const stmt = env.DB.prepare('SELECT id, title, body, role_tags FROM content WHERE deleted_at IS NULL AND id IN (' + ph + ')');
      const cres = await stmt.bind.apply(stmt, uniq).all();
      (cres.results || []).forEach(function(c) {
        var tags = [];
        try { tags = JSON.parse(c.role_tags || '[]'); } catch (e) { tags = []; }
        linked[c.id] = { title: c.title || '', body: c.body || '', tags: tags };
      });
    }
    function viewerCanSee(tags) {
      if (user.is_global_admin) return true;
      if (!Array.isArray(user.roles)) return false;
      return user.roles.some(function(r){ return tags.indexOf(r) !== -1; });
    }
    function applyNote(it) {
      var rec = dmap[it.key];
      it.description = ''; it.note_source = ''; it.note_title = ''; it.content_id = ''; it.location_key = ''; it.location_name = ''; it.location_order = 999;
      if (!rec) return;
      it.content_id = rec.content_id || '';
      if (rec.location_key && locmap[rec.location_key]) { it.location_key = rec.location_key; it.location_name = locmap[rec.location_key].name; it.location_order = locmap[rec.location_key].order; }
      if (rec.content_id && linked[rec.content_id]) {
        if (viewerCanSee(linked[rec.content_id].tags)) {
          it.description = linked[rec.content_id].body;
          it.note_title = linked[rec.content_id].title;
          it.note_source = 'linked';
        }
      } else if (rec.description) {
        it.description = rec.description;
        it.note_source = 'text';
      }
    }
    broad.forEach(applyNote);
    safety.forEach(applyNote);
  } catch (err) {
    console.error('Map notes load failed (non-fatal):', err);
    broad.forEach(function(it) { it.description = it.description || ''; });
    safety.forEach(function(it) { it.description = it.description || ''; });
  }

  broad.sort(function(a, b) { return a.name.localeCompare(b.name); });
  safety.sort(function(a, b) { return a.name.localeCompare(b.name); });
  // v2.9.227: supporting location pages, grouped by location_key, gated by the
  // viewer's roles (never leaks; conservative). Lets the gallery show each
  // location's reference notes so Resources->Maps can route here without loss.
  var locationPages = {};
  try {
    var pres = await env.DB.prepare('SELECT id, title, role_tags, location_key, is_emergency FROM content WHERE deleted_at IS NULL AND location_key IS NOT NULL').all();
    (pres.results || []).forEach(function(p) {
      var tags = []; try { tags = JSON.parse(p.role_tags || '[]'); } catch (e) { tags = []; }
      var canSee = user.is_global_admin || (Array.isArray(user.roles) && user.roles.some(function(r){ return tags.indexOf(r) !== -1; }));
      if (!canSee) return;
      if (!locationPages[p.location_key]) locationPages[p.location_key] = [];
      locationPages[p.location_key].push({ id: p.id, title: p.title, is_emergency: p.is_emergency });
    });
  } catch (e) {}
  return json({ broad: broad, safety: safety, locationPages: locationPages });
}

// v2.9.32: Maps-only uploader. Accepts images (jpg/png/webp/heic) AND PDF.
// Kept separate from uploadPhotoToR2 so incident/watch-list/note photos stay
// image-only. Stores correct content-type so handlePhotoServe serves it right.
async function uploadMapToR2(env, file, folder, recordId) {
  if (!env.PHOTOS) return { ok: false, error: 'r2_not_configured' };
  // Maps can be larger than snapshots (multi-page PDFs). Allow up to 15 MB.
  var MAX_MAP_BYTES = 15 * 1024 * 1024;
  if (file.size > MAX_MAP_BYTES) return { ok: false, error: 'map_too_large_max_15mb' };
  var contentType = file.type || 'application/octet-stream';
  var isPdf = /pdf/i.test(contentType) || /\.pdf$/i.test(file.name || '');
  var isImage = /^image\/(jpeg|jpg|png|webp|heic|heif)$/i.test(contentType);
  if (!isPdf && !isImage) return { ok: false, error: 'invalid_map_type_image_or_pdf' };
  var ext = 'jpg';
  if (isPdf) { ext = 'pdf'; contentType = 'application/pdf'; }
  else if (/png/i.test(contentType)) ext = 'png';
  else if (/webp/i.test(contentType)) ext = 'webp';
  else if (/heic|heif/i.test(contentType)) ext = 'heic';
  var ts = Date.now();
  var key = `${folder}/${recordId}-${ts}.${ext}`;
  try {
    var arrayBuffer = await file.arrayBuffer();
    await env.PHOTOS.put(key, arrayBuffer, {
      httpMetadata: { contentType: contentType },
      customMetadata: { folder: folder, record_id: recordId, uploaded_at: new Date().toISOString() }
    });
    return { ok: true, key: key };
  } catch (err) {
    console.error('R2 map upload failed:', err);
    return { ok: false, error: 'r2_upload_failed' };
  }
}

// v2.9.29: Admin-only facilities map upload.
// v2.9.34: now also reads `building` and `type` and derives the display name
// from the uploaded file's own filename (falling back to the label box for a
// single upload). The recordId encodes building__type__name so the list can
// group/label without any D1 change.
async function apiFacilitiesMapUpload(request, env) {
  const user = await getUserFromRequest(request, env);
  if (!user) return json({ error: 'unauthorized' }, 401);
  if (!user.is_global_admin) return json({ error: 'forbidden' }, 403);
  let form;
  try { form = await request.formData(); }
  catch (err) { return json({ error: 'bad_form' }, 400); }
  const file = form.get('map');
  const scope = (form.get('scope') || 'broad').toString();
  let label = (form.get('label') || '').toString().trim();
  const building = (form.get('building') || 'general').toString().trim() || 'general';
  const type = (form.get('type') || 'general').toString().trim() || 'general';
  if (!file || typeof file === 'string') return json({ error: 'no_file' }, 400);
  const folder = scope === 'safety' ? 'facilities-map-safety' : 'facilities-map';
  var safeRe = new RegExp('[^a-zA-Z0-9]+', 'g');
  var trimRe = new RegExp('^-+|-+$', 'g');
  function slug(s) {
    return (s || '').replace(safeRe, '-').replace(trimRe, '').toLowerCase();
  }
  // Name source: explicit label if given, else the file's own name (minus ext).
  var rawName = label;
  if (!rawName) {
    rawName = (file.name || 'map').toString().replace(/\.[a-zA-Z0-9]+$/, '');
  }
  var nameSlug = slug(rawName) || 'map';
  var buildingSlug = slug(building) || 'general';
  var typeSlug = slug(type) || 'general';
  // Encoded recordId: building__type__name  (uploadMapToR2 appends -<ts>.<ext>)
  var recordId = buildingSlug + '__' + typeSlug + '__' + nameSlug;
  const result = await uploadMapToR2(env, file, folder, recordId);
  if (!result.ok) return json({ error: result.error }, 400);
  await audit(env, user.id, 'facilities_map_uploaded', { key: result.key, scope: folder, building: buildingSlug, type: typeSlug });
  return json({ ok: true, key: result.key });
}

// v2.9.35: Admin-only facilities map delete. Removes one R2 object by its key.
// Key is validated against the two map folders so this endpoint can only ever
// delete a facilities map — never any other R2 object (incident photos, etc).
async function apiFacilitiesMapDelete(request, env) {
  const user = await getUserFromRequest(request, env);
  if (!user) return json({ error: 'unauthorized' }, 401);
  if (!user.is_global_admin) return json({ error: 'forbidden' }, 403);
  if (!env.PHOTOS) return json({ error: 'r2_not_configured' }, 400);
  let payload;
  try { payload = await request.json(); }
  catch (err) { return json({ error: 'bad_json' }, 400); }
  const key = (payload && payload.key ? String(payload.key) : '').trim();
  if (!key) return json({ error: 'no_key' }, 400);
  // Safety gate: only allow deleting objects inside the map folders.
  const okPrefix = key.indexOf('facilities-map/') === 0 || key.indexOf('facilities-map-safety/') === 0;
  if (!okPrefix) return json({ error: 'not_a_map_key' }, 400);
  try {
    await env.PHOTOS.delete(key);
  } catch (err) {
    console.error('Facilities map delete failed:', err);
    return json({ error: 'delete_failed' }, 500);
  }
  // v2.9.81: tidy up any saved note for this map (non-fatal).
  try { await env.DB.prepare('DELETE FROM map_descriptions WHERE map_key = ?').bind(key).run(); }
  catch (err) { console.error('Map description cleanup failed (non-fatal):', err); }
  await audit(env, user.id, 'facilities_map_deleted', { key: key });
  return json({ ok: true, key: key });
}

// v2.9.81: Admin-only — set or clear the note that travels with a map.
// Stored in D1 (map_descriptions), keyed by the R2 map key. Visibility is
// inherited from the map's own broad/safety gate, so there is no separate
// permission to manage. An empty description clears the note.
async function apiFacilitiesMapDescribe(request, env) {
  const user = await getUserFromRequest(request, env);
  if (!user) return json({ error: 'unauthorized' }, 401);
  if (!user.is_global_admin) return json({ error: 'forbidden' }, 403);
  let payload;
  try { payload = await request.json(); }
  catch (err) { return json({ error: 'bad_json' }, 400); }
  const key = (payload && payload.key ? String(payload.key) : '').trim();
  if (!key) return json({ error: 'no_key' }, 400);
  // Same safety gate as delete: only the two map folders are addressable.
  const okPrefix = key.indexOf('facilities-map/') === 0 || key.indexOf('facilities-map-safety/') === 0;
  if (!okPrefix) return json({ error: 'not_a_map_key' }, 400);
  let description = (payload && typeof payload.description === 'string') ? payload.description : '';
  // Cap length defensively — this is a note, not a document.
  if (description.length > 4000) description = description.slice(0, 4000);
  // v2.9.82: optional link to an existing content note (single source of truth).
  let contentId = (payload && typeof payload.content_id === 'string') ? payload.content_id.trim() : '';
  if (contentId) {
    try {
      const chk = await env.DB.prepare('SELECT id FROM content WHERE id = ? AND deleted_at IS NULL').bind(contentId).first();
      if (!chk) contentId = '';
    } catch (e) { contentId = ''; }
  }
  try {
    await env.DB.prepare(
      "INSERT INTO map_descriptions (map_key, description, content_id, updated_at, updated_by) VALUES (?, ?, ?, datetime('now'), ?) ON CONFLICT(map_key) DO UPDATE SET description = excluded.description, content_id = excluded.content_id, updated_at = excluded.updated_at, updated_by = excluded.updated_by"
    ).bind(key, description, contentId, user.id).run();
  } catch (err) {
    console.error('Map description save failed:', err);
    return json({ error: 'save_failed' }, 500);
  }
  await audit(env, user.id, 'facilities_map_described', { key: key, len: description.length, linked: contentId ? 1 : 0 });
  return json({ ok: true, key: key, description: description, content_id: contentId });
}

// v2.9.82: Admin-only — list existing content notes a map can be linked to.
async function apiFacilitiesMapNotes(request, env) {
  const user = await getUserFromRequest(request, env);
  if (!user) return json({ error: 'unauthorized' }, 401);
  if (!user.is_global_admin) return json({ error: 'forbidden' }, 403);
  try {
    const res = await env.DB.prepare('SELECT id, title FROM content WHERE deleted_at IS NULL ORDER BY title').all();
    return json({ notes: (res.results || []) });
  } catch (err) {
    console.error('Map notes list failed:', err);
    return json({ error: 'list_failed' }, 500);
  }
}

// v2.9.82: Admin-only — one-tap sync. For each map NOT already linked or noted,
// attach the matching note for that building (and scope). Never clobbers a map
// an admin has already linked or written. Returns counts.
async function apiFacilitiesMapAutolink(request, env) {
  const user = await getUserFromRequest(request, env);
  if (!user) return json({ error: 'unauthorized' }, 401);
  if (!user.is_global_admin) return json({ error: 'forbidden' }, 403);
  if (!env.PHOTOS) return json({ error: 'r2_not_configured' }, 400);
  function defaultNoteFor(building, scope) {
    var DEF = {
      'family-life-center': '381645517bbec74cdaa8edecfdd5bdc4',
      'youth-building': '35eb76ba228bd01a49aff0f26931546d',
      'foundations-school': 'a7c48c3816b140ea3e0fd16b9227b21b',
      'sanctuary': '5204fd502d1c1ba8560bc677e7ec514e',
      'general': 'campus_locations_rooms'
    };
    if (scope === 'safety' && (building === 'general' || building === 'sanctuary')) {
      return '6d5fedb6eb665364f2698867b895e879';
    }
    return DEF[building] || '';
  }
  try {
    const ex = await env.DB.prepare('SELECT map_key, description, content_id FROM map_descriptions').all();
    const have = {};
    (ex.results || []).forEach(function(r) { have[r.map_key] = r; });
    var linked = 0, skipped = 0;
    async function processPrefix(prefix, scope) {
      const listed = await env.PHOTOS.list({ prefix: prefix });
      var objs = listed.objects || [];
      for (var i = 0; i < objs.length; i++) {
        var key = objs[i].key;
        if (!key || key === prefix) continue;
        var existing = have[key];
        if (existing && ((existing.content_id && existing.content_id.length) || (existing.description && existing.description.length))) { skipped++; continue; }
        var meta = prettyMapName(key);
        var cid = defaultNoteFor(meta.building, scope);
        if (!cid) { skipped++; continue; }
        await env.DB.prepare(
          "INSERT INTO map_descriptions (map_key, description, content_id, updated_at, updated_by) VALUES (?, '', ?, datetime('now'), ?) ON CONFLICT(map_key) DO UPDATE SET content_id = excluded.content_id, updated_at = excluded.updated_at, updated_by = excluded.updated_by"
        ).bind(key, cid, user.id).run();
        linked++;
      }
    }
    await processPrefix('facilities-map/', 'broad');
    await processPrefix('facilities-map-safety/', 'safety');
    await audit(env, user.id, 'facilities_maps_autolinked', { linked: linked, skipped: skipped });
    return json({ ok: true, linked: linked, skipped: skipped });
  } catch (err) {
    console.error('Auto-link failed:', err);
    return json({ error: 'autolink_failed' }, 500);
  }
}

// ═════════════════════════════════════════════════════════════
// v2.6 — MY TEAM (PCO People integration)
// ═════════════════════════════════════════════════════════════

async function apiMyTeam(request, env) {
  const user = await getUserFromRequest(request, env);
  if (!user) return json({ error: 'not_authenticated' }, 401);

  if (!env.PCO_APP_ID || !env.PCO_SECRET) {
    return json({
      members: [],
      birthdays_this_month: [],
      note: 'pco_not_configured',
      message: 'PCO credentials not set. Contact admin.'
    });
  }

  // Check if PCO_GROUP_MAP has any entries
  const groupIds = Object.keys(PCO_GROUP_MAP);
  if (groupIds.length === 0) {
    return json({
      members: [],
      birthdays_this_month: [],
      note: 'pco_groups_not_mapped',
      message: 'PCO groups not mapped to TabReady roles yet. Admin needs to edit PCO_GROUP_MAP in the worker code.'
    });
  }

  // Determine which PCO groups this user should see
  // Admins see all groups; others see groups mapped to their roles
  let visibleGroupIds;
  if (user.is_global_admin) {
    visibleGroupIds = groupIds;
  } else {
    visibleGroupIds = groupIds.filter(gid => {
      const role = PCO_GROUP_MAP[gid];
      return user.roles && user.roles.includes(role);
    });
  }

  if (visibleGroupIds.length === 0) {
    return json({
      members: [],
      birthdays_this_month: [],
      note: 'no_visible_groups',
      message: "You're not in any teams that have PCO groups mapped yet."
    });
  }

  const creds = btoa(env.PCO_APP_ID + ':' + env.PCO_SECRET);
  const allMembers = [];
  const seenPersonIds = new Set();
  let pcoError = null;

  for (const groupId of visibleGroupIds) {
    try {
      // Get group memberships, including the related Person record
      const res = await fetch(
        `https://api.planningcenteronline.com/groups/v2/groups/${groupId}/memberships?include=person&per_page=100`,
        { headers: { 'Authorization': 'Basic ' + creds } }
      );
      if (!res.ok) {
        if (res.status === 401 || res.status === 403) {
          pcoError = 'pco_permissions_missing';
          break;
        }
        continue;
      }
      const data = await res.json();
      const included = data.included || [];
      const persons = included.filter(i => i.type === 'Person');
      const role = PCO_GROUP_MAP[groupId];

      for (const p of persons) {
        if (seenPersonIds.has(p.id)) continue;
        seenPersonIds.add(p.id);
        const attr = p.attributes || {};
        const birthday = attr.birthdate || null;
        allMembers.push({
          id: p.id,
          name: attr.name || ([attr.first_name, attr.last_name].filter(Boolean).join(' ')) || 'Unnamed',
          first_name: attr.first_name || '',
          last_name: attr.last_name || '',
          birthday: birthday,
          avatar_url: attr.avatar || null,
          role: role,
          // contact info comes from a second call per person — see below
          phone: null,
          email: null
        });
      }
    } catch (err) {
      console.error('PCO group fetch failed:', err);
      pcoError = 'pco_request_failed';
    }
  }

  if (pcoError === 'pco_permissions_missing') {
    return json({
      members: [],
      birthdays_this_month: [],
      note: pcoError,
      message: 'Your PCO app needs People + Groups permissions. Update in PCO settings.'
    });
  }

  // Fetch contact info for each member (in parallel, batched)
  // PCO People emails and phone numbers are separate endpoints
  await Promise.all(allMembers.map(async m => {
    try {
      const [emailRes, phoneRes] = await Promise.all([
        fetch(`https://api.planningcenteronline.com/people/v2/people/${m.id}/emails`,
          { headers: { 'Authorization': 'Basic ' + creds } }),
        fetch(`https://api.planningcenteronline.com/people/v2/people/${m.id}/phone_numbers`,
          { headers: { 'Authorization': 'Basic ' + creds } })
      ]);
      if (emailRes.ok) {
        const ed = await emailRes.json();
        const primary = (ed.data || []).find(e => e.attributes?.primary) || (ed.data || [])[0];
        m.email = primary?.attributes?.address || null;
      }
      if (phoneRes.ok) {
        const pd = await phoneRes.json();
        const primary = (pd.data || []).find(p => p.attributes?.primary) || (pd.data || [])[0];
        m.phone = primary?.attributes?.number || null;
      }
    } catch (err) {
      // Silent fail per member — just no contact info
    }
  }));

  // Compute this-month birthdays
  const now = new Date();
  const thisMonth = now.getMonth() + 1; // 1-12
  const birthdaysThisMonth = allMembers
    .filter(m => {
      if (!m.birthday) return false;
      // birthday format: "YYYY-MM-DD"
      const parts = m.birthday.split('-');
      if (parts.length < 2) return false;
      return parseInt(parts[1], 10) === thisMonth;
    })
    .map(m => {
      const parts = m.birthday.split('-');
      return {
        id: m.id,
        name: m.name,
        day: parseInt(parts[2], 10),
        month: parseInt(parts[1], 10),
        role: m.role
      };
    })
    .sort((a, b) => a.day - b.day);

  // Sort all members alphabetically by last name
  allMembers.sort((a, b) => {
    const al = (a.last_name || a.name).toLowerCase();
    const bl = (b.last_name || b.name).toLowerCase();
    return al.localeCompare(bl);
  });

  return json({
    members: allMembers,
    birthdays_this_month: birthdaysThisMonth,
    note: 'ok'
  });
}

