function facEsc(s){ return String(s==null?'':s).replace(/&/g,'&amp;').replace(/</g,'&lt;').replace(/"/g,'&quot;'); }
function facInit(){
  if (window.__facWired) return; window.__facWired = true;
  document.addEventListener('click', function(e){
    var el = e.target.closest ? e.target.closest('[data-fac]') : null;
    if (!el) return;
    var d = el.getAttribute('data-fac'); var p = d.indexOf(':');
    var k = d.slice(0,p), v = d.slice(p+1);
    if (k === 'cat') setContentCat(v);
    else if (k === 'open') openContent(v);
    else if (k === 'search') commonGo('search', v);
    else if (k === 'maps') showTab('facilities');
    else if (k === 'issue') window.open('https://tab-workorders.shanepass.workers.dev','_blank','noopener');
    else if (k === 'supply') window.open('https://tab-supplies-worker.shanepass.workers.dev/','_blank','noopener');
  });
}
function facBar(){
  return '<button type="button" data-fac="cat:all" style="background:#9cb573;color:#22301a;border:none;font-weight:750;font-size:14px;padding:9px 13px;border-radius:11px;cursor:pointer;margin-bottom:12px">‹ Back to Facilities</button>';
}
function facWorkRow(r){
  var act = r.id ? ('open:'+r.id) : ('search:'+r.s);
  var info = r.i ? '<div style="font-size:13px;color:#5b6b3f;font-weight:600;margin-top:3px">'+facEsc(r.i)+'</div>' : '';
  return '<div data-fac="'+act+'" style="background:#fff;border:1px solid #e6e6de;border-radius:13px;padding:13px;margin-bottom:9px;cursor:pointer"><div style="font-size:15px;font-weight:700;line-height:1.2">'+facEsc(r.t)+'</div>'+info+'</div>';
}
function facCatHTML(key){
  var g = FAC_CATS[key];
  var h = facBar() + '<div style="font-size:18px;font-weight:800;margin:2px 2px 12px">'+g.icon+' '+facEsc(g.label)+'</div>';
  for (var i=0;i<g.rows.length;i++) h += facWorkRow(g.rows[i]);
  facInit(); return h;
}
function facPerson(name, role, tel){
  var h = '<div style="background:#fff;border:1px solid #e6e6de;border-radius:14px;padding:14px;margin-bottom:10px"><div style="font-size:16px;font-weight:750">'+facEsc(name)+'</div><div style="font-size:13px;color:#7a766e;margin-top:2px">'+facEsc(role)+'</div>';
  if (tel){
    h += '<div style="display:flex;gap:8px;margin-top:11px"><a href="sms:'+tel+'" style="background:#dcecf5;color:#234;border-radius:10px;padding:9px 15px;font-weight:700;font-size:13.5px;text-decoration:none">Text</a><a href="tel:'+tel+'" style="background:#e7f0da;color:#3a4a1f;border-radius:10px;padding:9px 15px;font-weight:700;font-size:13.5px;text-decoration:none">Call</a></div>';
  } else {
    h += '<div style="margin-top:10px;font-size:12.5px;color:#a8a49b;font-style:italic">Direct contact to be added</div>';
  }
  return h + '</div>';
}
