  var h = '';
  h += '<button type="button" data-fac="issue:1" style="display:block;width:100%;box-sizing:border-box;border:none;border-radius:16px;padding:17px 16px;margin:2px 0 10px;text-align:left;color:#fff;background:linear-gradient(135deg,#ca8342,#b0641f);box-shadow:0 3px 8px rgba(176,100,31,.28);cursor:pointer;font:inherit"><div style="font-size:17px;font-weight:800">🛠️ Report a Facility Issue</div><div style="font-size:12.5px;opacity:.92;margin-top:3px">Photo + location → straight to the facilities team</div></button>';
