  h += '<button type="button" data-fac="supply:1" style="color:#fff;border:none;border-radius:14px;padding:14px 12px;text-align:left;font-weight:750;font-size:14.5px;cursor:pointer;min-height:64px;background:linear-gradient(135deg,#5fa0c8,#3f83ac);font-family:inherit">📦 Request Supplies</button>';
