// v2.5: Team Notes
async function loadNotes() {
  try {
    const res = await fetch('/api/notes');
    if (!res.ok) return;
    const data = await res.json();
    const items = data.items || [];
    const el = document.getElementById('notes-list');
    if (items.length === 0) {
      el.innerHTML =
        '<div class="start-here">' +
          '<div class="start-here-title">No notes yet</div>' +
          '<div class="start-here-body">When a note is sent, it will show up here.</div>' +
        '</div>';
      return;
    }
    el.innerHTML = items.map(function(n) {
      var idq = JSON.stringify(n.id).replace(/"/g,'&quot;');
      var target = n.target_role && n.target_role !== 'all'
        ? '<span class="pill pill-role">' + esc(n.target_role) + '</span>'
        : '<span class="pill pill-role">All teams</span>';
      var isClosed = n.status === 'closed';
      var statusBadge = isClosed
        ? '<span class="pill" style="background:#3f6b50;color:#fff">✓ Resolved</span>'
        : '<span class="pill" style="background:#ca8342;color:#fff">● Open</span>';
      var closedLine = (isClosed && n.closed_by)
        ? '<div style="font-size:12px;color:var(--muted);margin-top:4px">Resolved by ' + esc(n.closed_by) + (n.closed_at ? (' · ' + esc(n.closed_at)) : '') + '</div>'
        : '';
      var photo = n.photo_key
        ? '<div style="margin-top:10px"><a href="/photo/' + esc(n.photo_key) + '" target="_blank"><img src="/photo/' + esc(n.photo_key) + '" alt="note photo" style="max-width:100%;max-height:280px;border-radius:8px;border:1px solid var(--border)"></a></div>'
        : '';
      var canDelete = (n.author_user_id === ME_USER_ID) || USER_IS_GLOBAL_ADMIN;
      var rc = n.reply_count || 0;
      var replyBtn = '<button class="row-btn" onclick="toggleReplies(' + idq + ')">💬 Replies (' + rc + ')</button>';
      var closeBtn = '';
      if (n.can_close) {
        closeBtn = isClosed
          ? '<button class="row-btn" onclick="reopenNote(' + idq + ')">↩ Reopen</button>'
          : '<button class="row-btn" style="background:#3f6b50;color:#fff" onclick="closeNote(' + idq + ')">✓ Mark resolved</button>';
      }
      var delBtn = canDelete
        ? '<button class="row-btn row-btn-delete" onclick="deleteNote(' + idq + ')">🗑 Delete</button>'
        : '';
      var actionRow = '<div class="row-actions">' + replyBtn + closeBtn + delBtn + '</div>';
      var replyBox =
        '<div id="replies-' + n.id + '" class="note-replies" style="display:none;margin-top:10px;border-top:1px solid var(--border);padding-top:10px">' +
          '<div id="replies-list-' + n.id + '"><div class="empty">Loading…</div></div>' +
          '<textarea id="reply-body-' + n.id + '" placeholder="Add a reply or update…" style="width:100%;margin-top:8px"></textarea>' +
          '<button class="btn" style="margin-top:6px" onclick="postReply(' + idq + ')">Send reply</button>' +
        '</div>';
      return '<div class="notes-list-item">' +
        '<div class="notes-list-item-meta">' + esc(n.author_name) + ' · ' + esc(n.created_at) + ' · ' + target + ' ' + statusBadge + '</div>' +
        '<div class="notes-list-item-body">' + esc(n.body) + '</div>' +
        closedLine +
        photo +
        actionRow +
        replyBox +
        '</div>';
    }).join('');
  } catch (e) {
    document.getElementById('notes-list').innerHTML = '<div class="empty">Could not load notes.</div>';
  }
}

