// v2.9.170: note thread + close/reopen (Send a Note is the trackable request tool)
async function toggleReplies(id) {
  var box = document.getElementById('replies-' + id);
  if (!box) return;
  if (box.style.display === 'none') { box.style.display = 'block'; loadReplies(id); }
  else { box.style.display = 'none'; }
}
async function loadReplies(id) {
  var list = document.getElementById('replies-list-' + id);
  if (!list) return;
  try {
    var res = await fetch('/api/notes/' + encodeURIComponent(id) + '/replies');
    var data = await res.json();
    var items = data.items || [];
    if (items.length === 0) { list.innerHTML = '<div class="empty" style="padding:6px 0">No replies yet.</div>'; return; }
    list.innerHTML = items.map(function(r) {
      return '<div style="padding:6px 0;border-bottom:1px solid var(--border)">' +
        '<div style="font-size:12px;color:var(--muted)">' + esc(r.author_name) + ' · ' + esc(r.created_at) + '</div>' +
        '<div style="font-size:14px">' + esc(r.body) + '</div>' +
        '</div>';
    }).join('');
  } catch (e) { list.innerHTML = '<div class="empty">Could not load replies.</div>'; }
}
async function postReply(id) {
  var ta = document.getElementById('reply-body-' + id);
  if (!ta) return;
  var body = ta.value.trim();
  if (!body) { ta.focus(); return; }
  try {
    var res = await fetch('/api/notes/' + encodeURIComponent(id) + '/replies', { method: 'POST', headers: { 'Content-Type': 'application/json' }, body: JSON.stringify({ body: body }) });
    if (res.ok) { ta.value = ''; loadReplies(id); loadNotes(); }
    else { alert('Could not send reply.'); }
  } catch (e) { alert('Could not send reply.'); }
}
async function closeNote(id) {
  var note = prompt('Optional note for whoever filed this (or leave blank), then OK to mark resolved:');
  if (note === null) return;
  try {
    var res = await fetch('/api/notes/' + encodeURIComponent(id) + '/close', { method: 'POST', headers: { 'Content-Type': 'application/json' }, body: JSON.stringify({ note: note }) });
    if (res.ok) { loadNotes(); } else { alert('Could not mark resolved.'); }
  } catch (e) { alert('Could not mark resolved.'); }
}
async function reopenNote(id) {
  try {
    var res = await fetch('/api/notes/' + encodeURIComponent(id) + '/reopen', { method: 'POST' });
    if (res.ok) { loadNotes(); } else { alert('Could not reopen.'); }
  } catch (e) { alert('Could not reopen.'); }
}

async function postNote() {
  const bodyEl = document.getElementById('note-body');
  const roleEl = document.getElementById('note-role');
  const photoEl = document.getElementById('note-photo');
  const btn = document.getElementById('note-send');
  const body = bodyEl.value.trim();
  if (!body) { bodyEl.focus(); return; }
  btn.disabled = true; btn.textContent = 'Posting…';
  try {
    // v2.6: multipart form (supports photo)
    const fd = new FormData();
    fd.append('body', body);
    fd.append('target_role', roleEl.value);
    if (photoEl.files && photoEl.files[0]) {
      fd.append('photo', photoEl.files[0]);
    }
    const res = await fetch('/api/notes', { method: 'POST', body: fd });
    if (res.ok) {
      const data = await res.json();
      bodyEl.value = '';
      roleEl.value = 'not_sure';
      photoEl.value = '';
      if (data.photo_error) {
        alert('Note posted, but photo upload failed: ' + data.photo_error);
      }
      loadNotes();
    } else {
      alert('Could not post note. Try again.');
    }
  } catch (e) {
    alert('Could not post note. Try again.');
  } finally {
    btn.disabled = false; btn.textContent = 'Post Note';
  }
}

async function postChangeRequest() {
  const bodyEl = document.getElementById('cr-body');
  const btn = document.getElementById('cr-send');
  const body = bodyEl.value.trim();
  if (!body) { bodyEl.focus(); return; }
  btn.disabled = true; btn.textContent = 'Sending…';
  try {
    const res = await fetch('/api/change-requests', {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify({ body: body, request_type: 'edit' })
    });
    if (res.ok) {
      bodyEl.value = '';
      alert('Request sent. Shane has been notified and will review it. Thank you.');
    } else {
      alert('Could not send request. Try again.');
    }
  } catch (e) {
    alert('Could not send request. Try again.');
  } finally {
    btn.disabled = false; btn.textContent = 'Send Request';
  }
}

