// v2.9.19: Conversation history for Ask Tab. Mirrors website widget
// behavior — keep last 6 turns, send to backend for multi-turn context.
var ASK_HISTORY = [];

async function sendAsk() {
  const qEl = document.getElementById('ask-q');
  const q = qEl.value.trim();
  if (!q) return;
  const btn = document.getElementById('ask-send');
  const history = document.getElementById('ask-history');
  btn.disabled = true; btn.textContent = 'Thinking…';

  // Append user bubble immediately
  appendAskMsg('user', q);

  // Add a progress bar bubble while we wait
  var prog = document.createElement('div');
  prog.className = 'ask-progress';
  prog.id = 'ask-progress-bar';
  history.appendChild(prog);
  prog.scrollIntoView({ behavior: 'smooth', block: 'end' });

  try {
    const res = await fetch('/api/ask', {
      method: 'POST', headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify({ question: q, history: ASK_HISTORY.slice(-6) })
    });
    const data = await res.json();
    if (prog.parentNode) prog.parentNode.removeChild(prog);
    const answer = data.answer || 'No answer.';
    appendAskMsg('bot', answer);
    // Track history for multi-turn context (website widget does the same)
    ASK_HISTORY.push({ role: 'user', content: q });
    ASK_HISTORY.push({ role: 'assistant', content: answer });
    qEl.value = '';
    qEl.focus();
  } catch (e) {
    if (prog.parentNode) prog.parentNode.removeChild(prog);
    appendAskMsg('bot', 'Something went wrong. Please try again, or call the church office at (941) 355-8858.');
  } finally {
    btn.disabled = false; btn.textContent = 'Ask';
  }
}

function appendAskMsg(role, text) {
  var history = document.getElementById('ask-history');
  var d = document.createElement('div');
  d.className = 'ask-msg ' + role;
  if (role === 'bot') {
    d.innerHTML = renderMessageHTML(text);
  } else {
    d.textContent = text;
  }
  history.appendChild(d);
  if (role === 'user') {
    setTimeout(function() { history.scrollTop = history.scrollHeight; }, 50);
  } else {
    setTimeout(function() { d.scrollIntoView({ behavior: 'smooth', block: 'start' }); }, 50);
  }
}

// v2.9.19: Ported from tab-website-ai embed widget renderMessageHTML.
// Strips markdown (** __ * # backticks), converts [text](url) and bare
// http(s) URLs to clickable links, preserves newlines via CSS white-space.
// Uses new RegExp() with double-escaped string literals because this
// function lives inside a backtick template literal in the worker source —
// regex literals like /\s/ get mangled by the template parser.
function renderMessageHTML(text) {
  var s = String(text == null ? '' : text);

  // Strip Q:/A: prefixes if the model ever emits them
  s = s.replace(new RegExp('^\\\\s*(Q|Question):\\\\s*[^\\\\n]*\\\\n+', 'i'), '');
  s = s.replace(new RegExp('^\\\\s*(A|Answer):\\\\s*', 'i'), '');

  // Unwrap bold/italic wrapping a link: **[text](url)** -> [text](url)
  s = s.replace(new RegExp('(\\\\*\\\\*|__)\\\\s*(\\\\[[^\\\\]]+\\\\]\\\\(https?://[^\\\\s)]+\\\\))\\\\s*(\\\\*\\\\*|__)', 'g'), '$2');
  // Unwrap bare URL in bold/italic
  s = s.replace(new RegExp('__\\\\s*(https?://[^\\\\s_]+)\\\\s*__', 'g'), '$1');
  s = s.replace(new RegExp('\\\\*\\\\*\\\\s*(https?://[^\\\\s*]+)\\\\s*\\\\*\\\\*', 'g'), '$1');

  // Remove ** and __ formatting
  s = s.replace(new RegExp('\\\\*\\\\*', 'g'), '');
  s = s.replace(new RegExp('__', 'g'), '');

  // Single * italics: only when bordered by whitespace / punctuation
  s = s.replace(new RegExp('(^|[\\\\s(])\\\\*([^*\\\\s][^*]*?)\\\\*(?=[\\\\s).,!?;:]|$)', 'g'), '$1$2');

  // Strip leading # headers (line-starting)
  s = s.replace(new RegExp('^#+\\\\s', 'gm'), '');

  // Remove backticks (built via fromCharCode because a literal backtick
  // in this source would terminate the outer template literal)
  s = s.replace(new RegExp(String.fromCharCode(96), 'g'), '');

  // HTML-escape
  var escaped = s
    .replace(new RegExp('&', 'g'), '&amp;')
    .replace(new RegExp('<', 'g'), '&lt;')
    .replace(new RegExp('>', 'g'), '&gt;')
    .replace(new RegExp('"', 'g'), '&quot;');

  // [text](url) -> clickable link
  escaped = escaped.replace(
    new RegExp('\\\\[([^\\\\]]+)\\\\]\\\\((https?://[^\\\\s)]+)\\\\)', 'g'),
    function(_, txt, url) {
      return '<a href="' + url + '" target="_blank" rel="noopener noreferrer">' + txt + '</a>';
    }
  );

  // Bare YouTube URLs -> clickable
  escaped = escaped.replace(
    new RegExp('(^|[^"=>])(https://www\\\\.youtube\\\\.com/watch\\\\?v=[A-Za-z0-9_-]+)', 'g'),
    function(_, prefix, url) {
      return prefix + '<a href="' + url + '" target="_blank" rel="noopener noreferrer">' + url + '</a>';
    }
  );

  // Any other bare http(s) URLs not already wrapped -> clickable
  escaped = escaped.replace(
    new RegExp('(^|[^"=>])(https?://[^\\\\s<]+)', 'g'),
    function(_, prefix, url) {
      // Skip if already inside a link (cheap check: previous chars contain href=")
      return prefix + '<a href="' + url + '" target="_blank" rel="noopener noreferrer">' + url + '</a>';
    }
  );

  return escaped;
}

// v2.9.7: My Team — D1-based per-role directories with per-team colors.
// Builds a stack of collapsible directory cards (one per team the user belongs to,
// or all teams for admins). Reuses the same /api/team-directory endpoint.
// Roles without any user_roles assignments are skipped.
async function loadTeam() {
  const stack = document.getElementById('team-directories-stack');
  if (!stack) return;
  try {
    // Roles to render = ROLE_STYLE keys, but only the ones we have data for.
    // For non-admins, only the roles the user belongs to.
    // ROLE_STYLE is defined globally in this script.
    let candidateRoles = Object.keys(ROLE_STYLE);
    if (!USER_IS_GLOBAL_ADMIN) {
      candidateRoles = candidateRoles.filter(r => USER_ROLES.includes(r));
    }
    if (candidateRoles.length === 0) {
      stack.innerHTML =
        '<div class="start-here">' +
          '<div class="start-here-title">No teams yet</div>' +
          '<div class="start-here-body">Once a team leader adds you, your team directories will appear here.</div>' +
        '</div>';
      return;
    }
    // Fetch each directory in parallel, skip empty teams.
    const results = await Promise.all(candidateRoles.map(async roleId => {
      try {
        const res = await fetch('/api/team-directory?role=' + encodeURIComponent(roleId));
        if (!res.ok) return null;
        const data = await res.json();
        if (!data.members || data.members.length === 0) return null;
        return { roleId, data };
      } catch (e) {
        return null;
      }
    }));
    const nonEmpty = results.filter(r => r !== null);
    if (nonEmpty.length === 0) {
      stack.innerHTML =
        '<div class="start-here">' +
          '<div class="start-here-title">No team rosters loaded yet</div>' +
          '<div class="start-here-body">Team rosters live in D1. Send Shane a CSV from Planning Center for any team you want to see here. Safety, Greeters, and Café are loaded so far.</div>' +
        '</div>';
      return;
    }
    stack.innerHTML = nonEmpty.map(r => directoryCardHTML(r.roleId, r.data)).join('');
  } catch (e) {
    console.error('loadTeam error:', e);
    stack.innerHTML = '<div class="empty">Could not load team directories.</div>';
  }
}

// v2.9.7: Build the HTML for a single directory card.
// Uses per-role color from ROLE_STYLE for the header banner.
function directoryCardHTML(roleId, data) {
  const style = ROLE_STYLE[roleId] || { color: '#6d3d31', icon: '👥', textDark: false };
  const members = data.members || [];
  const roleName = (data.role && data.role.display_name) || roleId;
  const textColor = style.textDark ? '#1a1a1a' : '#ffffff';
  const headerBg = style.color;
  const cardId = 'dir-card-' + roleId;
  const bodyId = 'dir-body-' + roleId;
  const toggleId = 'dir-toggle-' + roleId;
  const pills = members.map(m => {
    const lead = m.is_lead ? '<span class="dir-lead">Lead</span>' : '';
    const ph = m.phone ? '<a class="dir-act call" href="tel:' + esc(m.phone) + '">Call</a>' : '';
    const tx = m.phone ? '<a class="dir-act text" href="sms:' + esc(m.phone) + '">Text</a>' : '';
    const em = m.email ? '<a class="dir-act email" href="mailto:' + esc(m.email) + '">Email</a>' : '';
    const sv = (m.phone || m.email) ? '<button type="button" class="dir-act save" onclick="pcVcard(this)" data-n="' + esc(m.display_name) + '" data-p="' + esc(m.phone || '') + '" data-e="' + esc(m.email || '') + '" data-o="">Save</button>' : '';
    const subC = (m.phone ? '<span class="dir-chip phone">' + esc(m.phone) + '</span>' : '') + (m.email ? '<span class="dir-chip email">' + esc(m.email) + '</span>' : '');
    const sub = subC ? '<div class="dir-chips">' + subC + '</div>' : '';
    const acts = (ph || tx || em || sv) ? '<div class="dir-acts">' + ph + tx + em + sv + '</div>' : '<div class="dir-sub">No phone or email on file</div>';
    return '<div class="dir-row"><div class="dir-who"><span class="dir-name">' + esc(m.display_name) + '</span>' + lead + (sub ? '<div class="dir-sub">' + sub + '</div>' : '') + '</div>' + acts + '</div>';
  }).join('');
  return (
    '<div class="card dir-card" id="' + cardId + '">' +
      '<button type="button" class="dir-toggle" id="' + toggleId + '" ' +
        'style="background:' + headerBg + ';color:' + textColor + '" ' +
        'onclick="toggleDirectory(&apos;' + roleId + '&apos;)" aria-expanded="false">' +
        '<span class="dir-toggle-label">' +
          '<span class="dir-toggle-icon" aria-hidden="true">' + (style.icon || '👥') + '</span>' +
          '<span>' + esc(roleName) + '</span>' +
          '<span class="dir-count">(' + members.length + ')</span>' +
        '</span>' +
        '<span class="dir-toggle-arrow">▸</span>' +
      '</button>' +
      '<div class="dir-body" id="' + bodyId + '" style="display:none">' +
        '<div style="font-size:12.5px;color:var(--muted);margin:0 0 10px">Tap Call, Text, Email or Save on anyone below.</div>' + pills +
        '<button type="button" class="dir-close" onclick="toggleDirectory(&apos;' + roleId + '&apos;)">Close</button>' +
      '</div>' +
    '</div>'
  );
}

// v2.9.7: generic toggle — works for any directory card by roleId
function toggleDirectory(roleId) {
  const body = document.getElementById('dir-body-' + roleId);
  const toggle = document.getElementById('dir-toggle-' + roleId);
  const card = document.getElementById('dir-card-' + roleId);
  if (!body || !toggle) return;
  const isOpen = body.style.display !== 'none';
  body.style.display = isOpen ? 'none' : 'block';
  toggle.setAttribute('aria-expanded', isOpen ? 'false' : 'true');
  if (isOpen && card) {
    card.scrollIntoView({ behavior: 'smooth', block: 'start' });
  }
}

// FLIP CHART — v2.5: section order refined
let CODES_DATA = [];
// v2.5: medical-with-medical, threat-with-threat, evacuation, children grouped
// v2.9.62: reordered emergency-first; florida relabeled "Weather / Facility"
//   (label only, no card re-bucketing); SECTION_ICONS added for calm parent rows.
const SECTION_ORDER = ['codes','threat','medical','evacuation','children','florida','pastoral','emergency','other'];
const SECTION_LABELS = {
  codes: 'Main Emergency Codes',
  threat: 'Active Threat',
  medical: 'Medical',
  evacuation: 'Evacuation',
  children: 'Children',
  florida: 'Weather',
  pastoral: 'Pastoral / Sensitive',
  emergency: 'Other Emergencies',
  other: 'Other'
};
const SECTION_ICONS = {
  codes: '🧭',
  threat: '🛡️',
  medical: '🩺',
  evacuation: '🚪',
  children: '🧒',
  florida: '🌦️',
  pastoral: '🤝',
  emergency: '⚠️',
  other: '📋'
};
const YELLOW_COLORS = new Set(['#e0a800']);
var CAT_DEFS = {};
var CAT_DEFS_LOADED = false;
if (typeof window !== 'undefined' && window.__catFallback == null) window.__catFallback = 0;
var SECTION2CANON = { codes:'codes', threat:'active_threat', medical:'medical', evacuation:'evacuation', children:'child_safety', florida:'weather', pastoral:'pastoral', emergency:'other_emergency', other:'general' };
var ICON_BY_CANON = { codes:'\uD83E\uDDED', active_threat:'\uD83D\uDEE1\uFE0F', medical:'\uD83E\uDE7A', evacuation:'\uD83D\uDEAA', child_safety:'\uD83E\uDDD2', security:'\u26A0\uFE0F', weather:'\uD83C\uDF26\uFE0F', pastoral:'\uD83E\uDD1D', other_emergency:'\u26A0\uFE0F', general:'\uD83D\uDCCB' };
var CANON_LABEL_FALLBACK = { codes:'Main Emergency Codes', active_threat:'Active Threat', medical:'Medical', evacuation:'Evacuation', child_safety:'Children', security:'Security / Behavior', weather:'Weather', pastoral:'Pastoral / Sensitive', other_emergency:'Other Emergencies', general:'Other' };
async function loadCategoryDefs() {
  if (CAT_DEFS_LOADED) return;
  try {
    const r = await fetch('/api/category-defs', { credentials: 'same-origin', cache: 'no-store' });
    if (r.ok) {
      const d = await r.json();
      (d.items || []).forEach(function(x){ CAT_DEFS[x.key] = { label: x.label, order: x.sort_order, emergency: x.is_emergency }; });
      CAT_DEFS_LOADED = true;
    }
  } catch (e) {}
}

async function loadCodes() {
  if (!USER_CAN_SEE_CODES) return;
  try {
    const res = await fetch('/api/codes');
    if (!res.ok) {
      document.getElementById('codes-sections').innerHTML = '<div class="empty">Could not load flip chart.</div>';
      return;
    }
    const data = await res.json();
    CODES_DATA = data.items || [];
    await loadCategoryDefs();
    renderCodes();
  } catch (e) {
    document.getElementById('codes-sections').innerHTML = '<div class="empty">Error loading flip chart.</div>';
  }
}

// v2.9.4: Safety team directory loader — pill grid, collapsible.
// Reuses USER_CAN_SEE_CODES (safety members + admins).
async function loadSafetyDirectory() {
  if (!USER_CAN_SEE_CODES) return;
  const card = document.getElementById('safety-directory-card');
  const body = document.getElementById('safety-directory-body');
  const countEl = document.getElementById('safety-directory-count');
  if (!card || !body) return;
  try {
    const res = await fetch('/api/team-directory?role=safety');
    if (!res.ok) {
      if (res.status === 403) { card.style.display = 'none'; return; }
      body.innerHTML = '<div class="empty">Could not load directory.</div>';
      card.style.display = '';
      return;
    }
    const data = await res.json();
    const members = data.members || [];
    if (countEl) countEl.textContent = '(' + members.length + ')';
    if (members.length === 0) {
      body.innerHTML = '<div class="empty">No directory entries yet.</div>';
      card.style.display = '';
      return;
    }
    const pills = members.map(m => {
      const leadClass = m.is_lead ? ' dir-pill-lead' : '';
      const phoneInner = m.phone
        ? '<div class="dir-pill-phone">' + esc(m.phone) + '</div>'
        : '<div class="dir-pill-nophone">no number</div>';
      if (m.phone) {
        const digits = m.phone.replace(/\D/g, '');
        return (
          '<a class="dir-pill' + leadClass + '" href="tel:+1' + digits + '">' +
            '<div class="dir-pill-name">' + esc(m.display_name) + '</div>' +
            phoneInner +
          '</a>'
        );
      } else {
        return (
          '<div class="dir-pill' + leadClass + '">' +
            '<div class="dir-pill-name">' + esc(m.display_name) + '</div>' +
            phoneInner +
          '</div>'
        );
      }
    }).join('');
    body.innerHTML = '<div style="font-size:12.5px;color:var(--muted);margin:0 0 10px">Tap Call, Text, Email or Save on anyone below.</div>' + pills +
      '<button type="button" class="dir-close" onclick="toggleSafetyDirectory()">Close</button>';
    card.style.display = '';
  } catch (e) {
    body.innerHTML = '<div class="empty">Error loading directory.</div>';
    card.style.display = '';
  }
}

// v2.9.4: toggle the directory grid visibility
function toggleSafetyDirectory() {
  const body = document.getElementById('safety-directory-body');
  const toggle = document.getElementById('safety-directory-toggle');
  const card = document.getElementById('safety-directory-card');
  if (!body || !toggle) return;
  const isOpen = body.style.display !== 'none';
  body.style.display = isOpen ? 'none' : 'block';
  toggle.setAttribute('aria-expanded', isOpen ? 'false' : 'true');
  // v2.9.6: when closing, scroll header back into view so user knows where they are
  if (isOpen && card) {
    card.scrollIntoView({ behavior: 'smooth', block: 'start' });
  }
}

// v2.9.31: accordion toggle for Reference category rows. Opening one category
// closes the others so the list never grows past one open group.
function toggleRefSection(secId) {
  const target = document.getElementById(secId);
  const header = document.querySelector('.ref-parent[data-refsec="' + secId + '"]');
  if (!target || !header) return;
  const opening = target.style.display === 'none';
  // Close every section first (accordion).
  document.querySelectorAll('.ref-children').forEach(function(c) { c.style.display = 'none'; });
  document.querySelectorAll('.ref-parent').forEach(function(h) { h.classList.remove('open'); });
  if (opening) {
    target.style.display = 'flex';
    header.classList.add('open');
    header.scrollIntoView({ behavior: 'smooth', block: 'start' });
  }
}

function toggleRefCard(el) {
  const body = el.querySelector('.home-ref-body');
  if (!body) return;
  const opening = body.style.display === 'none';
  body.style.display = opening ? '' : 'none';
  el.classList.toggle('open', opening);
}

function renderCodes() {
  const container = document.getElementById('codes-sections');
  if (CODES_DATA.length === 0) {
    container.innerHTML = '<div class="empty">No flip chart cards available.</div>';
    return;
  }
  const bySection = {};
  CODES_DATA.forEach(c => {
    var key = c.category_key || SECTION2CANON[c.section] || 'other_emergency';
    if (!c.category_key && CAT_DEFS_LOADED) { if (window.__catFallback != null) window.__catFallback++; }
    if (!bySection[key]) bySection[key] = [];
    bySection[key].push(c);
  });
  var _fcOrder = Object.keys(bySection).sort(function(a,b){
    var oa = (CAT_DEFS[a] && CAT_DEFS[a].order) || 900;
    var ob = (CAT_DEFS[b] && CAT_DEFS[b].order) || 900;
    return oa - ob;
  });
  const html = _fcOrder.map(sec => {
    const cards = bySection[sec];
    if (!cards || cards.length === 0) return '';
    const cardHtml = cards.map(c => {
      const isYellow = YELLOW_COLORS.has(c.color);
      const textClass = isYellow ? ' text-dark' : '';
      // v2.8.7: split title into top label and bottom description.
      // If title starts with "Code <Color>", that becomes the top line and
      // the rest becomes the description. Otherwise the full title goes on
      // top and the bottom stays empty.
      let topLabel = c.title || '';
      let bottomDesc = '';
      const m = (c.title || '').match(/^(Code\s+\w+(?:\s*\([^)]+\))?)\s+(.+)$/i);
      if (m) {
        topLabel = m[1].toUpperCase();
        bottomDesc = m[2];
      } else {
        topLabel = (c.title || '').toUpperCase();
      }
      const bottomHtml = bottomDesc
        ? '<div class="code-card-name">' + esc(bottomDesc) + '</div>'
        : '';
      return '<div class="code-card' + textClass + '" data-code-id="' + esc(c.id) + '" style="background:' + esc(c.color) + '">' +
        '<div class="code-card-top">' + esc(topLabel) + '</div>' +
        '<div class="code-card-icon">' + (c.icon || '⚪') + '</div>' +
        bottomHtml +
        '</div>';
    }).join('');
    // v2.9.62: calm neutral collapsible parent header + collapsed children grid.
    const secId = 'codesec-' + sec;
    const icon = ICON_BY_CANON[sec] || SECTION_ICONS[sec] || '📋';
    const label = (CAT_DEFS[sec] && CAT_DEFS[sec].label) || CANON_LABEL_FALLBACK[sec] || SECTION_LABELS[sec] || sec;
    return '<div class="codes-section">' +
      '<div class="codes-parent" data-codesec="' + secId + '" onclick="toggleCodeSection(&apos;' + secId + '&apos;)">' +
        '<span class="home-section-icon">' + icon + '</span>' +
        '<span class="ref-parent-label">' + esc(label) + '</span>' +
        '<span class="ref-parent-count">' + cards.length + '</span>' +
        '<span class="ref-parent-carat">&#9654;</span>' +
      '</div>' +
      '<div class="codes-children" id="' + secId + '" style="display:none">' +
        '<div class="codes-grid">' + cardHtml + '</div>' +
      '</div></div>';
  }).join('');
  container.innerHTML = html;
  container.addEventListener('click', function(e) {
    const card = e.target.closest('.code-card');
    if (card && card.dataset.codeId) showCode(card.dataset.codeId);
  });
}

// v2.9.62: accordion toggle for Codes parent rows. Mirrors toggleRefSection but
// scoped to .codes-parent / .codes-children so toggling here never touches the
// Reference tab's accordion. Opening one group closes the others.
function toggleCodeSection(secId) {
  const target = document.getElementById(secId);
  const header = document.querySelector('.codes-parent[data-codesec="' + secId + '"]');
  if (!target || !header) return;
  const opening = target.style.display === 'none';
  document.querySelectorAll('.codes-children').forEach(function(c) { c.style.display = 'none'; });
  document.querySelectorAll('.codes-parent').forEach(function(h) { h.classList.remove('open'); });
  if (opening) {
    target.style.display = 'block';
    header.classList.add('open');
    header.scrollIntoView({ behavior: 'smooth', block: 'start' });
  }
}

function showCode(id) {
  const code = CODES_DATA.find(c => c.id === id);
  if (!code) return;
  const el = document.getElementById('code-detail');
  if (id === 'fc_00_walkie_codes') {
    el.innerHTML =
      '<div class="code-detail-head" onclick="toggleCodeBody(this)">' +
        '<span class="code-swatch" style="background:' + esc(code.color) + '"></span>' +
        '<h3>' + esc(code.title) + '</h3>' +
        '<span class="code-detail-chevron">&#9654;</span>' +
      '</div>' +
      '<div class="code-detail-body" style="text-align:center">' +
        '<img src="/safety/walkie-card.jpg" alt="Walkie-Talkie Calls and Codes" style="width:100%;max-width:680px;border-radius:12px;box-shadow:0 2px 12px rgba(0,0,0,.18);cursor:zoom-in" onclick="window.open(this.src,&apos;_blank&apos;)">' +
        '<div style="font-size:12px;color:#6b7280;margin-top:8px">Tap the image to open it full screen.</div>' +
      '</div>' +
      '<button class="code-detail-close" onclick="closeCode()">Close</button>';
    el.classList.add('open');
    document.getElementById('codes-detail-anchor').scrollIntoView({ behavior: 'smooth', block: 'start' });
    return;
  }
  el.innerHTML =
    '<div class="code-detail-head" onclick="toggleCodeBody(this)">' +
      '<span class="code-swatch" style="background:' + esc(code.color) + '"></span>' +
      '<h3>' + esc(code.title) + '</h3>' +
      '<span class="code-detail-chevron">&#9654;</span>' +
    '</div>' +
    '<div class="code-detail-body">' + pillifyContacts(linkifyContent(injectContactBlocks(code.body, code.contact_block_key))) + '</div>' +
    '<a href="/capture/incident" style="display:block;text-align:center;margin:16px 0 8px;text-decoration:none">' +
      '<span style="display:inline-block;background:#c0392b;color:#fff;padding:10px 28px;border-radius:24px;font-weight:700;font-size:15px">🚨 File Incident Report</span>' +
    '</a>' +
    '<button class="code-detail-close" onclick="closeCode()">Close</button>';
  el.classList.add('open');
  document.getElementById('codes-detail-anchor').scrollIntoView({ behavior: 'smooth', block: 'start' });
}
// v2.9.21: tap the code header to collapse the open code instantly (escape
// hatch for a wrong tap) — no scrolling to the bottom Close button.
function toggleCodeBody(headEl) {
  const wrap = headEl.parentElement;
  const body = wrap.querySelector('.code-detail-body');
  const closeBtn = wrap.querySelector('.code-detail-close');
  if (!body) return;
  const collapsing = !wrap.classList.contains('code-collapsed');
  wrap.classList.toggle('code-collapsed', collapsing);
  body.style.display = collapsing ? 'none' : '';
  if (closeBtn) closeBtn.style.display = collapsing ? 'none' : '';
}
function closeCode() { document.getElementById('code-detail').classList.remove('open'); }

async function submitAddPerson() {
  var name = document.getElementById('ap-name').value.trim();
  var email = document.getElementById('ap-email').value.trim();
  var phone = document.getElementById('ap-phone').value.trim();
  var globalAdmin = document.getElementById('ap-global').checked;
  var roles = [];
  document.querySelectorAll('#ap-roles input[type=checkbox]:checked').forEach(function(c) { roles.push(c.value); });
  var resultEl = document.getElementById('ap-result');
  if (!name) { alert('Please enter a name.'); return; }
  if (!email && !phone) { alert('Please enter a phone number or email.'); return; }
  var btn = document.getElementById('ap-submit');
  btn.disabled = true; btn.textContent = 'Adding…';
  try {
    var res = await fetch('/api/admin/users', {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify({ name: name, email: email, phone: phone, roles: roles, is_global_admin: globalAdmin })
    });
    var data = await res.json();
    if (!res.ok || !data.ok) {
      resultEl.style.display = 'block';
      if (data.error === 'already_exists') {
        resultEl.innerHTML = '<div class="ap-err">That email is already in the system — no need to re-add. Use their existing link or a different email.</div>';
      } else {
        resultEl.innerHTML = '<div class="ap-err">Could not add: ' + esc(data.error || 'error') + '</div>';
      }
      return;
    }
    var first = name.split(' ')[0] || name;
    var sms = first + " — it's Pastor Shane. Tap this to sign in to TabReady. No password:\\n" +
              data.login_url + "\\nThat's it — you're in.";
    resultEl.style.display = 'block';
    resultEl.innerHTML =
      '<div class="ap-ok"><strong>' + esc(name) + '</strong> added. Their one-tap link is good for 7 days:</div>' +
      '<textarea id="ap-sms" class="ap-sms" readonly></textarea>' +
      '<button class="btn" onclick="copyAddPerson()">Copy text to send</button>' +
      '<button class="btn" style="margin-top:8px;background:#0f766e" onclick="toggleApQr()">Show QR code (scan in person)</button>' +
      '<div id="ap-qr" style="display:none;margin-top:12px;text-align:center"><div id="ap-qr-img" style="display:inline-block;background:#fff;padding:12px;border-radius:12px"></div><div style="font-size:13px;color:var(--muted);margin-top:8px">Have them scan this with their phone camera.</div></div>';
    document.getElementById('ap-sms').value = sms;
    renderQrInto('ap-qr-img', data.qr_svg);
    document.getElementById('ap-name').value = '';
    document.getElementById('ap-email').value = '';
    document.getElementById('ap-phone').value = '';
    document.getElementById('ap-global').checked = false;
    document.querySelectorAll('#ap-roles input[type=checkbox]:checked').forEach(function(c) { c.checked = false; });
  } catch (e) {
    resultEl.style.display = 'block';
    resultEl.innerHTML = '<div class="ap-err">Network error — please try again.</div>';
  } finally {
    btn.disabled = false; btn.textContent = 'Add & generate link';
  }
}
function renderQrInto(boxId, svg) {
  var box = document.getElementById(boxId);
  if (!box) return;
  box.innerHTML = svg || '';
  var s = box.querySelector('svg');
  if (s) { s.removeAttribute('width'); s.removeAttribute('height'); s.style.width = '100%'; s.style.maxWidth = '260px'; s.style.height = 'auto'; }
}
function toggleRlQr() { var d = document.getElementById('rl-qr'); if (d) d.style.display = (d.style.display === 'none' ? 'block' : 'none'); }
function toggleApQr() { var d = document.getElementById('ap-qr'); if (d) d.style.display = (d.style.display === 'none' ? 'block' : 'none'); }
async function submitRelink() {
  var email = (document.getElementById('rl-email').value || '').trim();
  var resultEl = document.getElementById('rl-result');
  if (!email) { alert('Please enter their email.'); return; }
  var btn = document.getElementById('rl-submit');
  btn.disabled = true; btn.textContent = 'Generating…';
  try {
    var res = await fetch('/api/admin/users/relink', {
      method: 'POST', headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify({ email: email })
    });
    var data = await res.json();
    resultEl.style.display = 'block';
    if (!res.ok || !data.ok) {
      if (data.error === 'not_found') {
        resultEl.innerHTML = '<div class="ap-err">No one with that email is in the system. Check the address, or use Add Person above.</div>';
      } else {
        resultEl.innerHTML = '<div class="ap-err">Could not generate: ' + esc(data.error || 'error') + '</div>';
      }
      return;
    }
    resultEl.innerHTML =
      '<div class="ap-ok"><strong>' + esc(data.name || email) + '</strong> — fresh link ready, good for 1 hour. Any older link is now cancelled.</div>' +
      '<textarea id="rl-link" class="ap-sms" readonly></textarea>' +
      '<button class="btn" onclick="copyRelink()">Copy link to text</button>' +
      '<button class="btn" style="margin-top:8px;background:#0f766e" onclick="toggleRlQr()">Show QR code (scan in person)</button>' +
      '<div id="rl-qr" style="display:none;margin-top:12px;text-align:center"><div id="rl-qr-img" style="display:inline-block;background:#fff;padding:12px;border-radius:12px"></div><div style="font-size:13px;color:var(--muted);margin-top:8px">Have them scan this with their phone camera.</div></div>';
    document.getElementById('rl-link').value = data.login_url;
    renderQrInto('rl-qr-img', data.qr_svg);
    document.getElementById('rl-email').value = '';
  } catch (e) {
    resultEl.style.display = 'block';
    resultEl.innerHTML = '<div class="ap-err">Network error — please try again.</div>';
  } finally {
    btn.disabled = false; btn.textContent = 'Generate login link';
  }
}
function copyRelink() {
  var t = document.getElementById('rl-link');
  if (!t) return;
  t.select();
  try { document.execCommand('copy'); } catch (e) {}
  if (navigator.clipboard) { navigator.clipboard.writeText(t.value).catch(function() {}); }
  var b = event && event.target; if (b) { b.textContent = 'Copied ✓'; setTimeout(function(){ b.textContent = 'Copy link to text'; }, 1500); }
}
function copyAddPerson() {
  var t = document.getElementById('ap-sms');
  if (!t) return;
  t.select();
  try { document.execCommand('copy'); } catch (e) {}
  if (navigator.clipboard) { navigator.clipboard.writeText(t.value).catch(function() {}); }
  var b = event && event.target; if (b) { b.textContent = 'Copied ✓'; setTimeout(function(){ b.textContent = 'Copy text to send'; }, 1500); }
}

