// ═══ v2.9.37: SCHEDULE (Stage 2 — read-only) ═══
var SCHED_MONTH = null;            // 'YYYY-MM' currently shown
var SCHED_DATA = null;             // last fetched payload
var SCHED_SELECTED = null;         // 'YYYY-MM-DD' selected day
var SCHED_DID_DEFAULT = false;     // have we jumped to next service day yet?

function schedTodayMonth() {
  var n = new Date();
  return n.getFullYear() + '-' + String(n.getMonth() + 1).padStart(2, '0');
}
function schedTodayStr() {
  var n = new Date();
  return n.getFullYear() + '-' + String(n.getMonth() + 1).padStart(2, '0') + '-' + String(n.getDate()).padStart(2, '0');
}
function schedMonthName(m) {
  var parts = m.split('-');
  var d = new Date(Number(parts[0]), Number(parts[1]) - 1, 1);
  return d.toLocaleDateString(undefined, { month: 'long', year: 'numeric' });
}
function schedShiftMonth(delta) {
  if (!SCHED_MONTH) SCHED_MONTH = schedTodayMonth();
  var parts = SCHED_MONTH.split('-');
  var y = Number(parts[0]); var mo = Number(parts[1]) - 1;
  var d = new Date(y, mo + delta, 1);
  SCHED_MONTH = d.getFullYear() + '-' + String(d.getMonth() + 1).padStart(2, '0');
  loadSchedule();
}


// ── v2.9.53: Schedule editor (team leaders + admins) ─────────────────────
function schedInitEditor() {
  var btn = document.getElementById('sched-add-btn');
  if (!btn) return;
  if (typeof USER_IS_TEAM_LEADER !== 'undefined' && USER_IS_TEAM_LEADER) {
    btn.style.display = '';
  }
  // Populate role dropdown with user's teams (or all teams for admin)
  var sel = document.getElementById('sched-add-role');
  if (!sel) return;
  var roles = (typeof USER_IS_GLOBAL_ADMIN !== 'undefined' && USER_IS_GLOBAL_ADMIN)
    ? (typeof ALL_ROLES !== 'undefined' ? ALL_ROLES : [])
    : (typeof ALL_ROLES !== 'undefined' ? ALL_ROLES.filter(function(r) {
        return (typeof MY_TEAM_ROLES !== 'undefined') && MY_TEAM_ROLES.includes(r.id);
      }) : []);
  roles.forEach(function(r) {
    var opt = document.createElement('option');
    opt.value = r.id;
    opt.textContent = r.display_name || r.id;
    sel.appendChild(opt);
  });
}

function schedShowAddPanel() {
  var p = document.getElementById('sched-add-panel');
  if (p) p.style.display = '';
  // Pre-fill date with selected day if any
  if (typeof SCHED_SELECTED !== 'undefined' && SCHED_SELECTED) {
    var d = document.getElementById('sched-add-date');
    if (d) d.value = SCHED_SELECTED;
  }
}
function schedHideAddPanel() {
  var p = document.getElementById('sched-add-panel');
  if (p) p.style.display = 'none';
  // v2.9.255: cancelling must abandon any pending swap, or the next plain Add
  // would silently delete the person we were swapping out.
  SCHED_SWAP_OUT = null;
  var m = document.getElementById('sched-add-msg');
  if (m) m.textContent = '';
}

function schedSubmitAdd() {
  var date = (document.getElementById('sched-add-date') || {}).value || '';
  var role = (document.getElementById('sched-add-role') || {}).value || '';
  var name = ((document.getElementById('sched-add-name') || {}).value || '').trim();
  var time = ((document.getElementById('sched-add-time') || {}).value || '').trim();
  var pos  = ((document.getElementById('sched-add-position') || {}).value || '').trim();
  var msg  = document.getElementById('sched-add-msg');
  if (!date || !role || !name) { if (msg) msg.textContent = 'Date, team, and name are required.'; return; }
  var addUid = (document.getElementById('sched-add-userid') || {}).value || null;
  var addBo = schedBlackoutFor(name, addUid, date);
  if (addBo) {
    if (!confirm(name + ' is marked unavailable on ' + date + (addBo.note ? ' (' + addBo.note + ')' : '') + '. Schedule anyway?')) {
      if (msg) msg.textContent = 'Not scheduled — ' + name + ' is unavailable that day.';
      return;
    }
  }
  if (msg) msg.textContent = 'Saving…';
  fetch('/api/schedule', {
    method: 'POST', credentials: 'same-origin',
    headers: { 'Content-Type': 'application/json' },
    body: JSON.stringify({ event_date: date, role: role, display_name: name, time_block: time || null, position: pos || null, user_id: (document.getElementById('sched-add-userid') || {}).value || null })
  }).then(function(r) { return r.json(); }).then(function(d) {
    if (d.ok) {
      if (msg) msg.textContent = 'Saved!';
      document.getElementById('sched-add-name').value = '';
      document.getElementById('sched-add-time').value = '';
      document.getElementById('sched-add-position').value = '';
      // v2.9.255: if this Save completes a Swap, retire the outgoing person only
      // NOW that the replacement is confirmed in. Add-then-remove, never the
      // reverse: a failed add must never leave the day short-staffed.
      if (SCHED_SWAP_OUT && SCHED_SWAP_OUT.id) {
        var outId = SCHED_SWAP_OUT.id;
        var outName = SCHED_SWAP_OUT.name;
        SCHED_SWAP_OUT = null;
        fetch('/api/schedule/' + encodeURIComponent(outId) + '/delete', { method: 'POST', credentials: 'same-origin' })
          .then(function(r2) { return r2.json(); })
          .then(function(d2) {
            if (msg) msg.textContent = (d2 && d2.ok)
              ? ('Swapped — ' + outName + ' removed, ' + name + ' added.')
              : (name + ' was added, but ' + outName + ' could not be removed. Remove them manually.');
            loadSchedule();
            setTimeout(function() { if (msg) msg.textContent = ''; }, 5000);
          })
          .catch(function() {
            if (msg) msg.textContent = name + ' was added, but ' + outName + ' could not be removed. Remove them manually.';
            loadSchedule();
          });
      } else {
        loadSchedule();
        setTimeout(function() { if (msg) msg.textContent = ''; }, 2000);
      }
    } else {
      if (msg) msg.textContent = d.error || 'Error saving.';
    }
  }).catch(function() { if (msg) msg.textContent = 'Network error.'; });
}

function calEsc(s) { return String(s == null ? '' : s).split('&').join('&amp;').split('<').join('&lt;').split('>').join('&gt;'); }
function attrEsc(s) { return calEsc(s).split('"').join('&quot;'); }
function pcVcard(btn) {
  var n = btn.getAttribute('data-n') || '', p = btn.getAttribute('data-p') || '', e = btn.getAttribute('data-e') || '', o = btn.getAttribute('data-o') || '';
  if (!n.trim()) return;
  var NL = String.fromCharCode(10);
  var v = 'BEGIN:VCARD' + NL + 'VERSION:3.0' + NL + 'FN:' + n + NL + 'N:' + n + ';;;;' + NL;
  if (o) v += 'ORG:' + o + NL;
  if (p) v += 'TEL;TYPE=CELL:' + p + NL;
  if (e) v += 'EMAIL;TYPE=INTERNET:' + e + NL;
  v += 'END:VCARD' + NL;
  try {
    var blob = new Blob([v], { type: 'text/vcard;charset=utf-8' });
    var url = URL.createObjectURL(blob);
    var a = document.createElement('a');
    a.href = url; a.download = (n.replace(new RegExp('[^a-z0-9]', 'gi'), '_') || 'contact') + '.vcf';
    document.body.appendChild(a); a.click(); document.body.removeChild(a);
    setTimeout(function() { URL.revokeObjectURL(url); }, 1500);
    btn.textContent = 'Saved!';
    setTimeout(function() { btn.textContent = 'Save to phone'; }, 3000);
  } catch (err) { btn.textContent = 'Save failed'; }
}
function loadCalendar() {
  var box = document.getElementById('cal-list');
  if (!box) return;
  box.innerHTML = '<div class="empty">Loading…</div>';
  fetch('/api/pco-events', { credentials: 'same-origin' })
    .then(function(r) { return r.json(); })
    .then(function(d) {
      var events = d.events || [];
      if (!events.length) {
        box.innerHTML = '<div class="empty">No upcoming events found.' + (d.note ? ' (' + calEsc(d.note) + ')' : '') + '</div>';
        return;
      }
      box.innerHTML = events.map(function(e) {
        var dt = e.starts_at ? new Date(e.starts_at) : null;
        var day = dt ? dt.toLocaleDateString(undefined, { weekday:'short', month:'short', day:'numeric' }) : '';
        var tm = dt ? dt.toLocaleTimeString(undefined, { hour:'numeric', minute:'2-digit' }) : '';
        return '<div class="cal-ev">' +
          '<div class="cal-ev-date"><div class="cal-ev-day">' + calEsc(day) + '</div><div class="cal-ev-time">' + calEsc(tm) + '</div></div>' +
          '<div class="cal-ev-name">' + calEsc(e.name || 'Event') + '</div>' +
        '</div>';
      }).join('');
    })
    .catch(function() { box.innerHTML = '<div class="empty">Could not load the calendar.</div>'; });
}
function dirToggle(btn) {
  var open = btn.getAttribute('aria-expanded') === 'true';
  btn.setAttribute('aria-expanded', open ? 'false' : 'true');
  var m = btn.nextElementSibling;
  if (m) m.style.display = open ? 'none' : '';
  var ch = btn.querySelector('.dir-chev');
  if (ch) ch.textContent = open ? '▾' : '▴';
}
var PCO_SEARCH_TIMER = null;
function pcoSearch() {
  var inp = document.getElementById('pco-q');
  var box = document.getElementById('pco-results');
  if (!inp || !box) return;
  var q = (inp.value || '').trim();
  if (PCO_SEARCH_TIMER) clearTimeout(PCO_SEARCH_TIMER);
  if (q.length < 2) { box.innerHTML = ''; return; }
  box.innerHTML = '<div class="empty">Searching…</div>';
  PCO_SEARCH_TIMER = setTimeout(function() {
    fetch('/api/pco-people?q=' + encodeURIComponent(q), { credentials: 'same-origin' })
      .then(function(r) { return r.json(); })
      .then(function(d) {
        if (d && d.error) { box.innerHTML = '<div class="empty">Not available for your role.</div>'; return; }
        var people = (d && d.people) || [];
        if (!people.length) { box.innerHTML = '<div class="empty">No matches.</div>'; return; }
        box.innerHTML = people.map(function(m) {
          var ph = m.phone ? '<a class="dir-act call" href="tel:' + calEsc(m.phone) + '">Call</a>' : '';
          var tx = m.phone ? '<a class="dir-act text" href="sms:' + calEsc(m.phone) + '">Text</a>' : '';
          var em = m.email ? '<a class="dir-act email" href="mailto:' + calEsc(m.email) + '">Email</a>' : '';
          var subC = (m.phone ? '<span class="dir-chip phone">' + calEsc(m.phone) + '</span>' : '') + (m.email ? '<span class="dir-chip email">' + calEsc(m.email) + '</span>' : '');
          var sub = (subC ? '<div class="dir-chips">' + subC + '</div>' : '') + (m.org ? '<div class="dir-line">' + calEsc(m.org) + '</div>' : '');
          var badges = (m.sources || []).map(function(s) { return '<span class="src-badge src-' + calEsc(String(s).toLowerCase()) + '">' + calEsc(s) + '</span>'; }).join('');
          var canSave = !!(m.phone || m.email);
          var sv = canSave ? '<button type="button" class="dir-act save pc-save" onclick="pcVcard(this)" data-n="' + attrEsc(m.name) + '" data-p="' + attrEsc(m.phone) + '" data-e="' + attrEsc(m.email) + '" data-o="' + attrEsc(m.org) + '">Save</button>' : '';
          return '<div class="dir-row"><div class="dir-who"><span class="dir-name">' + calEsc(m.name) + '</span>' + badges + '<div class="dir-sub">' + sub + '</div></div><div class="dir-acts">' + ph + tx + em + sv + '</div></div>';
        }).join('');
      })
      .catch(function() { box.innerHTML = '<div class="empty">Could not search Planning Center.</div>'; });
  }, 350);
}

