async function apiDatesRefresh(request, env) {
  const user = await getUserFromRequest(request, env);
  if (!user) return json({ ok: false, error: 'not_authenticated' }, 401);
  if (!datesAdminGate(user)) return json({ ok: false, error: 'forbidden' }, 403);
  // v2.9.267: warm group membership too, not just dates. Membership was the
  // uncached half that blew the rate limit on every Upcoming Dates page load.
  let ginfo = { groups: 0, groups_read: 0, members: 0 };
  try { ginfo = await refreshAllGroupsCache(env, {}); } catch (e) {}
  const info = await refreshAllDatesCache(env, { maxPages: 40 });
  let cached = 0;
  try { const row = await env.DB.prepare("SELECT COUNT(*) AS c FROM pco_dates_cache WHERE bmonth IS NOT NULL OR amonth IS NOT NULL").first(); cached = row ? row.c : 0; } catch (e) {}
  return json({ ok: true, groups_cached: ginfo.groups_read, group_memberships_cached: ginfo.members, pages_read: info.pages, people_scanned: info.people_total, people_with_dates_cached: cached, more_pages: info.more, note: info.more ? 'Warmed a batch \u2014 tap again to page the rest.' : 'All Planning Center people scanned and cached.' });
}


// -- v2.9.240: HEADCOUNT - AGE-ORDERED STOPS (rebuild of v2.9.211) -----------
//   Phone-first headcount for the office. Stops run birth -> oldest:
//   Preschool (nursery), Children, Youth, Worship (sanctuary + foyer).
//   Workers are counted WHERE THEY SERVE, not in a floating volunteers bucket.
//   Saving IS delivery: the row lands in D1 and, if an office recipient is set,
//   the office is emailed automatically. No second button to forget.
//   Stored tall (one row per stop) so new stops need no migration.
//   Gated to safety, staff, elders and the full-visibility (top) tier.

const ATT_STOPS = [
  { key: 'preschool', name: 'Preschool', sub: 'Birth \u2013 Kindergarten \u00b7 nursery', people: 'Preschoolers', vol: 'Volunteers', workers: true },
  { key: 'children', name: 'Children', sub: '1st \u2013 6th grade', people: 'Children', vol: 'Volunteers', workers: true },
  { key: 'youth', name: 'Youth', sub: 'Middle & high school', people: 'Students', vol: 'Volunteers', workers: true },
  { key: 'worship', name: 'Worship', sub: 'Sanctuary + foyer', people: 'Guests', vol: '', workers: false }
];

function attStopByKey(k) {
  for (let i = 0; i < ATT_STOPS.length; i++) { if (ATT_STOPS[i].key === k) return ATT_STOPS[i]; }
  return null;
}

function canSeeAttendance(user) {
  if (!user) return false;
  if (hasFullVisibility(user)) return true; // editor/admin + staff + elders + full_visibility
  if (!Array.isArray(user.roles)) return false;
  return user.roles.includes('safety');
}

async function ensureAttendanceTable(env) {
  // Legacy table kept intact (0 rows in prod, but never silently dropped).
  try {
    await env.DB.prepare(
      "CREATE TABLE IF NOT EXISTS attendance_counts (id INTEGER PRIMARY KEY AUTOINCREMENT, service_date TEXT NOT NULL, service_label TEXT NOT NULL, adults INTEGER NOT NULL DEFAULT 0, children INTEGER NOT NULL DEFAULT 0, youth INTEGER NOT NULL DEFAULT 0, volunteers INTEGER NOT NULL DEFAULT 0, total INTEGER NOT NULL DEFAULT 0, note TEXT, created_by_id TEXT, created_by_name TEXT, created_at TEXT NOT NULL DEFAULT (datetime('now')))"
    ).run();
  } catch (e) {}
  try {
    await env.DB.prepare(
      "CREATE TABLE IF NOT EXISTS attendance_entries (id INTEGER PRIMARY KEY AUTOINCREMENT, service_date TEXT NOT NULL, service_label TEXT NOT NULL, stop_key TEXT NOT NULL, attendance INTEGER NOT NULL DEFAULT 0, workers INTEGER NOT NULL DEFAULT 0, note TEXT, created_by_id TEXT, created_by_name TEXT, created_at TEXT NOT NULL DEFAULT (datetime('now')))"
    ).run();
  } catch (e) {}
  try {
    await env.DB.prepare(
      "CREATE INDEX IF NOT EXISTS idx_att_entries_svc ON attendance_entries (service_date, service_label)"
    ).run();
  } catch (e) {}
}

function attNonNegInt(v) {
  const n = parseInt(v, 10);
  if (!isFinite(n) || n < 0) return 0;
  if (n > 100000) return 100000;
  return n;
}

function attIsIsoDate(s) {
  return /^\d{4}-\d{2}-\d{2}$/.test(String(s == null ? '' : s));
}

// Group tall rows into one object per service (date + label).
function attGroupServices(rows) {
  const order = [];
  const map = {};
  for (const r of (rows || [])) {
    const k = r.service_date + '||' + r.service_label;
    if (!map[k]) {
      map[k] = {
        service_date: r.service_date,
        service_label: r.service_label,
        created_by_name: r.created_by_name || '',
        created_at: r.created_at || '',
        total: 0,
        stops: {}
      };
      order.push(k);
    }
    const g = map[k];
    g.stops[r.stop_key] = { attendance: r.attendance, workers: r.workers };
    g.total += (r.attendance || 0) + (r.workers || 0);
    if (!g.created_by_name && r.created_by_name) g.created_by_name = r.created_by_name;
  }
  return order.map(function (k) { return map[k]; });
}

function attServiceLines(svc) {
  const out = [];
  for (let i = 0; i < ATT_STOPS.length; i++) {
    const s = ATT_STOPS[i];
    const v = svc.stops[s.key];
    if (!v) continue;
    let t = s.name + ' ' + v.attendance;
    if (s.workers) t += ' (+' + v.workers + ' serving)';
    out.push(t);
  }
  return out;
}

async function apiAttendanceCreate(request, env) {
  const user = await getUserFromRequest(request, env);
  if (!user) return json({ ok: false, error: 'not_authenticated' }, 401);
  if (!canSeeAttendance(user)) return json({ ok: false, error: 'forbidden' }, 403);
  await ensureAttendanceTable(env);

  let b = {};
  try { b = await request.json(); } catch (e) { return json({ ok: false, error: 'bad_json' }, 400); }

  const label = (b.service_label == null ? '' : String(b.service_label)).trim().slice(0, 80);
  if (!label) return json({ ok: false, error: 'Pick or name a service first.' }, 400);
  let date = (b.service_date == null ? '' : String(b.service_date)).trim().slice(0, 10);
  if (!attIsIsoDate(date)) date = new Date().toISOString().slice(0, 10);
  const note = (b.note == null ? '' : String(b.note)).trim().slice(0, 300);

  const stopsIn = (b.stops && typeof b.stops === 'object') ? b.stops : {};
  const picked = [];
  let total = 0;
  for (let i = 0; i < ATT_STOPS.length; i++) {
    const s = ATT_STOPS[i];
    const raw = stopsIn[s.key];
    if (!raw || typeof raw !== 'object') continue;
    const a = attNonNegInt(raw.attendance);
    const w = s.workers ? attNonNegInt(raw.workers) : 0;
    picked.push({ key: s.key, attendance: a, workers: w });
    total += a + w;
  }
  if (!picked.length) return json({ ok: false, error: 'Enter at least one count.' }, 400);

  // Per-stop replace: re-saving a stop overwrites only that stop, so two people
  // counting different rooms for the same service never wipe each other out.
  try {
    for (const p of picked) {
      await env.DB.prepare(
        "DELETE FROM attendance_entries WHERE service_date = ? AND service_label = ? AND stop_key = ?"
      ).bind(date, label, p.key).run();
      await env.DB.prepare(
        "INSERT INTO attendance_entries (service_date, service_label, stop_key, attendance, workers, note, created_by_id, created_by_name) VALUES (?,?,?,?,?,?,?,?)"
      ).bind(date, label, p.key, p.attendance, p.workers, note, user.id || '', user.display_name || '').run();
    }
  } catch (e) {
    return json({ ok: false, error: 'save_failed' }, 500);
  }

  // Saving IS delivery. Pull the whole service back and email the office.
  let svc = null;
  try {
    const q = await env.DB.prepare(
      "SELECT service_date, service_label, stop_key, attendance, workers, created_by_name, created_at FROM attendance_entries WHERE service_date = ? AND service_label = ? ORDER BY id ASC"
    ).bind(date, label).all();
    const grouped = attGroupServices(q.results || []);
    svc = grouped.length ? grouped[0] : null;
  } catch (e) { svc = null; }

  let emailed = '';
  try {
    const to = await datesGetSetting(env, 'attendance_report_to', '');
    const recips = attParseRecipients(to);
    if (recips.length && svc) {
      const ok = await resendEmail(
        env,
        recips,
        'Headcount \u2014 ' + svc.service_label + ' (' + svc.service_date + ') \u2014 total ' + svc.total,
        attServiceEmailHtml(svc, user),
        { reply_to: user.email || undefined }
      );
      if (ok) emailed = recips.join(', ');
    }
  } catch (e) { emailed = ''; }

  return json({
    ok: true,
    service_date: date,
    service_label: label,
    total: svc ? svc.total : total,
    stops: svc ? svc.stops : {},
    emailed_to: emailed
  });
}

function attServiceEmailHtml(svc, user) {
  let tr = '';
  for (let i = 0; i < ATT_STOPS.length; i++) {
    const s = ATT_STOPS[i];
    const v = svc.stops[s.key];
    if (!v) continue;
    tr += '<tr>'
      + '<td style="padding:8px;border-bottom:1px solid #eee;"><b>' + escapeHtml(s.name) + '</b><br><span style="color:#8a7a6a;font-size:12px;">' + escapeHtml(s.sub) + '</span></td>'
      + '<td style="padding:8px;border-bottom:1px solid #eee;text-align:center;font-weight:700;">' + v.attendance + '</td>'
      + '<td style="padding:8px;border-bottom:1px solid #eee;text-align:center;">' + (s.workers ? String(v.workers) : '\u2014') + '</td>'
      + '</tr>';
  }
  return '<div style="font-family:-apple-system,Segoe UI,Roboto,sans-serif;color:#1a1a1a;max-width:560px;margin:0 auto;">'
    + '<h2 style="color:#402020;margin:0 0 4px;">Headcount \u2014 ' + escapeHtml(svc.service_label) + '</h2>'
    + '<p style="color:#6b7280;margin:0 0 16px;font-size:13px;">The Tabernacle Church \u00b7 ' + escapeHtml(svc.service_date)
    + ' \u00b7 counted by ' + escapeHtml((user && user.display_name) || svc.created_by_name || 'TabReady') + '</p>'
    + '<table style="width:100%;border-collapse:collapse;font-size:14px;">'
    + '<thead><tr style="background:#aac27f;color:#22331a;text-align:left;">'
    + '<th style="padding:8px;">Stop</th><th style="padding:8px;text-align:center;">People</th><th style="padding:8px;text-align:center;">Serving</th>'
    + '</tr></thead><tbody>' + tr + '</tbody>'
    + '<tfoot><tr style="background:#402020;color:#fff;font-weight:800;">'
    + '<td style="padding:10px 8px;">TOTAL HEADCOUNT</td>'
    + '<td style="padding:10px 8px;text-align:center;font-size:18px;" colspan="2">' + svc.total + '</td>'
    + '</tr></tfoot></table>'
    + '<p style="color:#8a7a6a;font-size:12px;margin-top:14px;">Sent automatically by TabReady when the count was saved.</p>'
    + '</div>';
}

async function apiAttendanceList(request, env) {
  const user = await getUserFromRequest(request, env);
  if (!user) return json({ ok: false, error: 'not_authenticated' }, 401);
  if (!canSeeAttendance(user)) return json({ ok: false, error: 'forbidden' }, 403);
  await ensureAttendanceTable(env);
  const url = new URL(request.url);
  let limit = parseInt(url.searchParams.get('limit') || '40', 10);
  if (!isFinite(limit) || limit < 1) limit = 40;
  if (limit > 100) limit = 100;
  let rows = [];
  try {
    const q = await env.DB.prepare(
      "SELECT service_date, service_label, stop_key, attendance, workers, created_by_name, created_at FROM attendance_entries WHERE (service_date || '||' || service_label) IN (SELECT (service_date || '||' || service_label) FROM attendance_entries GROUP BY service_date, service_label ORDER BY service_date DESC, MAX(id) DESC LIMIT ?) ORDER BY service_date DESC, service_label ASC, id ASC"
    ).bind(limit).all();
    rows = q.results || [];
  } catch (e) { rows = []; }
  const services = attGroupServices(rows);
  services.sort(function (a, b) { return a.service_date < b.service_date ? 1 : (a.service_date > b.service_date ? -1 : 0); });
  return json({ ok: true, count: services.length, stops: ATT_STOPS, services: services });
}

async function apiAttendanceDelete(request, env) {
  const user = await getUserFromRequest(request, env);
  if (!user) return json({ ok: false, error: 'not_authenticated' }, 401);
  if (!canSeeAttendance(user)) return json({ ok: false, error: 'forbidden' }, 403);
  await ensureAttendanceTable(env);
  let b = {};
  try { b = await request.json(); } catch (e) { return json({ ok: false, error: 'bad_json' }, 400); }
  const label = (b.service_label == null ? '' : String(b.service_label)).trim().slice(0, 80);
  const date = (b.service_date == null ? '' : String(b.service_date)).trim().slice(0, 10);
  if (!label || !attIsIsoDate(date)) return json({ ok: false, error: 'bad_request' }, 400);
  let removed = 0;
  try {
    const res = await env.DB.prepare(
      "DELETE FROM attendance_entries WHERE service_date = ? AND service_label = ?"
    ).bind(date, label).run();
    removed = (res && res.meta && res.meta.changes) ? res.meta.changes : 0;
  } catch (e) {
    return json({ ok: false, error: 'delete_failed' }, 500);
  }
  try {
    await env.DB.prepare(
      "INSERT INTO audit_log_v2 (id, actor_user_id, action, target_kind, target_id, metadata) VALUES (?,?,?,?,?,?)"
    ).bind(crypto.randomUUID(), user.id || '', 'headcount_deleted', 'attendance', date + '|' + label,
      JSON.stringify({ rows: removed, by: user.display_name || '' })).run();
  } catch (e) {}
  return json({ ok: true, removed: removed });
}

function attParseRecipients(raw) {
  const parts = String(raw == null ? '' : raw).split(/[,;\s]+/).map(function (s) { return s.trim(); }).filter(Boolean);
  const valid = [];
  for (const p of parts) { if (/^[^@\s]+@[^@\s]+\.[^@\s]+$/.test(p) && valid.indexOf(p) === -1) valid.push(p); }
  return valid;
}

async function apiAttendanceReportRecipient(request, env) {
  const user = await getUserFromRequest(request, env);
  if (!user) return json({ ok: false, error: 'not_authenticated' }, 401);
  if (!canSeeAttendance(user)) return json({ ok: false, error: 'forbidden' }, 403);
  const to = await datesGetSetting(env, 'attendance_report_to', '');
  return json({ ok: true, to: to || '' });
}

// Kept: sets the office recipient, and can send a multi-week catch-up summary.
async function apiAttendanceSendReport(request, env) {
  const user = await getUserFromRequest(request, env);
  if (!user) return json({ ok: false, error: 'not_authenticated' }, 401);
  if (!canSeeAttendance(user)) return json({ ok: false, error: 'forbidden' }, 403);
  await ensureAttendanceTable(env);
  let b = {};
  try { b = await request.json(); } catch (e) { return json({ ok: false, error: 'bad_json' }, 400); }

  const recips = attParseRecipients(b.to);

  if (b.save_only) {
    if (!recips.length) return json({ ok: false, error: 'Enter a valid email to save.' }, 400);
    await datesSetSetting(env, 'attendance_report_to', recips.join(', '));
    return json({ ok: true, saved: true, to: recips.join(', ') });
  }
  if (b.clear_only) {
    await datesSetSetting(env, 'attendance_report_to', '');
    return json({ ok: true, saved: true, to: '' });
  }
  if (!recips.length) return json({ ok: false, error: 'Enter a valid email address.' }, 400);

  let rows = [];
  try {
    const q = await env.DB.prepare(
      "SELECT service_date, service_label, stop_key, attendance, workers, created_by_name, created_at FROM attendance_entries WHERE service_date >= date('now','-35 days') ORDER BY service_date DESC, id ASC"
    ).all();
    rows = q.results || [];
  } catch (e) { rows = []; }
  const services = attGroupServices(rows);
  if (!services.length) return json({ ok: false, error: 'No head counts saved yet \u2014 save one first.' }, 400);

  let tr = '';
  let grand = 0;
  for (const svc of services) {
    grand += svc.total;
    tr += '<tr>'
      + '<td style="padding:7px 8px;border-bottom:1px solid #eee;">' + escapeHtml(svc.service_date) + '</td>'
      + '<td style="padding:7px 8px;border-bottom:1px solid #eee;">' + escapeHtml(svc.service_label) + '</td>'
      + '<td style="padding:7px 8px;border-bottom:1px solid #eee;font-size:12px;color:#555;">' + escapeHtml(attServiceLines(svc).join(' \u00b7 ')) + '</td>'
      + '<td style="padding:7px 8px;border-bottom:1px solid #eee;text-align:center;font-weight:700;">' + svc.total + '</td>'
      + '</tr>';
  }
  const genOn = new Date().toISOString().slice(0, 10);
  const html = '<div style="font-family:-apple-system,Segoe UI,Roboto,sans-serif;color:#1a1a1a;max-width:680px;margin:0 auto;">'
    + '<h2 style="color:#402020;margin:0 0 4px;">Headcount Summary</h2>'
    + '<p style="color:#6b7280;margin:0 0 16px;font-size:13px;">The Tabernacle Church \u2014 generated ' + escapeHtml(genOn)
    + ' by ' + escapeHtml((user && user.display_name) || 'TabReady') + '. ' + services.length + ' service(s).</p>'
    + '<table style="width:100%;border-collapse:collapse;font-size:13px;">'
    + '<thead><tr style="background:#aac27f;color:#22331a;text-align:left;">'
    + '<th style="padding:8px;">Date</th><th style="padding:8px;">Service</th><th style="padding:8px;">Breakdown</th><th style="padding:8px;text-align:center;">Total</th>'
    + '</tr></thead><tbody>' + tr + '</tbody>'
    + '<tfoot><tr style="background:#402020;color:#fff;font-weight:800;">'
    + '<td style="padding:9px 8px;" colspan="3">GRAND TOTAL</td>'
    + '<td style="padding:9px 8px;text-align:center;">' + grand + '</td>'
    + '</tr></tfoot></table></div>';

  const ccList = (user.email && recips.indexOf(user.email) === -1) ? [user.email] : [];
  const sendOpts = { reply_to: user.email || undefined };
  if (ccList.length) sendOpts.cc = ccList;
  let sent = false;
  try { sent = await resendEmail(env, recips, 'Headcount Summary \u2014 The Tabernacle (' + genOn + ')', html, sendOpts); } catch (e) { sent = false; }
  if (!sent) return json({ ok: false, error: 'Email send failed. Check with the office/admin.' }, 502);

  if (b.remember) { await datesSetSetting(env, 'attendance_report_to', recips.join(', ')); }
  return json({ ok: true, sent_to: recips.join(', '), copy_to: ccList[0] || '', services: services.length });
}

async function attendancePage(request, env) {
  const user = await getUserFromRequest(request, env);
  if (!user) return loginPage();
  const hdr = { 'Content-Type': 'text/html;charset=utf-8', 'Cache-Control': 'no-store' };
  if (!canSeeAttendance(user)) {
    return new Response(mgShell('Headcount', 'Worship & event head count', '<div class="empty">This tool is for safety, staff, elders and church leadership.<br><br>If you should have access, reach out to the church office.</div>'), { headers: hdr });
  }
  await ensureAttendanceTable(env);
  const today = new Date().toISOString().slice(0, 10);
  let officeTo = '';
  try { officeTo = await datesGetSetting(env, 'attendance_report_to', ''); } catch (e) { officeTo = ''; }

  const css = '<style>'
    + '.att-card{background:#fff;border:1.5px solid #ece4d7;border-radius:16px;padding:16px 14px;margin-bottom:14px}'
    + '.att-lbl{font-size:12px;font-weight:800;letter-spacing:.4px;text-transform:uppercase;color:#8a7a6a;margin-bottom:8px}'
    + '.att-chips{display:flex;flex-wrap:wrap;gap:8px}'
    + '.att-chip{flex:1 1 0;text-align:center;padding:10px 4px;border-radius:10px;border:1.5px solid #e5dccf;background:#f7f2ea;color:#402020;font-weight:800;font-size:13px;cursor:pointer;user-select:none}'
    + '.att-chip.on{background:#aac27f;border-color:#7fae5a;color:#22331a}'
    + '.att-in{width:100%;padding:13px 12px;border:1.5px solid #e5dccf;border-radius:12px;font-size:16px;background:#fff;color:#402020;margin-top:9px}'
    + '.att-stop{background:#fff;border:1.5px solid #ece4d7;border-radius:14px;padding:12px 12px;margin-bottom:11px}'
    + '.att-cat{font-size:17px;font-weight:800;color:#402020}'
    + '.att-cat .sub{display:block;font-size:11px;font-weight:600;color:#8a7a6a;text-transform:none;margin-top:1px}'
    + '.att-line{display:flex;align-items:center;justify-content:space-between;margin-top:10px}'
    + '.att-line .who{font-size:12px;font-weight:800;text-transform:uppercase;letter-spacing:.3px;color:#8a7a6a}'
    + '.att-step{display:flex;align-items:center;gap:12px}'
    + '.att-btn{width:44px;height:44px;border-radius:50%;border:0;font-size:25px;font-weight:800;line-height:1;cursor:pointer;display:flex;align-items:center;justify-content:center}'
    + '.att-minus{background:#f3ede4;color:#6d3d31}'
    + '.att-plus{background:#aac27f;color:#22331a}'
    + '.att-inp{width:92px;text-align:center;font-size:23px;font-weight:900;color:#402020;border:1.5px solid #d8cbb8;border-bottom:3px solid #aac27f;border-radius:10px;background:#fffdf9;padding:7px 4px;cursor:text;-moz-appearance:textfield}'
    + '.att-inp:focus{outline:none;border-color:#aac27f;background:#fff}'
    + '.att-inp.w{width:78px;font-size:19px;border-bottom-color:#ca8342}'
    + '.att-hint{background:#eef4e6;border:1px solid #d3e3c2;color:#3a5a28;border-radius:12px;padding:12px 14px;font-size:13.5px;font-weight:600;line-height:1.5;margin-bottom:14px}'
    + '.att-hint b{color:#2c4a1c}'
    + '.att-total{display:flex;align-items:center;justify-content:space-between;background:#402020;color:#fff;border-radius:14px;padding:15px 16px;margin:4px 0 14px;font-weight:800}'
    + '.att-total .n{font-size:30px;font-weight:900}'
    + '.att-save{display:block;width:100%;text-align:center;font-weight:900;padding:16px;border-radius:14px;border:0;font-size:17px;background:#6d3d31;color:#fff;cursor:pointer}'
    + '.att-save:disabled{opacity:.5}'
    + '.att-clear{display:block;width:100%;text-align:center;font-weight:800;padding:13px;border-radius:14px;border:1.5px solid #d8cbb8;background:#fff;color:#8a7a6a;font-size:14px;cursor:pointer;margin-top:9px}'
    + '.att-del{display:inline-block;margin:9px 0 0 8px;padding:9px 14px;border-radius:10px;background:#f3ede4;color:#6d3d31;font-weight:800;font-size:13px;border:0;cursor:pointer}'
    + '.att-office{text-align:center;font-size:12.5px;color:#8a7a6a;margin:10px 2px 4px;line-height:1.6}'
    + '.att-office a{color:#6d3d31;font-weight:800;text-decoration:underline;cursor:pointer}'
    + '.att-hist{background:#fff;border:1.5px solid #ece4d7;border-radius:14px;padding:13px 13px;margin-bottom:10px}'
    + '.att-hist .h1{font-size:16px;font-weight:800;color:#402020}'
    + '.att-hist .h2{font-size:12px;color:#8a7a6a;margin-top:2px}'
    + '.att-hist .h3{font-size:13px;color:#402020;margin-top:7px;line-height:1.5}'
    + '.att-hist .tot{float:right;font-size:22px;font-weight:900;color:#6d3d31}'
    + '.att-sh{display:inline-block;margin-top:9px;padding:9px 14px;border-radius:10px;background:#8dc6e8;color:#0a2536;font-weight:800;font-size:13px;border:0;cursor:pointer}'
    + '.att-sec{font-size:13px;font-weight:800;text-transform:uppercase;letter-spacing:.4px;color:#8a7a6a;margin:18px 2px 10px}'
    + '</style>';

  const chips = [
    { v: 'Sunday Morning', t: 'Sunday' },
    { v: 'Wednesday', t: 'Wednesday' },
    { v: 'Special Event', t: 'Special' }
  ];
  let chipHtml = '';
  for (let i = 0; i < chips.length; i++) {
    chipHtml += '<div class="att-chip' + (i === 0 ? ' on' : '') + '" data-label="' + mgEsc(chips[i].v) + '" onclick="attPick(this)">' + mgEsc(chips[i].t) + '</div>';
  }

  // Stops render birth -> oldest. Each carries its own workers line.
  let rowHtml = '';
  for (let i = 0; i < ATT_STOPS.length; i++) {
    const c = ATT_STOPS[i];
    rowHtml += '<div class="att-stop">'
      + '<div class="att-cat">' + mgEsc(c.name) + '<span class="sub">' + c.sub + '</span></div>'
      + '<div class="att-line">'
      + '<span class="who">' + mgEsc(c.people) + '</span>'
      + '<div class="att-step">'
      + '<button type="button" class="att-btn att-minus" onclick="attBump(\'' + c.key + '\',\'a\',-1)">\u2212</button>'
      + '<input class="att-inp" id="att-a-' + c.key + '" type="text" inputmode="numeric" value="0" onfocus="this.select()" oninput="attType(\'' + c.key + '\',\'a\')">'
      + '<button type="button" class="att-btn att-plus" onclick="attBump(\'' + c.key + '\',\'a\',1)">+</button>'
      + '</div></div>';
    if (c.workers) {
      rowHtml += '<div class="att-line">'
        + '<span class="who">' + mgEsc(c.vol) + '</span>'
        + '<div class="att-step">'
        + '<button type="button" class="att-btn att-minus" onclick="attBump(\'' + c.key + '\',\'w\',-1)">\u2212</button>'
        + '<input class="att-inp w" id="att-w-' + c.key + '" type="text" inputmode="numeric" value="0" onfocus="this.select()" oninput="attType(\'' + c.key + '\',\'w\')">'
        + '<button type="button" class="att-btn att-plus" onclick="attBump(\'' + c.key + '\',\'w\',1)">+</button>'
        + '</div></div>';
    }
    rowHtml += '</div>';
  }

  const officeLine = officeTo
    ? 'Saving emails the office automatically: <b>' + mgEsc(officeTo) + '</b><br><a onclick="attSetOffice()">Change</a>'
    : '\u26A0\uFE0F No office email set \u2014 counts save, but nobody is notified.<br><a onclick="attSetOffice()">Set the office email</a>';

  const form = '<div class="att-card">'
    + '<div class="att-lbl">What are you counting?</div>'
    + '<div class="att-chips">' + chipHtml + '</div>'
    + '<input class="att-in" id="att-custom" placeholder="Name the event" oninput="attCustom()" style="display:none">'
    + '<input type="hidden" id="att-label" value="Sunday Morning">'
    + '<div class="att-lbl" style="margin-top:14px">Date</div>'
    + '<input class="att-in" type="date" id="att-date" value="' + today + '">'
    + '</div>'
    + '<div class="att-hint">\uD83D\uDC46 Tap a number and type it in, or use the \u2212 and + buttons. Then tap <b>Save this count</b>.</div>'
    + rowHtml
    + '<div class="att-total"><span>Total headcount</span><span class="n" id="att-total">0</span></div>'
    + '<button type="button" class="att-save" id="att-save" onclick="attSave()">Save this count</button>'
    + '<button type="button" class="att-clear" onclick="attClearForm()">Clear all numbers</button>'
    + '<div class="att-office" id="att-office">' + officeLine + '</div>'
    + '<div class="att-sec">Recent counts</div>'
    + '<div id="att-history"><div class="empty" style="padding:20px">Loading\u2026</div></div>';

  // Inline script - plain concatenation, no template literals, no backticks.
  const NL = String.fromCharCode(10);
  const STOPS_JSON = JSON.stringify(ATT_STOPS.map(function (s) { return { key: s.key, name: s.name, workers: !!s.workers }; }));
  let js = '<script>' + NL;
  js += 'var attStops=' + STOPS_JSON + ';' + NL;
  js += 'var attState={};attStops.forEach(function(s){attState[s.key]={a:0,w:0};});' + NL;
  js += 'var attSvcs=[];' + NL;
  js += 'function attBump(k,f,d){var v=(attState[k][f]||0)+d;if(v<0)v=0;if(v>100000)v=100000;attState[k][f]=v;var el=document.getElementById("att-"+f+"-"+k);if(el)el.value=v;attTotal();}' + NL;
  js += 'function attType(k,f){var el=document.getElementById("att-"+f+"-"+k);if(!el)return;var s=(el.value||"").replace(/[^0-9]/g,"");if(s.length>6)s=s.slice(0,6);if(el.value!==s)el.value=s;attState[k][f]=(s===""?0:parseInt(s,10));attTotal();}' + NL;
  js += 'function attTotal(){var t=0;attStops.forEach(function(s){t+=(attState[s.key].a||0);if(s.workers)t+=(attState[s.key].w||0);});var el=document.getElementById("att-total");if(el)el.textContent=t;return t;}' + NL;
  js += 'function attPick(el){var c=document.querySelectorAll(".att-chip");for(var i=0;i<c.length;i++)c[i].classList.remove("on");el.classList.add("on");var v=el.getAttribute("data-label");var cu=document.getElementById("att-custom");if(v==="Special Event"){cu.style.display="block";document.getElementById("att-label").value=(cu.value||"").trim();cu.focus();}else{cu.style.display="none";document.getElementById("att-label").value=v;}}' + NL;
  js += 'function attCustom(){document.getElementById("att-label").value=(document.getElementById("att-custom").value||"").trim();}' + NL;
  js += 'function attReset(){attStops.forEach(function(s){attState[s.key]={a:0,w:0};var a=document.getElementById("att-a-"+s.key);if(a)a.value="0";var w=document.getElementById("att-w-"+s.key);if(w)w.value="0";});attTotal();var cu=document.getElementById("att-custom");cu.value="";cu.style.display="none";document.getElementById("att-label").value="Sunday Morning";var c=document.querySelectorAll(".att-chip");for(var i=0;i<c.length;i++)c[i].classList.remove("on");if(c[0])c[0].classList.add("on");}' + NL;
  js += 'function attEsc(s){s=String(s==null?"":s);return s.replace(/&/g,"&amp;").replace(/</g,"&lt;").replace(/>/g,"&gt;");}' + NL;
  js += 'function attSetOffice(){var to=prompt("Email address the office should receive counts at:","");if(to===null)return;to=to.trim();if(!to){return;}fetch("/api/attendance/send-report",{method:"POST",headers:{"Content-Type":"application/json"},body:JSON.stringify({to:to,save_only:true})}).then(function(r){return r.json();}).then(function(d){if(d&&d.ok){mgToast("Office email set \\u2014 saves will notify "+d.to);setTimeout(function(){location.reload();},900);}else{mgToast((d&&d.error)?d.error:"Could not save");}}).catch(function(){mgToast("Could not save");});}' + NL;
  js += 'function attFmt(s){var L=[s.service_label+" \\u2014 "+s.service_date];attStops.forEach(function(t){var v=s.stops[t.key];if(!v)return;L.push(t.name+" "+v.attendance+(t.workers?(" (+"+v.workers+" serving)"):""));});L.push("TOTAL "+s.total);return L.join(String.fromCharCode(10));}' + NL;
  js += 'function attShare(s){if(!s)return;var txt=attFmt(s);if(navigator.share){navigator.share({title:"Headcount \\u2014 "+s.service_label,text:txt}).catch(function(){});}else if(navigator.clipboard){navigator.clipboard.writeText(txt).then(function(){mgToast("Copied \\u2014 paste to share");}).catch(function(){mgToast("Copy failed");});}else{mgToast(txt);}}' + NL;
  js += 'function attShareIdx(i){attShare(attSvcs[i]);}' + NL;
  js += 'function attClearForm(){if(attTotal()===0){attReset();mgToast("Cleared");return;}if(confirm("Clear all numbers on this screen? Nothing already saved is affected.")){attReset();mgToast("Cleared");}}' + NL;
  js += 'function attDelIdx(i){var s=attSvcs[i];if(!s)return;if(!confirm("Delete this saved count?"+String.fromCharCode(10)+s.service_label+" "+s.service_date+" (total "+s.total+")"+String.fromCharCode(10)+String.fromCharCode(10)+"It is removed from the record. An email already sent to the office cannot be recalled."))return;fetch("/api/attendance/delete",{method:"POST",headers:{"Content-Type":"application/json"},body:JSON.stringify({service_label:s.service_label,service_date:s.service_date})}).then(function(r){return r.json();}).then(function(d){if(d&&d.ok){mgToast("Deleted");attLoad();}else{mgToast((d&&d.error)?d.error:"Delete failed");}}).catch(function(){mgToast("Delete failed");});}' + NL;
  js += 'function attSave(){var label=(document.getElementById("att-label").value||"").trim();if(!label){mgToast("Name the event first");return;}if(attTotal()===0){if(!confirm("Every stop is 0. Save anyway?"))return;}var date=document.getElementById("att-date").value||"";var btn=document.getElementById("att-save");btn.disabled=true;btn.textContent="Saving\\u2026";var stops={};attStops.forEach(function(s){stops[s.key]={attendance:attState[s.key].a,workers:(s.workers?attState[s.key].w:0)};});fetch("/api/attendance",{method:"POST",headers:{"Content-Type":"application/json"},body:JSON.stringify({service_label:label,service_date:date,stops:stops})}).then(function(r){return r.json();}).then(function(d){btn.disabled=false;btn.textContent="Save this count";if(d&&d.ok){mgToast(d.emailed_to?("Saved \\u2014 total "+d.total+" \\u00b7 office notified"):("Saved \\u2014 total "+d.total));attReset();attLoad();}else{mgToast((d&&d.error)?d.error:"Save failed");}}).catch(function(){btn.disabled=false;btn.textContent="Save this count";mgToast("Save failed");});}' + NL;
  js += 'function attLoad(){fetch("/api/attendance/list?limit=40").then(function(r){return r.json();}).then(function(d){var box=document.getElementById("att-history");attSvcs=(d&&d.services)?d.services:[];if(!attSvcs.length){box.innerHTML="<div class=\\"empty\\" style=\\"padding:20px\\">No counts recorded yet.</div>";return;}var h="";for(var i=0;i<attSvcs.length;i++){var s=attSvcs[i];var parts=[];attStops.forEach(function(t){var v=s.stops[t.key];if(!v)return;parts.push(attEsc(t.name)+" "+v.attendance+(t.workers?(" <span style=\\"color:#ca8342\\">+"+v.workers+"</span>"):""));});var by=s.created_by_name?(" \\u00b7 by "+attEsc(s.created_by_name)):"";h+="<div class=\\"att-hist\\"><span class=\\"tot\\">"+s.total+"</span><div class=\\"h1\\">"+attEsc(s.service_label)+"</div><div class=\\"h2\\">"+attEsc(s.service_date)+by+"</div><div class=\\"h3\\">"+parts.join(" \\u00b7 ")+"</div><button class=\\"att-sh\\" onclick=\\"attShareIdx("+i+")\\">\\u21AA Share</button><button class=\\"att-del\\" onclick=\\"attDelIdx("+i+")\\">Delete</button></div>";}box.innerHTML=h;}).catch(function(){document.getElementById("att-history").innerHTML="<div class=\\"empty\\" style=\\"padding:20px\\">Could not load recent counts.</div>";});}' + NL;
  js += 'attLoad();' + NL;
  js += '<' + '/script>';

  return new Response(mgShell('Headcount', 'Worship & event head count', css + form + js), { headers: hdr });
}
